window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["nicet-fire-alarm"] = window.COURSE_LANG["nicet-fire-alarm"] || {};
window.COURSE_LANG["nicet-fire-alarm"]["ru"] = [
  {id:1, q:"Тетраэдр огня добавляет четвёртый элемент к классическому треугольнику огня. Что это за четвёртый элемент?", opts:["Световая (лучистая) энергия","Образование дыма","Самоподдерживающаяся химическая цепная реакция","Газ монооксид углерода"], re:"Тетраэдр огня состоит из топлива, тепла, кислорода плюс самоподдерживающейся химической цепной реакции. Источник: основы науки о пожаре (Тетраэдр огня WFCA; справочные данные по обнаружению NFPA 72)."},
  {id:2, q:"Какие три элемента составляют базовый треугольник огня?", opts:["Дым, тепло и пламя","Воспламенение, вентиляция и топливо","Углерод, водород и кислород","Топливо, кислород и тепло"], re:"Треугольник огня — это топливо, кислород (окислитель) и тепло; удаление любого из них гасит огонь. Источник: основы науки о пожаре (Firesafe.org.uk; WFCA)."},
  {id:3, q:"На ранней стадии типичного пожара какой обнаруживаемый продукт обычно появляется ПЕРВЫМ?", opts:["Открытое пламя","Высокая температура","Невидимые частицы горения / дым","Обрушение конструкции"], re:"На начальной стадии невидимые аэрозоли и частицы горения появляются раньше видимого дыма, пламени или значительного тепла, поэтому раннее обнаружение дыма срабатывает первым. Источник: принципы обнаружения NFPA 72; основы стадий пожара."},
  {id:4, q:"Медленно развивающийся пожар, который производит крупные частицы дыма, но мало пламени, лучше всего описывается как:", opts:["Объёмная вспышка (flashover)","Пламенный пожар","Обратная тяга (backdraft)","Тлеющий пожар (smoldering)"], re:"Тлеющий пожар горит медленно без пламени и даёт более крупные частицы дыма; фотоэлектрическое обнаружение реагирует на него лучше всего. Источник: руководство NFPA по дымовым извещателям; основы горения."},
  {id:5, q:"По сравнению с тлеющими пожарами, пожары с быстрым пламенем обычно производят частицы дыма, которые:", opts:["Всегда невидимы для всех извещателей","Крупнее по размеру","Мельче по размеру","Идентичны по размеру"], re:"Пламенные пожары образуют более мелкие частицы дыма/горения, на которые ионизационное обнаружение реагирует лучше всего; тлеющие пожары дают более крупные частицы. Источник: руководство NFPA по технологии дымовых извещателей."},
  {id:6, q:"Четыре общие стадии развития пожара обычно перечисляют как:", opts:["Объёмная вспышка (flashover), тление, пламя, затухание","Затухание, начальная, рост, объёмная вспышка (flashover)","Начальная, рост, полностью развитый, затухание","Воспламенение, объёмная вспышка (flashover), подавление, проливка"], re:"Пожар развивается через начальную стадию, стадию роста, полностью развитую стадию и стадию затухания. Источник: основы поведения пожара (справочник Phoenix Fire; справочные данные по обнаружению NFPA)."},
  {id:7, q:"Тепло от пожара передаётся тремя способами. В каком списке правильно названы все три?", opts:["Горение, окисление, пиролиз","Ионизация, фотоэлектрический, луч","Теплопроводность, конвекция, излучение","Воспламенение, распространение, тушение"], re:"Передача тепла происходит путём теплопроводности, конвекции и излучения; конвекция (восходящие горячие газы) направляет дым к потолочным извещателям. Источник: основы науки о пожаре."},
  {id:8, q:"Почему большинство точечных дымовых и тепловых извещателей устанавливают на потолке или рядом с ним?", opts:["Чтобы держать их вне досягаемости людей","Только чтобы сократить длину проводки","Потому что нормы полностью запрещают настенный монтаж","Потому что горячий дым и газы поднимаются за счёт конвекции и собираются у потолка"], re:"Плавучий горячий дым поднимается и образует слой у потолка, поэтому размещение в зоне потолка даёт самую раннюю реакцию. Источник: обоснование размещения точечных извещателей NFPA 72."},
  {id:9, q:"Процесс, при котором твёрдое топливо химически разлагается под действием тепла, выделяя горючие пары, называется:", opts:["Конвекция","Окисление","Сублимация","Пиролиз"], re:"Пиролиз — это термическое разложение топлива, при котором выделяются горючие газы, которые затем воспламеняются. Источник: основы науки о пожаре."},
  {id:10, q:"Монооксид углерода (CO) образуется при пожаре главным образом в результате:", opts:["Только электрической дуги","Полного сгорания с избытком кислорода","Неполного сгорания топлив на основе углерода","Реакции воды с топливом"], re:"CO — продукт неполного сгорания при ограниченном кислороде; это бесцветный, не имеющий запаха токсичный газ. Источник: основы химии пожара; справочные данные по обнаружению CO (NFPA 720/72)."},
  {id:11, q:"Быстрое, почти одновременное воспламенение большинства открытых горючих поверхностей в помещении известно как:", opts:["Обратная тяга (backdraft)","Пиролиз","Перекатывание пламени (rollover)","Объёмная вспышка (flashover)"], re:"Объёмная вспышка (flashover) — это переход, при котором лучистое тепло воспламеняет почти все горючие материалы в помещении почти одновременно. Источник: основы поведения пожара."},
  {id:12, q:"Технологии обнаружения, как правило, воспринимают одну из трёх сигнатур пожара. В каком наборе перечислены эти сигнатуры?", opts:["Напряжение, ток, сопротивление","Скорость, давление, масса","Дым (аэрозоли), тепло и лучистая энергия (пламя)","Цвет, запах и вкус"], re:"Автоматические пожарные извещатели реагируют на дым/аэрозоли, тепло или лучистую энергию (пламя) — три основные сигнатуры пожара. Источник: классификации извещателей NFPA 72."},
  {id:13, q:"В каком порядке обнаруживаемые сигнатуры пожара чаще всего становятся доступными при типичном пожаре, который сначала тлеет, а затем горит пламенем?", opts:["Тепло, затем пламя, затем дым","Пламя, затем тепло, затем дым","Тепло, затем дым, затем пламя","Дым, затем пламя, затем высокая температура"], re:"Аэрозоли дыма обычно появляются раньше всего, за ними следует пламя, а затем значительное тепло по мере роста пожара; это определяет выбор извещателя для раннего оповещения. Источник: принципы обнаружения NFPA 72."},
  {id:14, q:"Какое утверждение о кислороде и горении является правильным?", opts:["Кислород не играет роли в пожаре","Для горения требуется чистый 100 % кислород","Обычный воздух (около 21 % кислорода) легко поддерживает пламенное горение","Снижение кислорода всегда ускоряет пожар"], re:"Обычный воздух (~21 % O2) поддерживает горение; снижение концентрации окислителя, как правило, подавляет огонь. Источник: основы науки о пожаре."},
  {id:15, q:"Самая низкая температура, при которой топливо выделяет достаточно паров для образования воспламеняемой смеси в воздухе, — это его:", opts:["Температура самовоспламенения","Точка кипения","Температура вспышки","Точка Кюри"], re:"Температура вспышки — это минимальная температура, при которой жидкость производит достаточно паров для кратковременной вспышки при наличии источника воспламенения. Источник: основы химии пожара."},
  {id:16, q:"На какую сигнатуру пожара ДЫМОВОЙ извещатель НЕ реагировал бы напрямую?", opts:["Видимые частицы дыма","Невидимые аэрозоли горения","Лучистое тепло от чистого пламени, производящего мало дыма","Продукты тлеющего горения"], re:"Дымовые извещатели реагируют на находящиеся в воздухе частицы горения; чистое, быстрое пламя, производящее мало дыма, лучше улавливается извещателем пламени (лучистой энергии). Источник: выбор извещателей NFPA 72."},
  {id:17, q:"Выбор подходящего типа извещателя для опасности зависит главным образом от:", opts:["Ожидаемой сигнатуры пожара и среды защищаемого пространства","Цвета стены","Только марки панели управления","Дня недели установки"], re:"Выбор извещателя основан на предполагаемой сигнатуре пожара (дым, тепло, пламя) и условиях окружающей среды пространства. Источник: руководство по выбору извещателей Главы 17 NFPA 72."},
  {id:18, q:"Ионизационный дымовой извещатель обычно реагирует БЫСТРЕЕ всего на какой тип пожара?", opts:["Пожары с быстрым пламенем","Медленные тлеющие пожары","Утечки CO без горения","Перегретая проводка без дыма"], re:"Ионизационные извещатели лучше всего реагируют на пожары с быстрым пламенем, которые производят мелкие частицы дыма. Источник: руководство NFPA по технологии дымовых извещателей."},
  {id:19, q:"Фотоэлектрический дымовой извещатель обычно реагирует БЫСТРЕЕ всего на какой тип пожара?", opts:["Пожары с быстрым пламенем","Только лучистое пламя","Чистое тепло без дыма","Медленные тлеющие пожары"], re:"Фотоэлектрические (светорассеивающие) извещатели лучше всего реагируют на медленные тлеющие пожары, которые производят более крупные частицы дыма. Источник: руководство NFPA по технологии дымовых извещателей."},
  {id:20, q:"Радиоактивный источник, используемый в типичном ионизационном дымовом извещателе, — это:", opts:["Кобальт-60","Радий-226","Америций-241","Цезий-137"], re:"Ионизационные дымовые извещатели используют небольшой альфа-источник америция-241 (около 1 микрокюри в бытовых устройствах) для ионизации воздуха в камере. Источник: ORAU/Всемирная ядерная ассоциация; справочные данные по ионизационным извещателям."},
  {id:21, q:"Как дым, попадающий в ионизационную камеру, вызывает срабатывание сигнализации?", opts:["Резко увеличивает ток камеры","Нагревает камеру до заданной точки","Создаёт магнитное поле","Присоединяется к ионам и снижает ток камеры"], re:"Частицы дыма присоединяются к ионизированным молекулам воздуха, снижая небольшой постоянный ток; извещатель воспринимает это падение и подаёт сигнал тревоги. Источник: принцип работы ионизационного извещателя (ORAU)."},
  {id:22, q:"Фотоэлектрический (светорассеивающий) дымовой извещатель подаёт сигнал тревоги, когда:", opts:["Частицы дыма рассеивают свет от источника на фотодатчик","Дым охлаждает внутренний нагреватель","Радиоактивный источник распадается быстрее","Напряжение камеры падает до нуля"], re:"В светорассеивающем фотоэлектрическом извещателе дым, попадающий в камеру, рассеивает свет светодиода на фотодатчик, который обычно защищён от луча, вызывая срабатывание сигнализации. Источник: принцип работы фотоэлектрического извещателя."},
  {id:23, q:"Для наилучшей общей защиты безопасности жизни руководство NFPA рекомендует:", opts:["Только ионизационные извещатели","Удаление дымовых извещателей из спален","Только тепловые извещатели","Обе технологии — фотоэлектрическую и ионизационную (или комбинированное устройство)"], re:"NFPA рекомендует использовать обе технологии — ионизационную и фотоэлектрическую — или комбинированные извещатели, потому что каждая лучше реагирует на разные типы пожара. Источник: руководство NFPA по дымовым извещателям."},
  {id:24, q:"Распространённым источником ложных срабатываний для ИОНИЗАЦИОННЫХ извещателей, размещённых слишком близко к кухне, является:", opts:["Кулинарные аэрозоли и пар","Только лучистое тепло","Низкая влажность","Только монооксид углерода"], re:"Ионизационные устройства склонны к ложным срабатываниям от кулинарных паров/пара, поэтому их следует держать вдали от кухонных приборов. Источник: руководство по размещению NFPA 72; справочные данные по дымовым извещателям."},
  {id:25, q:"Согласно NFPA 72, номинальный (общепринятый) шаг, используемый как ориентир для точечных дымовых извещателей на гладких потолках, составляет примерно:", opts:["10 ft","20 ft","30 ft","75 ft"], re:"Дымовые извещатели не имеют сертифицированного шага, но обычно применяются с номинальным шагом 30 ft на гладких потолках в качестве начального ориентира. Источник: NFPA 72; статья ECMag о шаге извещателей."},
  {id:26, q:"Дымовой извещатель, установленный на боковой стене (не на потолке), обычно должен иметь свою верхнюю часть расположенной:", opts:["В пределах 12 in. от потолка","Не менее чем на 36 in. ниже потолка","На полу","Точно только на середине высоты стены"], re:"Настенные точечные дымовые извещатели размещают так, чтобы их верхняя часть была в пределах 12 in. от потолка, чтобы они достигали поднимающегося слоя дыма. Источник: монтаж точечных извещателей NFPA 72 (UpCodes 907 / 17.7)."},
  {id:27, q:"Точечный дымовой извещатель, установленный на потолке, должен находиться на минимальном расстоянии от боковой стены не менее:", opts:["1 in.","2 in.","4 in.","18 in."], re:"NFPA 72 требует, чтобы точечные извещатели, установленные на потолке, находились не менее чем в 4 in. от боковой стены. Источник: монтаж точечных извещателей NFPA 72 (getsafeandsound; UpCodes)."},
  {id:28, q:"Какой тип извещателя ЛУЧШЕ всего подходит там, где требуется очень раннее оповещение о медленных тлеющих пожарах электроники в центре обработки данных?", opts:["Фотоэлектрическое или аспирационное обнаружение дыма","Только тепловой извещатель фиксированной температуры","Ручной пожарный извещатель одинарного действия","Только тепловой извещатель максимально-дифференциального типа (скорости нарастания)"], re:"Тлеющие, маломощные пожары производят более крупные частицы и мало тепла на ранней стадии, поэтому фотоэлектрическое или высокочувствительное аспирационное обнаружение дыма предпочтительнее тепловых извещателей. Источник: выбор извещателей NFPA 72; руководство по применению VESDA."},
  {id:29, q:"'Комбинированный' дымовой извещатель обычно относится к устройству, которое:", opts:["Использует и ионизационное, и фотоэлектрическое обнаружение","Объединяет ручной извещатель и сирену","Обнаруживает только диоксид углерода","Имеет два шнура питания"], re:"Комбинированный дымовой извещатель сочетает и ионизационное, и фотоэлектрическое обнаружение, чтобы хорошо реагировать как на пламенные, так и на тлеющие пожары. Источник: руководство NFPA по дымовым извещателям."},
  {id:30, q:"Какое утверждение об ионизационных извещателях ВЕРНО согласно действующим сертификациям?", opts:["Они запрещены NFPA 72 во всех зданиях","Они никогда не требуют обслуживания","Они обнаруживают только тепло, а не дым","Они сертифицированы по UL 268 и приняты по NFPA 72 для коммерческого использования"], re:"Ионизационные дымовые извещатели соответствуют UL 268 и приняты по NFPA 72; как и все дымовые извещатели, они требуют периодических функциональных проверок и проверок чувствительности. Источник: NFPA 72; UL 268."},
  {id:31, q:"Установка точечного дымового извещателя непосредственно в высокоскоростном потоке воздуха от приточного диффузора HVAC является проблемой, потому что:", opts:["Это выглядит непривлекательно","Это превращает его в тепловой извещатель","Это увеличивает мощность радиоактивного источника","Движущийся воздух может разбавить или отвести дым от извещателя, задерживая реакцию"], re:"Сильный поток воздуха вблизи диффузоров может не дать дыму достичь чувствительной камеры, поэтому извещатели следует держать вдали от прямого приточного потока воздуха. Источник: руководство по размещению NFPA 72."},
  {id:32, q:"Дымовые извещатели, используемые в СИСТЕМЕ пожарной сигнализации (в отличие от автономных извещателей), как правило:", opts:["Запитаны только от батареи 9V без контроля","Запрещены инициировать оповещение","Обязаны не содержать электроники","Подключены к контрольно-приёмному прибору пожарной сигнализации и контролируются им"], re:"Системные извещатели подключаются к контрольно-приёмному прибору пожарной сигнализации, который контролирует их и инициирует оповещение; автономные извещатели самодостаточны. Источник: основы системы NFPA 72."},
  {id:33, q:"ОСНОВНАЯ цель канального дымового извещателя в системе HVAC — это:", opts:["Заменить все площадные дымовые извещатели в здании","Обеспечить общее покрытие площади для людей","Измерять температуру канала для комфорта","Обнаруживать дым в воздухообрабатывающей установке и отключать/управлять HVAC для ограничения распространения дыма"], re:"Канальные дымовые извещатели отбирают пробы воздуха в каналах HVAC для обнаружения дыма и отключения или управления системой, предотвращая распространение дыма; они не заменяют площадное обнаружение. Источник: требования к канальным извещателям NFPA 72 / NFPA 90A."},
  {id:34, q:"Дрейф чувствительности, вызванный накоплением пыли в камере дымового извещателя, устраняется путём:", opts:["Периодической проверки чувствительности и очистки согласно NFPA 72","Закрашивания извещателя","Постоянного отключения извещателя","Игнорирования до выхода устройства из строя"], re:"NFPA 72 требует периодических функциональных проверок и проверок чувствительности/очистки, чтобы извещатели оставались в пределах своего сертифицированного диапазона чувствительности. Источник: проверка, испытания и техническое обслуживание NFPA 72."},
  {id:35, q:"Тепловой извещатель фиксированной температуры срабатывает, когда:", opts:["Температура повышается быстрее заданной скорости","Монооксид углерода достигает 70 ppm","Дым затемняет световой луч","Чувствительный элемент достигает заданной температуры"], re:"Тепловой извещатель фиксированной температуры срабатывает, когда его рабочий элемент достигает заданной температуры (например, 135 F). Источник: определения тепловых извещателей NFPA 72; FM Approvals."},
  {id:36, q:"Тепловой извещатель максимально-дифференциального типа (скорости нарастания, ROR) срабатывает, когда температура воздуха:", opts:["Достигает только фиксированной заданной точки","Остаётся постоянной в течение одного часа","Быстро падает","Повышается быстрее заданной скорости, обычно около 15 F в минуту"], re:"Извещатели ROR реагируют, когда температура повышается быстрее заданной скорости, обычно около 15 F (≈8.3 C) в минуту. Источник: NFPA 72; критерии тепловых извещателей FM Approvals."},
  {id:37, q:"Распространённое стандартное значение фиксированной температуры для тепловых извещателей обычного температурного диапазона составляет примерно:", opts:["55 F","32 F","500 F","135 F"], re:"Тепловые извещатели фиксированной температуры обычного диапазона обычно срабатывают около 135 F (и 200 F для промежуточных значений). Источник: классификации температуры тепловых извещателей NFPA 72."},
  {id:38, q:"Тепловой извещатель максимально-дифференциального типа может НЕ сработать в каком сценарии?", opts:["Очень медленно развивающийся пожар, температура которого ползёт вверх ниже порога скорости","Внезапный пожар, быстро повышающий температуру","Любой пожар, производящий быстрое тепло","Пожар прямо под извещателем"], re:"Медленно тлеющий пожар может повышать температуру ниже порога скорости нарастания и не сработать на элементе ROR; поэтому ROR часто комбинируют с элементом фиксированной температуры. Источник: работа тепловых извещателей NFPA 72."},
  {id:39, q:"Комбинированный тепловой извещатель фиксированной температуры/скорости нарастания обеспечивает:", opts:["Только обнаружение дыма","Юстировку луча","Обнаружение монооксида углерода","Реакцию как на быстро, так и на медленно развивающиеся пожары"], re:"Элемент ROR улавливает быстрые пожары, а элемент фиксированной температуры улавливает медленные, охватывая обе модели роста пожара. Источник: NFPA 72; комбинированные тепловые извещатели FM Approvals."},
  {id:40, q:"Тепловой извещатель с компенсацией скорости лучше всего описывается как извещатель, который:", opts:["Реагирует, когда окружающий воздух достигает заданной температуры с минимальным тепловым запаздыванием","Считает частицы дыма","Обнаруживает УФ-излучение","Измеряет поток воздуха в канале"], re:"Извещатель с компенсацией скорости реагирует, когда окружающий воздух достигает заданной температуры при малом влиянии скорости нарастания (низкое тепловое запаздывание), ведя себя как быстрый извещатель фиксированной температуры. Источник: определения NFPA 72; FM Approvals."},
  {id:41, q:"По сравнению с дымовыми извещателями, тепловые извещатели, как правило:", opts:["Дают более раннее оповещение о пожаре","Более склонны к ложным срабатываниям","Реагируют позже, но с меньшим числом ложных срабатываний","Обнаруживают невидимые аэрозоли"], re:"Тепловые извещатели реагируют позже (тепло накапливается после дыма), но гораздо менее склонны к ложным срабатываниям, что делает их подходящими для грязных или суровых зон. Источник: выбор извещателей NFPA 72."},
  {id:42, q:"В какой среде ТЕПЛОВОЙ извещатель обычно предпочтительнее дымового извещателя?", opts:["Чистый офис","Палата больницы для сна","Пыльная, грязная или насыщенная парами зона, такая как котельная или гараж","Серверная, нуждающаяся в очень раннем оповещении"], re:"Тепловые извещатели выбирают для пыльных, грязных, насыщенных парами или с высокой влажностью помещений, где дымовые извещатели давали бы ложные срабатывания. Источник: руководство по выбору извещателей NFPA 72."},
  {id:43, q:"'Невосстанавливаемый' тепловой извещатель фиксированной температуры (например, с плавкой вставкой или эвтектического типа) должен быть:", opts:["Сброшен ключом после каждой проверки","Перезаряжен электрически","Окрашен для восстановления функции","Заменён после срабатывания"], re:"Невосстанавливаемые извещатели используют плавящийся (эвтектический) элемент, который разрушается при срабатывании и должен быть заменён; восстанавливаемые типы сбрасываются автоматически. Источник: типы тепловых извещателей NFPA 72."},
  {id:44, q:"Шаг точечных тепловых извещателей по NFPA 72 использует 'сертифицированный шаг'. Ключевое правило для покрытия состоит в том, что каждая точка потолка должна находиться в пределах:", opts:["0.7 от сертифицированного шага извещателя","2.0 от сертифицированного шага","ровно 100 ft","ширины здания"], re:"'Правило 0.7' требует, чтобы каждая точка потолка находилась в пределах 0.7 × сертифицированного шага теплового извещателя. Источник: шаг тепловых извещателей NFPA 72 ('Правило Точки 7' NTC)."},
  {id:45, q:"По мере увеличения высоты потолка требуемый шаг точечных тепловых извещателей, как правило, должен быть:", opts:["Увеличен","Установлен в ноль","Оставлен без изменений","Уменьшен (умножен на коэффициент меньше 1)"], re:"NFPA 72 применяет коэффициент уменьшения по высоте (<1) к сертифицированному шагу тепловых извещателей по мере увеличения высоты потолков, потому что тепло расслаивается, прежде чем достичь удалённых извещателей. Источник: Таблица 17.6.3.5.1 NFPA 72."},
  {id:46, q:"Тепловой извещатель линейного типа обычно использует:", opts:["Один радиоактивный источник","Ультразвуковой преобразователь","Фотоэлектрическую камеру","Непрерывный кабель, изоляция которого разрушается при заданной температуре, замыкая цепь"], re:"Линейное (линейного типа) обнаружение тепла использует непрерывный термочувствительный кабель; при номинальной температуре изоляция разрушается, и проводники замыкаются, сигнализируя о месте нагрева. Источник: тепловое обнаружение линейного типа NFPA 72."},
  {id:47, q:"Тепловой извещатель с более высокой номинальной температурой (например, 190-200 F вместо 135 F) выбирался бы для места, которое:", opts:["Обычно остаётся очень холодным","Не имеет риска пожара","Является чистым офисом","Имеет высокую нормальную температуру окружающей среды, чтобы избежать ложного срабатывания"], re:"Тепловые извещатели рассчитываются выше максимальной ожидаемой нормальной температуры окружающей среды; горячие зоны (чердаки, котельные) используют извещатели с более высоким номиналом для предотвращения ложного срабатывания. Источник: классификация температуры NFPA 72."},
  {id:48, q:"Термин 'тепловое запаздывание' в обнаружении тепла относится к:", opts:["Задержке до того, как чувствительный элемент достигнет фактической температуры воздуха","Времени монтажа извещателя","Задержке сирены сигнализации","Проценту затемнения дымом"], re:"Тепловое запаздывание — это разница между фактической температурой воздуха и температурой элемента извещателя; извещатели с компенсацией скорости разработаны для его минимизации. Источник: принципы работы тепловых извещателей NFPA 72."},
  {id:49, q:"Какой тип теплового извещателя ВОССТАНАВЛИВАЕТСЯ (сбрасывается) сам после удаления источника тепла, без замены?", opts:["Невосстанавливаемый тип с плавкой вставкой (эвтектический)","Тип с плавящейся таблеткой","Тип с хрупкой стеклянной колбой","Восстанавливаемый точечный биметаллический тип"], re:"Восстанавливаемые биметаллические извещатели изгибаются при изменении температуры и возвращаются в норму при охлаждении; типы с плавкой вставкой/эвтектические и со стеклянной колбой разрушаются при срабатывании. Источник: восстанавливаемые и невосстанавливаемые извещатели NFPA 72."},
  {id:50, q:"Почему тепловые извещатели НЕ рекомендуются в качестве основного извещателя безопасности жизни в спальных зонах?", opts:["Они слишком дороги","Они работают только на улице","Их нельзя подключить к панели","Они реагируют слишком поздно, чтобы защитить спящих людей от дыма и токсичных газов"], re:"Поскольку тепло накапливается после дыма и CO, тепловые извещатели предупреждают слишком поздно для безопасности жизни в спальных зонах, где вместо этого требуется обнаружение дыма. Источник: выбор извещателей NFPA 72; руководство NFPA по безопасности жизни."},
  {id:51, q:"Пневматический точечный тепловой извещатель скорости нарастания работает за счёт того, что:", opts:["Обнаруживает альфа-частицы","Плавит металлическую таблетку","Рассеивает инфракрасный свет","Воздух в герметичной камере расширяется быстрее, чем калиброванное вентиляционное отверстие может стравить, изгибая мембрану для замыкания контактов"], re:"Пневматические извещатели ROR используют герметичную воздушную камеру с небольшим вентиляционным отверстием; быстрый нагрев расширяет воздух быстрее, чем он может стравиться, изгибая мембрану, которая замыкает контакты сигнализации. Источник: принцип работы скорости нарастания NFPA 72."},
  {id:52, q:"Согласно NFPA 72, рабочая часть ручного пожарного извещателя должна монтироваться не ниже ___ и не выше ___ над чистым полом.", opts:["24 in. / 36 in.","12 in. / 24 in.","60 in. / 72 in.","42 in. / 48 in."], re:"NFPA 72 (17.14) требует, чтобы рабочая часть ручного пожарного извещателя находилась на высоте минимум 42 in. и максимум 48 in. над чистым полом. Источник: NFPA 72 §17.14; блог NFPA о высоте ручных извещателей."},
  {id:53, q:"Ручной пожарный извещатель 'двойного действия' требует, чтобы пользователь:", opts:["Выполнил два отдельных действия, например, поднял крышку или заслонку и затем потянул","Потянул дважды в одном направлении","Нажал одну кнопку один раз","Вставил монету"], re:"Извещатели двойного действия требуют двух отдельных движений (например, поднять/нажать крышку, затем потянуть), снижая случайное или умышленное срабатывание. Источник: руководство по ручным пожарным извещателям NFPA 72."},
  {id:54, q:"Ручной пожарный извещатель 'одинарного действия' активируется:", opts:["Двумя отдельными шагами","Только дистанционным сигналом","Одним движением, обычно одним рывком ручки","Теплом, достигающим 135 F"], re:"Извещатели одинарного действия срабатывают одним движением (одним рывком), обеспечивая самую быструю ручную активацию. Источник: типы ручных пожарных извещателей NFPA 72."},
  {id:55, q:"NFPA 72 требует, чтобы ручной пожарный извещатель располагался на каком расстоянии от каждой выходной двери?", opts:["В пределах 60 in. (5 ft) от выхода","В пределах 50 ft от выхода","В любом месте этажа","Только в пределах 200 ft"], re:"Ручной пожарный извещатель должен располагаться в пределах 60 in. (5 ft) от проёма выходной двери на каждом выходе. Источник: размещение ручных извещателей NFPA 72 §17.14."},
  {id:56, q:"На большом этаже NFPA 72 ограничивает горизонтальное расстояние перемещения до ближайшего ручного пожарного извещателя не более чем примерно:", opts:["50 ft","100 ft","200 ft","500 ft"], re:"Расстояние перемещения до ручного пожарного извещателя не должно превышать 200 ft на одном этаже; для соблюдения этого добавляют дополнительные извещатели. Источник: NFPA 72 §17.14."},
  {id:57, q:"Стандартный цвет, требуемый для ручных пожарных извещателей, — это:", opts:["Зелёный","Синий","Красный","Жёлтый"], re:"Ручные пожарные извещатели должны быть красными. Источник: требования к ручным пожарным извещателям NFPA 72 §17.14."},
  {id:58, q:"Где обычно располагают ручные пожарные извещатели вдоль пути эвакуации?", opts:["В естественном доступе к выходу, рядом с дверями, которые люди используют для выхода","Только внутри запертых шкафов","Только на крыше","Спрятанными за мебелью"], re:"Извещатели размещают на естественном пути эвакуации рядом с выходами, чтобы выходящий человек проходил мимо одного из них. Источник: цель размещения NFPA 72 §17.14."},
  {id:59, q:"Основная причина выбора ручных извещателей ДВОЙНОГО действия (или с крышкой) в школе или другой зоне с высокой проходимостью — это:", opts:["Снизить умышленные или случайные ложные срабатывания","Сделать их труднее находимыми для пожарных","Устранить необходимость в дымовых извещателях","Понизить высоту монтажа"], re:"Дополнительный шаг (и защитные крышки) на извещателях двойного действия сокращает ложные и умышленные срабатывания в помещениях с высокой проходимостью. Источник: руководство по ручным пожарным извещателям NFPA 72."},
  {id:60, q:"Ручной пожарный извещатель классифицируется в системе пожарной сигнализации как:", opts:["Оповещатель","Источник питания","Извещатель (инициирующее устройство)","Прибор индикации"], re:"Ручной пожарный извещатель — это инициирующее устройство ручного действия, которое подаёт сигнал на контрольный прибор. Источник: определения инициирующих устройств NFPA 72."},
  {id:61, q:"После активации обычного ручного извещателя с разбиваемым стеклом или с фиксацией восстановление его в нормальное состояние обычно требует:", opts:["Покрасить его снова в красный","Подождать, пока он остынет ниже 135 F","Использовать ключ или инструмент для сброса (и заменить стеклянный стержень, если он есть)","Только выключить и включить питание здания"], re:"Ручные извещатели с фиксацией остаются сработавшими до сброса соответствующим ключом/инструментом; типы с разбиваемым стержнем также требуют замены стеклянного/пластикового стержня. Источник: работа ручных пожарных извещателей производителя/NFPA 72."},
  {id:62, q:"Чёткая инструкция по эксплуатации, такая как слово 'PULL' (ПОТЯНУТЬ) на ручном извещателе, служит для того, чтобы:", opts:["Украсить устройство","Указать калибр провода","Сообщить людям, как им пользоваться во время чрезвычайной ситуации","Отметить радиоактивный источник"], re:"Ручные пожарные извещатели несут чёткие инструкции по эксплуатации (например, PULL/ПОТЯНУТЬ), чтобы люди могли активировать их в состоянии стресса. Источник: маркировка ручных пожарных извещателей NFPA 72."},
  {id:63, q:"Положение 'проверка', управляемое ключом, на некоторых ручных извещателях позволяет технику:", opts:["Навсегда отключить систему","Увеличить громкость оповещения","Привести извещатель в действие для проверки без разбивания стержня или стекла","Изменить чувствительность извещателя"], re:"Функция проверки с ключом позволяет приводить извещатель в действие и сбрасывать его для периодических проверок без расходования разбиваемого элемента. Источник: ITM NFPA 72; документация производителя."},
  {id:64, q:"Монтаж всех ручных пожарных извещателей в пределах диапазона 42-48 in. главным образом поддерживает:", opts:["Единообразную, доступную эксплуатацию, в том числе людьми в инвалидных колясках (ADA)","Сокращение длины провода","Их сокрытие от глаз","Тепловое обнаружение"], re:"Диапазон 42-48 in. обеспечивает единообразную досягаемость и доступность, согласуясь с диапазонами досягаемости ADA. Источник: NFPA 72 §17.14; согласование с диапазонами досягаемости ADA."},
  {id:65, q:"Когда ручной пожарный извещатель активирован, контрольный прибор пожарной сигнализации должен:", opts:["Игнорировать его в течение 5 минут","Инициировать состояние пожарной тревоги и оповещатели","Отключить все извещатели","Сбросить себя автоматически"], re:"Приведение в действие инициирующего устройства, такого как ручной извещатель, переводит панель в состояние тревоги и активирует оповещение согласно программе системы. Источник: работа системы NFPA 72."},
  {id:66, q:"В адресной системе пожарной сигнализации ручной пожарный извещатель обычно:", opts:["Сообщает свой конкретный адрес/местоположение на панель","Вообще не может быть идентифицирован","Работает только без какой-либо проводки","Функционирует исключительно как сирена"], re:"Адресные ручные извещатели сообщают уникальный адрес, чтобы панель могла отобразить точное устройство/местоположение, которое было активировано. Источник: основы адресных систем NFPA 72."},
  {id:67, q:"Что НЕ является подходящим соображением по размещению ручного пожарного извещателя?", opts:["Рядом с каждым выходом","На пути эвакуации","За запертой дверью, недоступной для людей","На единообразной высоте 42-48 in."], re:"Ручные извещатели должны быть легко доступны на пути эвакуации рядом с выходами; размещение одного из них за запертой, недоступной дверью сводит на нет его назначение. Источник: размещение NFPA 72 §17.14."},
  {id:68, q:"Ручной пожарный извещатель отличается от автоматического извещателя тем, что он:", opts:["Требует действия человека для инициирования тревоги","Обнаруживает дым автоматически","Обнаруживает тепло автоматически","Обнаруживает CO автоматически"], re:"Ручные извещатели — это инициирующие устройства, приводимые в действие человеком, тогда как автоматические извещатели воспринимают сигнатуру пожара без участия человека. Источник: классификации инициирующих устройств NFPA 72."},
  {id:69, q:"Линейный дымовой извещатель (с проецируемым лучом) воспринимает дым путём:", opts:["Подсчёта альфа-частиц","Измерения уменьшения света (затемнения) вдоль луча от передатчика к приёмнику","Обнаружения тепла при 135 F","Отбора проб концентрации CO"], re:"Извещатели с проецируемым лучом измеряют затемнение инфракрасного луча между передатчиком и приёмником; дым, пересекающий луч, ослабляет свет. Источник: обнаружение проецируемым лучом NFPA 72; справочные данные по оптическому лучу."},
  {id:70, q:"Линейные дымовые извещатели с проецируемым лучом особенно хорошо подходят для:", opts:["Маленьких чуланов","Больших открытых пространств с высокими потолками, таких как атриумы и склады","Только внутри каналов HVAC","Герметичных электрических шкафов"], re:"Лучевые извещатели эффективно защищают большие, высокие, открытые пространства (атриумы, склады, спортзалы), которые иначе потребовали бы множества точечных извещателей. Источник: применение проецируемого луча NFPA 72; справочные данные ORR/Hochiki."},
  {id:71, q:"На гладких потолках NFPA 72 даёт ориентир горизонтального шага между соседними проецируемыми лучами не более чем примерно:", opts:["10 ft","30 ft","60 ft","300 ft"], re:"NFPA 72 использует ориентир не более 60 ft между лучами (и половину этого до параллельной боковой стены) на гладких потолках. Источник: шаг проецируемого луча NFPA 72 §17.7 (UpCodes)."},
  {id:72, q:"'Рефлекторный' (одностороннего типа) извещатель с проецируемым лучом использует:", opts:["Два радиоактивных источника","Передатчик/приёмник в одном устройстве, нацеленный на удалённый отражатель","Только тепловой элемент","Сеть труб для отбора проб"], re:"Рефлекторные лучевые извещатели объединяют передатчик и приёмник в одном корпусе и отражают луч от удалённого отражателя, упрощая установку. Источник: NFPA 72; руководства по применению лучевых извещателей."},
  {id:73, q:"Внезапная ПОЛНАЯ блокировка пути проецируемого луча извещателя (например, объект, помещённый перед приёмником), обычно вызывает:", opts:["Пожарную тревогу немедленно","Сигнал неисправности, а не пожарную тревогу","Никакой реакции вообще","Сброс панели"], re:"Полная блокировка луча рассматривается как состояние неисправности (потеря луча), что отличает её от постепенного затемнения дымом. Источник: работа проецируемого луча NFPA 72; сертификации производителя."},
  {id:74, q:"Аспирационная система обнаружения дыма (с отбором проб воздуха), такая как VESDA, работает путём:", opts:["Ожидания, пока дым нанесёт в точечную камеру","Непрерывного забора воздуха через сеть труб в высокочувствительную камеру обнаружения","Расплавления плавкой вставки","Обнаружения только монооксида углерода"], re:"Аспирационные системы используют вентилятор/аспиратор для непрерывного забора проб воздуха через трубы отбора проб в чувствительную лазерную/оптическую камеру, обеспечивая очень раннее оповещение. Источник: отбор проб воздуха NFPA 72 §17.7; справочные данные Xtralis VESDA."},
  {id:75, q:"Ключевое преимущество аспирационного обнаружения (типа VESDA) над стандартными точечными извещателями — это:", opts:["Оно не нуждается в питании","Очень раннее оповещение / очень высокая чувствительность к минимальным уровням дыма","Оно обнаруживает тепло быстрее","Оно устраняет необходимость в панели управления"], re:"Аспирационные системы обеспечивают очень раннее оповещение, обнаруживая чрезвычайно низкие концентрации дыма, что идеально для ценных или критически важных помещений. Источник: NFPA 72 §17.7; руководство по применению VESDA."},
  {id:76, q:"В NFPA 72 каждое отверстие отбора проб аспирационной системы, как правило, рассматривается, для размещения и шага, как:", opts:["Оповещатель","Точечный дымовой извещатель","Ручной пожарный извещатель","Тепловой извещатель"], re:"NFPA 72 (17.7) требует, чтобы каждое отверстие отбора проб рассматривалось как точечный дымовой извещатель для размещения и шага, если не используется проектирование на основе характеристик. Источник: NFPA 72 §17.7.3.6.1."},
  {id:77, q:"Извещатель пламени воспринимает пожар, реагируя на:", opts:["Лучистую энергию (УФ или ИК), излучаемую пламенем","Подсчёт частиц дыма","Только температуру воздуха","Концентрацию монооксида углерода"], re:"Извещатели пламени — это извещатели лучистой энергии, которые воспринимают УФ или ИК-излучение пламени. Источник: определение извещателя лучистой энергии (пламени) NFPA 72."},
  {id:78, q:"Извещатель пламени UV/IR повышает надёжность по сравнению с однодатчиковым устройством путём:", opts:["Использования двух разных спектральных диапазонов для подтверждения пламени и отсева ложных источников","Добавления радиоактивного источника","Отбора проб воздуха канала","Расплавления при 135 F"], re:"Сочетание ультрафиолетового и инфракрасного обнаружения требует, чтобы оба диапазона подтвердили пламя, повышая устойчивость к ложным срабатываниям. Источник: принципы работы извещателей пламени (AZoSensors; MSA)."},
  {id:79, q:"ИК-датчик во многих извещателях пламени для углеводородов нацелен на излучение вблизи 4.3-4.4 микрон, потому что этот диапазон соответствует:", opts:["Видимому свету от ламп","Горячему диоксиду углерода (CO2), образующемуся при горении углеводородов","Только водяному пару","Радиоволнам"], re:"Горящие углеводороды излучают сильную ИК-сигнатуру вблизи 4.3 микрон от горячего CO2; ИК-извещатели пламени ориентируются на этот диапазон. Источник: спектральные справочные данные извещателей пламени (AZoSensors)."},
  {id:80, q:"Извещатель пламени — хороший выбор там, где:", opts:["Пожар может вспыхнуть как открытое пламя с малым количеством дыма, например, в зонах обращения с топливом или ангарах","Ожидается только медленное тление без пламени","Риск пожара отсутствует","Мониторинг CO — единственная потребность"], re:"Извещатели пламени превосходны там, где могут возникать быстрые пламенные, высокоэнергетические пожары (горючие жидкости, газы) с малым ранним дымом. Источник: применение извещателей лучистой энергии NFPA 72."},
  {id:81, q:"Извещатель пламени, как правило, требует:", opts:["Прямой линии видимости к возможному пламени","Отсутствия обзора защищаемой зоны","Контакта с топливом","Погружения в воду"], re:"Поскольку они воспринимают лучистую энергию, извещатели пламени должны иметь беспрепятственную линию видимости к зоне, где может появиться пламя. Источник: размещение извещателей лучистой энергии NFPA 72."},
  {id:82, q:"Извещатель монооксида углерода (CO) обычно использует какую технологию обнаружения?", opts:["Ионизационную камеру","Электрохимический датчик","Биметаллическую пластину","Инфракрасный луч через помещение"], re:"Бытовые/коммерческие извещатели CO обычно используют электрохимическую ячейку, которая реагирует с CO с образованием измеримого тока. Источник: справочные данные по обнаружению CO (NFPA 720/72; Kidde)."},
  {id:83, q:"Какое утверждение об извещателях CO является правильным?", opts:["Извещатель CO — это то же самое, что дымовой извещатель","Извещатель CO воспринимает токсичный газ монооксид углерода, а не дым или пламя","Извещатели CO обнаруживают тепло при 135 F","CO — это видимый газ со сладким запахом"], re:"Извещатели CO воспринимают монооксид углерода — бесцветный и не имеющий запаха токсичный газ; они не заменяют дымовые или тепловые извещатели. Источник: требования к обнаружению CO NFPA 720/72."},
  {id:84, q:"В жилищах извещатели CO, как правило, должны располагаться:", opts:["Только на чердаке","За пределами каждой отдельной спальной зоны и на каждом уровне жилища","Внутри топки камина","Только в гараже"], re:"Нормы требуют извещателей CO за пределами каждой отдельной спальной зоны и на каждом уровне жилища, чтобы люди были предупреждены о CO. Источник: размещение извещателей CO NFPA 720/72; IRC."},
  {id:85, q:"Цепь инициирующих устройств (IDC) лучше всего описывается как цепь, которая:", opts:["Питает сирены и стробоскопы оповещения","Соединяет инициирующие устройства (такие как ручные извещатели и детекторы) с контрольным прибором","Подаёт питание сети в здание","Несёт только телефонную линию"], re:"IDC соединяет инициирующие устройства (ручные извещатели, детекторы, датчики потока воды) с контрольно-приёмным прибором пожарной сигнализации. Источник: определения цепей NFPA 72."},
  {id:86, q:"В обычной IDC Класса B контроль на обрыв цепи обычно обеспечивается с помощью:", opts:["Радиоактивного источника","Оконечного резистора (EOLR)","Датчика пламени","Ручки ручного извещателя"], re:"IDC Класса B оканчивается оконечным резистором; панель пропускает небольшой контрольный ток через шлейф, и потеря этого тока указывает на обрыв. Источник: контроль цепей NFPA 72; пути NTC."},
  {id:87, q:"Если в IDC Класса B происходит один ОБРЫВ, устройства, расположенные ЗА обрывом, будут:", opts:["Всё равно сообщать о тревогах нормально","Не способны сообщать на панель (становятся неработоспособными)","Автоматически переключаться на Класс A","Напрямую запускать оповещатели"], re:"В цепи Класса B один обрыв изолирует всё, что находится за обрывом, поэтому эти устройства не могут подать сигнал на панель; панель показывает неисправность. Источник: поведение Класса B NFPA 72; пути NTC."},
  {id:88, q:"IDC Класса A отличается от Класса B тем, что после одного обрыва провода она:", opts:["Теряет все устройства","Всё ещё может связываться с каждым устройством, питая шлейф с обоих направлений","Подаёт непрерывную тревогу","Не требует контроля"], re:"Путь Класса A возвращается к панели, поэтому один обрыв обходится за счёт питания шлейфа с обоих концов, и все устройства продолжают сообщать. Источник: пути Класса A и Класса B NFPA 72."},
  {id:89, q:"Обычные инициирующие устройства в базовой IDC работают путём:", opts:["Отправки цифрового адреса","Переключения из нормально-разомкнутого состояния в замкнутое (замыкая шлейф) для сигнала тревоги","Увеличения значения EOLR","Отключения питания здания"], re:"Обычные инициирующие устройства — это нормально-разомкнутые контакты, которые замыкаются при тревоге, создавая низкое сопротивление через шлейф, которое панель считывает как тревогу. Источник: работа обычной IDC NFPA 72."},
  {id:90, q:"В контролируемой IDC Класса B ОБРЫВ цепи обычно сообщается панелью как:", opts:["Тревога","Состояние неисправности","Контрольное событие CO","Только отключение питания"], re:"Потеря контрольного тока (обрыв) в IDC Класса B вызывает сигнал неисправности, отличный от тревоги, создаваемой замыканием устройства. Источник: индикация неисправности цепи NFPA 72."},
  {id:91, q:"В обычной IDC Класса B тревога отличается от нормального состояния/состояния неисправности, потому что замыкание устройства заставляет сопротивление шлейфа:", opts:["Возрасти до бесконечности (обрыв)","Упасть до низкого значения (замыкание через линию)","Остаться точно на значении EOLR","Стать отрицательным"], re:"Замкнутое инициирующее устройство замыкает шлейф, понижая сопротивление значительно ниже значения EOLR; панель считывает это падение как тревогу. Обрыв (бесконечность) считывается как неисправность. Источник: работа обычной IDC NFPA 72."},
  {id:92, q:"Цель контроля IDC состоит в том, чтобы:", opts:["Улучшить звучание сирен","Обнаруживать неисправности проводки (обрывы/замыкания/замыкания на землю), чтобы их можно было устранить до чрезвычайной ситуации","Увеличить срок службы радиоактивного источника","Уменьшить высоту монтажа устройств"], re:"Контроль позволяет панели сигнализировать о неисправностях цепи, чтобы повреждённая проводка была найдена и устранена до того, как она отключит защиту. Источник: цель контроля цепей NFPA 72."},
  {id:93, q:"В Статье 760 NEC цепи пожарной сигнализации делятся на две основные категории:", opts:["Переменного и постоянного тока","С ограниченной мощностью (PLFA) и с неограниченной мощностью (NPLFA)","Класс 2 и Класс 3","Высокое напряжение и низкое напряжение"], re:"Статья 760 NEC разделяет цепи пожарной сигнализации на цепи с ограниченной мощностью (PLFA) и с неограниченной мощностью (NPLFA), каждая со своими правилами прокладки. Источник: Статья 760 NEC (NFPA 70)."},
  {id:94, q:"Цепь пожарной сигнализации с ограниченной мощностью (PLFA) по NEC 760 должна иметь своё напряжение и мощность ограниченными:", opts:["Сертифицированным источником питания, отвечающим требованиям ограниченной мощности","Оконечным резистором","Самым длинным участком провода","Числом извещателей"], re:"Цепи PLFA питаются от сертифицированного источника с ограниченной мощностью (по NEC 760.121), который по своей сути ограничивает ток и снижает риск поражения/пожара, допуская менее строгую прокладку. Источник: Статья 760 NEC."},
  {id:95, q:"По сравнению с цепями PLFA, цепи пожарной сигнализации с неограниченной мощностью (NPLFA):", opts:["Могут работать при более высоком напряжении/мощности и имеют более строгие правила прокладки","Всегда 24 V и легки в установке","Не несут электрического риска","Не разрешены NEC"], re:"Цепи NPLFA (до 600 V, мощность не ограничена по своей сути) несут больший риск поражения и должны следовать более строгим правилам установки, чем PLFA. Источник: требования NPLFA Статьи 760 NEC."},
  {id:96, q:"Проводники пожарной сигнализации с ограниченной мощностью (PLFA), как правило, должны содержаться:", opts:["В том же кабеле, что и силовые проводники здания","Физически отделёнными от проводников освещения, силовых и других более высокоэнергетических, если не применяется исключение","Только снаружи","Под напряжением 600 V"], re:"NEC 760 требует, чтобы проводники PLFA были отделены от проводников освещения, силовых, Класса 1 и NPLFA (без общего кабеля/короба), кроме случаев, когда конкретные исключения это допускают. Источник: правила разделения Статьи 760 NEC."},
  {id:97, q:"Замыкание на ЗЕМЛЮ в цепи инициирующих устройств должно быть:", opts:["Проигнорировано контрольным прибором","Обозначено как состояние неисправности на контрольном приборе","Сообщено только как тревога","Использовано для отключения извещателей"], re:"NFPA 72 требует, чтобы контрольный прибор отслеживал целостность цепи; замыкание на землю в контролируемой цепи приводит к индикации неисправности. Источник: контроль цепей NFPA 72."},
  {id:98, q:"Смешивание обычных инициирующих устройств в IDC означает, что когда одно устройство подаёт тревогу, панель может определить:", opts:["Точное отдельное устройство","Только то, что сработало какое-то устройство в этой зоне/цепи","Используемый калибр провода","Температурный номинал извещателя"], re:"Обычная IDC сообщает по зоне/цепи, поэтому панель знает, что сработало устройство в этой цепи, но не какое именно; адресные системы определяют конкретное устройство. Источник: обычные и адресные системы NFPA 72."},
  {id:99, q:"В базовой обычной IDC какое электрическое состояние панель считает 'нормальным' (нет тревоги, нет неисправности)?", opts:["Замыкание через шлейф","Ноль вольт на шлейфе","Контрольный ток, протекающий через оконечный резистор","Звучащие сирены"], re:"Нормальное состояние — это небольшой контрольный ток, протекающий через EOLR; замыкание считывается как тревога, а обрыв считывается как неисправность. Источник: контроль обычной IDC NFPA 72."},
  {id:100, q:"Почему оконечный резистор размещают на САМОМ ДАЛЬНЕМ (последнем) устройстве IDC Класса B, а не на панели?", opts:["Чтобы сэкономить провод","Чтобы контрольный ток должен был проходить через весь участок, позволяя обнаружить обрыв в любом месте","Чтобы увеличить громкость оповещения","Чтобы преобразовать цепь в Класс A"], re:"Размещение EOLR на конце вынуждает контрольный ток проходить через всю цепь; обрыв в любом месте прерывает этот ток и сигнализируется как неисправность. Источник: принцип контроля Класса B NFPA 72."},
  {id:101, q:"Для звукового оповещения в публичном режиме NFPA 72 требует, чтобы сигнал был как минимум на сколько дБА выше среднего уровня фонового шума?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], re:"NFPA 72 (2022) 18.4.3.1: звуковые оповещатели публичного режима должны создавать уровень звука как минимум на 15 dBA выше среднего фонового, либо на 5 dBA выше максимального уровня звука длительностью 60 с, в зависимости от того, что больше."},
  {id:102, q:"Звуковые сигналы публичного режима также должны быть как минимум на сколько дБА выше максимального уровня звука длительностью не менее 60 секунд?", opts:["10 dBA","5 dBA","15 dBA","25 dBA"], re:"NFPA 72 18.4.3.1: требование составляет 15 dBA выше среднего фонового ИЛИ 5 dBA выше 60-секундного максимума, в зависимости от того, что больше."},
  {id:103, q:"В спальных зонах звуковой сигнал у подушки должен иметь как минимум какой уровень звука, в зависимости от того, что больше?", opts:["65 dBA","70 dBA","75 dBA","85 dBA"], re:"NFPA 72 18.4.5: в спальных помещениях сигнал должен быть на 15 dBA выше фонового, на 5 dBA выше 60-секундного максимума или составлять не менее 75 dBA у подушки, в зависимости от того, что больше."},
  {id:104, q:"На какой высоте над полом в занимаемой зоне измеряются уровни звука публичного режима?", opts:["1.0 m (3 ft)","1.2 m (4 ft)","1.8 m (6 ft)","1.5 m (5 ft)"], re:"NFPA 72 18.4.3: измерения проводятся на высоте 1.5 m (5 ft) над полом в занимаемой зоне, с A-взвешиванием."},
  {id:105, q:"Суммарный уровень звукового давления от всех звуковых оповещателей в сочетании с фоновым шумом НЕ должен превышать какое значение на минимальном расстоянии слышимости?", opts:["110 dBA","105 dBA","100 dBA","120 dBA"], re:"NFPA 72 18.4.4: суммарное звуковое давление не должно превышать 110 dBA на минимальном расстоянии слышимости для защиты слуха."},
  {id:106, q:"Для звукового оповещения в частном режиме сигнал должен быть как минимум на сколько дБА выше среднего уровня фонового шума?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], re:"NFPA 72 18.4.4 (частный режим): как минимум на 10 dBA выше среднего фонового или на 5 dBA выше 60-секундного максимума, в зависимости от того, что больше."},
  {id:107, q:"Какую шкалу взвешивания указывает NFPA 72 для измерения уровней звука оповещения?", opts:["C-взвешивание (dBC)","Z-взвешивание (dBZ)","A-взвешивание (dBA)","Линейная (dB SPL)"], re:"NFPA 72 глава 18 указывает шкалу с A-взвешиванием (dBA), которая приближённо соответствует чувствительности человеческого слуха."},
  {id:108, q:"Чтобы разбудить людей в спальных зонах, NFPA 72 требует, чтобы сигнал дымового извещателя/оповещения включал какую частотную характеристику?", opts:["Высокочастотный тон 5000 Hz","Чистый синусоидальный тон 1000 Hz","Ультразвуковой пилот-тон","Низкочастотный прямоугольный сигнал 520 Hz"], re:"NFPA 72 18.4.5.3: оповещатели, предназначенные для пробуждения спящих, должны создавать низкочастотный прямоугольный сигнал 520 Hz ±10 %, который пробуждает эффективнее (включая людей с нарушениями слуха)."},
  {id:109, q:"Когда между звуковым оповещателем и подушкой имеется дверь или иная преграда, как определяется уровень звука в спальной зоне?", opts:["Измеряется с установленной преградой (закрытой)","Измеряется с открытой преградой","Рассчитывается без преграды","Преграда полностью игнорируется"], re:"NFPA 72 18.4.5: уровень звука измеряется при промежуточных преградах (двери, шторы, перегородки) в их нормальном закрытом положении, поскольку это наихудший случай."},
  {id:110, q:"'Средний уровень фонового шума' по NFPA 72 — это среднеквадратичное значение всех звуков за какой минимальный период в течение 24-часовых суток?", opts:["1 минута","Время, достаточное для характеристики зоны","24 часа репрезентативного измерения","5 минут"], re:"Определения NFPA 72: средний фоновый — это среднеквадратичный (RMS) уровень звука, измеренный за время, достаточное для репрезентативности нормального состояния помещения."},
  {id:111, q:"Если в помещении средний фоновый шум составляет 55 dBA, каков минимальный уровень сигнала публичного режима при использовании только правила '15 дБА выше фонового'?", opts:["60 dBA","65 dBA","70 dBA","75 dBA"], re:"NFPA 72 18.4.3.1: 55 dBA фонового + 15 dBA = минимум 70 dBA (перед проверкой правила 60-секундного максимума)."},
  {id:112, q:"Звуковые оповещатели, как правило, НЕ требуются для работы в какой из следующих зон?", opts:["Коридоры и вестибюли","Спальные помещения","Зрелищные (сборные) объекты","Механические/электрические помещения, где не ожидается присутствие людей"], re:"NFPA 72 / IBC: оповещение предусматривается там, где необходимо предупредить людей; незанятые помещения механического/электрического оборудования обычно не требуют оповещения людей."},
  {id:113, q:"Какова основная цель ограничения максимального звукового давления в 110 dBA?", opts:["Предотвратить повреждение слуха у людей","Сэкономить заряд батареи","Снизить стоимость проводки","Улучшить синхронизацию световых оповещателей"], re:"NFPA 72 18.4.4: предел в 110 dBA на минимальном расстоянии слышимости защищает людей от травмы слуха во время эвакуации."},
  {id:114, q:"Гудок с характеристикой 90 dBA на 10 ft теряет примерно сколько уровня звука при каждом удвоении расстояния от него (свободное поле)?", opts:["3 dBA","6 dBA","10 dBA","12 dBA"], re:"Закон обратных квадратов даёт примерно падение на 6 dB при каждом удвоении расстояния в свободном поле; это основа проектирования слышимости согласно Приложению A NFPA 72."},
  {id:115, q:"Для целей слышимости какой тип оповещателя создаёт самый громкий выход при заданном входе и распространён в промышленных зонах?", opts:["Колокольчик (chime)","Звонок","Гудок","Громкоговоритель на низких отводах"], re:"NFPA 72 Приложение/практика: гудки обеспечивают наибольший выход в dBA и предпочтительны в промышленных помещениях с высоким фоном; колокольчики/звонки создают более низкие уровни."},
  {id:116, q:"Какое утверждение о сертификации (listing) звуковых оповещателей верно?", opts:["Любой громкоговоритель можно использовать без сертификации","Сертификация относится только к панели","Сертификация требуется только для световых оповещателей","Звуковые оповещатели должны иметь сертификацию для применения в пожарной сигнализации"], re:"NFPA 72 10.3 / 18.3: все оповещатели должны быть сертифицированы по назначению; изготовители публикуют номинальные dBA на 10 ft (в реверберационной камере) для проектирования."},
  {id:117, q:"Звуковые характеристики изготовителя (dBA на 10 ft) обычно публикуются при каком условии для проектирования по нормам?", opts:["Реверберационные условия (UL 464)","Только заглушенные (свободное поле)","Только на открытом воздухе","Под водой"], re:"UL 464 / проектирование NFPA 72: оповещатели характеризуются на 10 ft в реверберационной камере; проектировщики используют эти значения для проверки требования '15 dBA выше фонового'."},
  {id:118, q:"Какова минимальная характеристика в канделах, допустимая для светового оповещателя в коридоре шириной 20 ft или менее?", opts:["30 cd","15 cd","75 cd","110 cd"], re:"NFPA 72 18.5.5.5: коридорные световые оповещатели (коридор шириной ≤ 20 ft) могут быть 15 cd, располагаться в пределах 15 ft от каждого конца и не далее 100 ft друг от друга."},
  {id:119, q:"В коридорном применении световые оповещатели должны располагаться не далее какого расстояния от конца коридора?", opts:["10 ft","20 ft","15 ft","25 ft"], re:"NFPA 72 18.5.5.5: видимые оповещатели должны находиться в пределах 15 ft от конца коридора."},
  {id:120, q:"В коридоре максимальный шаг, допустимый между световыми оповещателями, составляет:", opts:["50 ft","75 ft","130 ft","100 ft"], re:"NFPA 72 18.5.5.5: расстояние между коридорными световыми оповещателями не должно превышать 100 ft."},
  {id:121, q:"Согласно NFPA 72, коридор шире 20 ft при расстановке светового оповещения должен рассматриваться как:", opts:["Помещение (с применением правил расстановки для помещений)","Коридор со световыми оповещателями 15 cd","Наружное пространство","Запотолочное пространство (пленум)"], re:"NFPA 72 18.5.5.5: коридоры шириной более 20 ft расставляются как помещения (Таблица 18.5.5.4.1), обычно требуя более высокую канделу."},
  {id:122, q:"Для одного настенного светового оповещателя какая минимальная кандела требуется для покрытия помещения 20 ft × 20 ft?", opts:["30 cd","15 cd","60 cd","75 cd"], re:"NFPA 72 Таблица 18.5.5.4.1(a): один настенный световой оповещатель, покрывающий помещение 20×20 ft, требует минимум 15 cd."},
  {id:123, q:"При использовании одного настенного светового оповещателя какая минимальная кандела покрывает помещение 40 ft × 40 ft?", opts:["30 cd","95 cd","60 cd","135 cd"], re:"NFPA 72 Таблица 18.5.5.4.1(a): один настенный световой оповещатель для помещения 40×40 ft требует 60 cd."},
  {id:124, q:"Настенные световые оповещатели должны монтироваться так, чтобы вся линза находилась в каком диапазоне высоты над чистовым полом?", opts:["48 to 72 in.","60 to 80 in.","96 to 120 in.","80 to 96 in."], re:"NFPA 72 18.5.5.2: настенные световые оповещатели должны иметь всю линзу в пределах от 80 in. до 96 in. над чистовым полом (или 6 in. ниже потолка, если он ниже)."},
  {id:125, q:"Максимальная высота монтажа, допустимая для потолочного светового оповещателя по таблицам расстановки NFPA 72, составляет:", opts:["30 ft","25 ft","20 ft","40 ft"], re:"NFPA 72 18.5.5.4 / Таблица 18.5.5.4.1(b): таблицы расстановки потолочных световых оповещателей доходят до высоты монтажа 30 ft; оповещатели выше 30 ft подвешиваются на 30 ft или ниже."},
  {id:126, q:"Для спального помещения настенный световой оповещатель, установленный более чем на 24 in. ниже потолка, должен быть как минимум:", opts:["75 cd","110 cd","135 cd","177 cd"], re:"NFPA 72 18.5.5.7: световые оповещатели спальной зоны требуют 110 cd, когда установлены более чем на 24 in. от потолка."},
  {id:127, q:"Для спального помещения световой оповещатель, установленный менее чем на 24 in. от потолка, должен быть как минимум:", opts:["110 cd","135 cd","177 cd","185 cd"], re:"NFPA 72 18.5.5.7: когда световой оповещатель спального помещения находится в пределах 24 in. от потолка, требуется оповещатель 177 cd для преодоления ослабления слоем дыма."},
  {id:128, q:"Начиная со Стандартов ADA 2010 года, видимые оповещатели пожарной сигнализации должны устанавливаться в соответствии с:", opts:["Только ICC A117.1","Только предпочтением изготовителя","Только местным пожарным кодексом","NFPA 72"], re:"Стандарты ADA 2010 (и ICC A117.1) ссылаются на NFPA 72 для размещения и канделы видимых оповещателей, согласуя правила доступности и пожарной сигнализации."},
  {id:129, q:"Видимые оповещатели требуются в основном для оповещения каких людей?", opts:["Глухих или слабослышащих людей","Только спящих людей","Только обслуживающего персонала","Пешеходов на улице"], re:"NFPA 72 / ADA: световые оповещатели обеспечивают оповещение глухих или слабослышащих людей, что является требованием доступности в занимаемых пространствах."},
  {id:130, q:"Таблицы покрытия световых оповещателей в NFPA 72 основаны на какой геометрии помещения?", opts:["Круглые помещения","Квадратные помещения","Г-образные помещения","Треугольные помещения"], re:"NFPA 72 18.5.5.4: таблицы расстановки для помещений предполагают квадратные помещения; неквадратные помещения разбиваются на квадраты для покрытия."},
  {id:131, q:"Для помещения 50 ft × 50 ft какая минимальная кандела требуется при использовании одного настенного светового оповещателя?", opts:["60 cd","75 cd","95 cd","135 cd"], re:"NFPA 72 Таблица 18.5.5.4.1(a): один настенный световой оповещатель, покрывающий помещение 50×50 ft, требует 95 cd."},
  {id:132, q:"Стандартный (не расширенного покрытия) световой оповещатель с сертификацией UL обычно НЕ выпускается с какой характеристикой в канделах?", opts:["15 cd","75 cd","110 cd","185 cd"], re:"Стандартные световые оповещатели сертифицируются на 15/30/75/95/110 cd; 177 и 185 cd — это характеристики расширенного покрытия, а не значения стандартного покрытия."},
  {id:133, q:"Если для достижения требуемого покрытия помещению нужно более двух настенных световых оповещателей, NFPA 72 требует, чтобы оповещатели были:", opts:["Синхронизированы","Разных цветов","Установлены только на потолке","С характеристикой 15 cd"], re:"NFPA 72 18.5.5.4.6: когда в любом поле зрения находится более двух видимых оповещателей, они должны мигать синхронно для ограничения риска приступа."},
  {id:134, q:"Видимые оповещатели должны создавать вспышки, которые являются прозрачными или какого цвета?", opts:["Красного","Белого","Синего","Янтарного"], re:"NFPA 72 18.5.4: видимые оповещатели пожарной сигнализации должны быть прозрачными или номинально белыми; другие цвета (например, янтарный/синий) зарезервированы для непожарного оповещения, такого как MNS."},
  {id:135, q:"Цепь оповещения класса B контролируется на целостность посредством:", opts:["Резервного обратного пути к панели","Только детектора замыкания на землю","Оконечного резистора (EOLR)","Второй панели управления"], re:"NFPA 72 12.3 / Приложение: цепь оповещения (NAC) класса B оканчивается оконечным резистором, так что низкий контрольный ток обнаруживает обрывы; единичный обрыв отключает устройства, расположенные далее по цепи."},
  {id:136, q:"Ключевое преимущество цепи оповещения класса A перед классом B состоит в том, что она:", opts:["Использует меньше проводников","Устраняет потребность в питании","Не требует контроля","Продолжает работу оповещателей после единичного обрыва (разрыва провода)"], re:"NFPA 72 12.3: цепь класса A обеспечивает резервный обратный путь, поэтому единичный обрыв не препятствует работе оповещателей; класс B теряет всё, что находится далее по цепи от обрыва."},
  {id:137, q:"Сколько проводников (путей) использует цепь оповещения класса A?", opts:["4","2","1","6"], re:"NFPA 72 12.3: класс A использует 4 провода (исходящую пару плюс резервную обратную пару), так что цепь контролируется на целостность и переживает единичный обрыв."},
  {id:138, q:"Цепи оповещения контролируются так, что единичный обрыв или замыкание на землю приводит к чему?", opts:["Тихому отказу","Сигналу неисправности на устройстве управления","Автоматической тревоге","Немедленной эвакуации"], re:"NFPA 72 10.17 / 12.3: неисправности на контролируемых цепях формируют сигнал неисправности в установленное время, чтобы повреждение было известно и устранено."},
  {id:139, q:"Большинство современных поляризованных оповещателей подключаются к цепи оповещения с помощью:", opts:["Неполяризованной проводки переменного тока","Трёхфазного питания","Поляризованной проводки постоянного тока с правильной полярностью","Коаксиального кабеля"], re:"Практика NFPA 72: обычные гудки/световые оповещатели являются поляризованными устройствами постоянного тока; правильная полярность требуется для активации оповещателей и для работы контроля."},
  {id:140, q:"Какова цель проведения расчёта падения напряжения на цепи оповещения?", opts:["Установить задержку подтверждения тревоги","Рассчитать шаг дымовых извещателей","Выбрать цвет светового оповещателя","Обеспечить, чтобы последний оповещатель получал как минимум своё минимальное номинальное рабочее напряжение"], re:"NFPA 72 / практика проектирования: расчёты падения напряжения подтверждают, что оконечный оповещатель всё ещё получает как минимум своё минимальное напряжение по сертификации UL, чтобы он работал и оставался в синхронизации."},
  {id:141, q:"Если напряжение на последнем световом оповещателе цепи падает ниже минимального сертифицированного значения оповещателя, наиболее вероятный результат:", opts:["Оповещатель может не сработать или потерять синхронизацию","Световой оповещатель мигает ярче","Панель перезагружается","Уровень фонового шума повышается"], re:"Практика проектирования по NFPA 72: недостаточное напряжение на оповещателе может предотвратить активацию или вызвать рассинхронизацию световых оповещателей."},
  {id:142, q:"Усилитель питания (бустер) цепи оповещения используется в основном для того, чтобы:", opts:["Преобразовывать переменный ток в газ","Обеспечить дополнительное стабилизированное питание и резервную батарею для большего числа оповещателей","Заменить устройство управления пожарной сигнализацией","Устранить необходимость в оконечном контроле"], re:"NFPA 72: сертифицированный усилитель питания цепи оповещения подаёт дополнительное контролируемое питание с резервом от батареи, чтобы большие нагрузки оповещателей превышали ёмкость цепи оповещения основной панели."},
  {id:143, q:"Цепи оповещения должны электрически контролироваться, чтобы обнаруживались неисправности. Это требуется по:", opts:["Только Статье 90 NEC","ASHRAE 90.1","NFPA 72 (контроль целостности)","Только ADA"], re:"NFPA 72 10.17 / 12.3: пути, обслуживающие оповещатели, должны контролироваться на целостность, если только это специально не освобождено."},
  {id:144, q:"Что описывает различие цепи 'пуска' и 'оповещения', значимое для проектирования цепи оповещения?", opts:["Обе идентичны","Цепи оповещения не могут контролироваться","Цепь оповещения всегда управляет клапанами спринклеров","Цепь оповещения управляет звуковыми/видимыми оповещателями, а не пуском средств пожаротушения"], re:"NFPA 72: цепи оповещения управляют гудками/световыми оповещателями/громкоговорителями; функции пуска используют отдельные сертифицированные пусковые цепи с собственными требованиями."},
  {id:145, q:"Когда оповещатели добавляются к существующей цепи оповещения, проектировщик должен заново проверить какие две вещи?", opts:["Потребляемый ток (ёмкость панели) и оконечное падение напряжения","Цвет краски и размер этикетки","Температуру и влажность в помещении","Чувствительность дымовых извещателей"], re:"Практика проектирования NFPA 72: добавленные оповещатели увеличивают токовую нагрузку, поэтому необходимо заново проверить как общий ток относительно номинала цепи, так и оконечное напряжение."},
  {id:146, q:"Цепь оповещения класса B отличается от класса A тем, что единичный разрыв провода на классе B:", opts:["Не имеет эффекта","Отключает все оповещатели, подключённые после разрыва","Увеличивает выход оповещателя","Запускает общую тревогу"], re:"NFPA 72 12.3: на классе B устройства далее по цепи от обрыва теряются, поскольку нет резервного обратного пути; только оконечный контроль сообщает о неисправности."},
  {id:147, q:"Оповещатели в цепи, которые должны мигать вместе, обычно требуют какой функции от панели или модуля синхронизации?", opts:["Генератора случайных вспышек","Более высокой температуры окружающей среды","Сигнала/протокола синхронизации","Янтарной линзы"], re:"NFPA 72 18.5.5.4.6: модуль синхронизации или совместимая панель обеспечивает сигнал синхронизации, чтобы все световые оповещатели в поле зрения мигали вместе."},
  {id:148, q:"Максимальный ток, который может нести цепь оповещения, ограничивается в основном:", opts:["Цветом линзы светового оповещателя","Уровнем фонового шума","Числом ручных извещателей","Номиналом цепи панели/бустера и токонесущей способностью/падением напряжения проводника"], re:"Проектирование NFPA 72: нагрузка цепи оповещения ограничивается номинальным выходным током источника и падением напряжения проводника, обеспечивая, чтобы все оповещатели оставались в пределах сертифицированного напряжения."},
  {id:149, q:"Какая практика выбора проводников помогает минимизировать падение напряжения на длинном участке цепи оповещения?", opts:["Использовать провод большего сечения (с меньшим сопротивлением)","Использовать провод меньшего сечения","Увеличить число сросток","Добавить больше оконечных резисторов"], re:"Базовое проектирование цепей по NFPA 72: проводники большего сечения имеют меньшее сопротивление, снижая падение напряжения, чтобы оконечные оповещатели получали достаточное напряжение."},
  {id:150, q:"Почему нагрузки цепи оповещения от световых оповещателей должны рассчитываться с использованием тока наихудшего случая (пускового/пикового) оповещателя?", opts:["Световые оповещатели никогда не потребляют ток","Световые оповещатели потребляют кратковременный высокий пик при каждой вспышке, который источник должен поддерживать","Только гудки потребляют ток","Ток не имеет значения для световых оповещателей"], re:"Практика проектирования: световые оповещатели потребляют кратковременный высокий пиковый ток при каждой вспышке; источник цепи оповещения должен поддерживать этот пик, чтобы сохранялись выход и синхронизация."},
  {id:151, q:"'T-отвод' (параллельная ветвь), как правило, НЕ допускается на какой класс цепи без потери её класса?", opts:["Класс B","Любая низковольтная цепь","Класс A (нарушил бы резервный контур)","Только с ограниченной мощностью"], re:"NFPA 72 12.3: класс A требует непрерывного контура с возвратом к панели; T-отвод сводит на нет резервный обратный путь и преимущество целостности класса A."},
  {id:152, q:"Системы экстренной связи рассматриваются в какой главе NFPA 72?", opts:["Глава 14","Глава 18","Глава 29","Глава 24"], re:"NFPA 72 глава 24 охватывает Системы экстренной связи (ECS), включая внутрисистемное речевое оповещение о пожаре в зданиях и системы массового оповещения (MNS)."},
  {id:153, q:"Каков средний индекс передачи речи (STI), который должен быть достигнут в каждом акустически различимом пространстве (ADS) для разборчивой ECS?", opts:["0.50","0.45","0.35","0.70"], re:"NFPA 72 глава 24 / Приложение D: средний STI в каждом ADS должен быть не менее 0.50, при этом не менее 90 % точек на уровне 0.45 или выше."},
  {id:154, q:"Не менее 90 % точек измерения в пределах ADS должны достигать STI не менее:", opts:["0.35","0.45","0.55","0.65"], re:"NFPA 72 Приложение D: 90 % измеренных точек в каждом ADS должны достигать STI ≥ 0.45 (≈0.65 CIS), при среднем по площади ≥ 0.50."},
  {id:155, q:"'Акустически различимое пространство' (ADS) — это пространство, отличаемое по его:", opts:["Окраске и освещению","Только числу выходов","Акустическим, средовым или эксплуатационным характеристикам (например, реверберация, фоновый уровень)","Цвету потолка"], re:"NFPA 72 3.3 / 24: ADS — это зона, отличаемая от других по акустическим, средовым или эксплуатационным характеристикам, таким как время реверберации и фоновое звуковое давление."},
  {id:156, q:"В комбинированной системе пожарной сигнализации / массового оповещения NFPA 72 разрешает какому сообщению иметь приоритет там, где этого требует анализ рисков?", opts:["Всегда сигналу пожарной сигнализации","Сигналу управления HVAC","Никакому; они не могут сосуществовать","Сообщению массового оповещения (MNS)"], re:"NFPA 72 глава 24: хотя исторически пожар имел наивысший приоритет, анализ рисков может отдать приоритет MNS над пожарной сигнализацией (например, при сценариях активной угрозы)."},
  {id:157, q:"Сообщение живым голосом, транслируемое через систему речевого оповещения, должно быть способно перекрывать что?", opts:["Автоматическое (предварительно записанное) сообщение об эвакуации","Водоснабжение здания","Спринклерную систему","Только возврат лифта"], re:"NFPA 72 24.4: надлежащим образом авторизованное объявление живым голосом должно иметь возможность перекрывать автоматическое предварительно записанное сообщение для выдачи указаний в реальном времени."},
  {id:158, q:"Для внутриобъектовой MNS требуемый уровень живучести линий определяется:", opts:["Канделой светового оповещателя","Анализом рисков","Температурой окружающей среды","Числом ручных извещателей"], re:"NFPA 72 24.5: живучесть линий для внутриобъектового массового оповещения устанавливается документированным анализом рисков, а не фиксированным уровнем."},
  {id:159, q:"Массовое оповещение распределённых получателей (например, оповещения по SMS/электронной почте) по NFPA 72:", opts:["Может заменять требуемое звуковое/видимое оповещение","Полностью запрещено","Не должно использоваться вместо требуемого звукового и видимого оповещения","Не требует интеграции"], re:"NFPA 72 24.7: MNS распределённых получателей дополняет, но не должна заменять требуемое внутриобъектовое звуковое и видимое оповещение."},
  {id:160, q:"Количественное измерение STI по NFPA 72 является:", opts:["Всегда обязательным в каждой точке","Требуемым только для жилых сигнализаций","Запрещённым","Необязательным; прослушивательная проверка может быть допустима, но при измерении применяются критерии"], re:"NFPA 72 Приложение D: разборчивость может проверяться квалифицированной прослушивательной проверкой; если измеряется количественный STI/CIS, применяются критерии 0.45/0.50."},
  {id:161, q:"Главная причина использования систем речевого оповещения вместо только гудков в высотных зданиях — это:", opts:["Обеспечить разборчивые указания для поэтапной эвакуации/перемещения","Сократить проводку","Снизить уровень фонового шума","Избежать световых оповещателей"], re:"NFPA 72 24.4 / IBC: речевое оповещение обеспечивает поэтапную эвакуацию и перемещение с чёткими устными указаниями, которые один тон передать не может."},
  {id:162, q:"Перед речевым тоновым сигналом (предупреждение/тревога) в ECS NFPA 72 обычно использует что для привлечения внимания?", opts:["Только тихую паузу","Предварительный сигнал предупреждения/привлечения внимания (например, тон) перед речевым сообщением","Только смену цвета светового оповещателя","Срабатывание спринклера"], re:"NFPA 72 24.4: предупреждающий тон обычно предшествует речевому сообщению, чтобы привлечь внимание перед выдачей указаний."},
  {id:163, q:"Громкоговорители в речевой системе обычно выбираются по настройке мощностного 'отвода' (например, 1/4, 1/2, 1, 2 W) для управления:", opts:["Канделой светового оповещателя","Значением оконечного резистора","Акустическим выходом (уровнем звука) для пространства","Химией батареи"], re:"NFPA 72 / проектирование: настройки отвода громкоговорителя задают мощность и, следовательно, звуковой выход, позволяя настраивать слышимость и разборчивость для каждого пространства."},
  {id:164, q:"Системы массового оповещения большой площади (например, наружный 'гигантский голос') по главе 24 NFPA 72 предназначены в основном для того, чтобы:", opts:["Обеспечивать только видимые сигналы","Заменять внутренние дымовые извещатели","Управлять лифтами","Оповещать людей на улице на больших площадях"], re:"NFPA 72 24.6: MNS большой площади (мощные массивы громкоговорителей / гигантский голос) доставляют разборчивые сообщения на больших наружных территориях кампусов."},
  {id:165, q:"В ECS наивысший приоритет, как правило, назначается на основе:", opts:["Относительного риска для жизни, установленного проектом/анализом рисков системы","Того, какое устройство сработало первым","Алфавитного порядка сообщений","Наименьшего потребляемого тока"], re:"NFPA 72 глава 24: приоритет сообщения устанавливается по риску для жизни согласно проекту/анализу рисков, чтобы транслировалось наиболее критичное указание."},
  {id:166, q:"Автономное устройство управления (ACU) в системе массового оповещения функционирует как:", opts:["Линза светового оповещателя","Точка управления, которая контролирует и управляет MNS","Оконечный резистор","Только ручной извещатель"], re:"NFPA 72 24.3: ACU является основной точкой управления и контроля системы массового оповещения, часто сопрягаемой с системой пожарной сигнализации."},
  {id:167, q:"Разборчивость речи наиболее ухудшается в пространствах с:", opts:["Низкой реверберацией и низким фоновым шумом","Без людей","Высоким временем реверберации и высоким фоновым шумом","Только коврами на полу"], re:"NFPA 72 Приложение D: длительное время реверберации и высокий фоновый шум снижают STI, делая такие пространства труднее сделать разборчивыми."},
  {id:168, q:"Какой раздел какого документа содержит методологию и руководство по разборчивости ECS?", opts:["Только ICC A117.1","NEC глава 9","OSHA 1926","NFPA 72 Приложение D"], re:"NFPA 72 Приложение D содержит справочную методологию для оценки и проектирования разборчивости речи в ECS."},
  {id:169, q:"Какова максимально допустимая частота вспышки светового оповещателя по NFPA 72?", opts:["2 Hz (120 fpm)","1 Hz (60 fpm)","3 Hz (180 fpm)","5 Hz (300 fpm)"], re:"NFPA 72 18.5.4.4: видимые оповещатели должны мигать с максимумом 2 Hz (120 вспышек/мин) для снижения риска светочувствительного приступа."},
  {id:170, q:"Какова минимальная частота вспышки, требуемая для светового оповещателя пожарной сигнализации по NFPA 72?", opts:["0.5 Hz","1 Hz","2 Hz","4 Hz"], re:"NFPA 72 18.5.4.4: минимальная частота вспышки составляет 1 Hz (60 вспышек/мин) для обеспечения адекватного видимого оповещения."},
  {id:171, q:"Синхронизация световых оповещателей требуется главным образом для предотвращения:", opts:["Избыточного потребления тока","Звуковой обратной связи","Светочувствительных эпилептических приступов от суммарных частот вспышек в поле зрения","Отказа оконечного резистора"], re:"NFPA 72 18.5.5.4.6 / Приложение: синхронизация световых оповещателей удерживает суммарную частоту вспышек в поле зрения на уровне частоты двух оповещателей или ниже, ограничивая риск приступа."},
  {id:172, q:"Синхронизация требуется, когда сколько видимых оповещателей находится в поле зрения человека?", opts:["Любое число, всегда 1","Более 5","Ровно 1","Более 2"], re:"NFPA 72 18.5.5.4.6: там, где в любом поле зрения находится более двух видимых оповещателей, они должны мигать синхронно."},
  {id:173, q:"Уровни живучести линий в NFPA 72 определяются преимущественно в какой главе?", opts:["Глава 12","Глава 10","Глава 18","Глава 23"], re:"NFPA 72 глава 12 (Цепи и пути) определяет уровни живучести линий 0-3 (Уровень 4 добавлен в 2022)."},
  {id:174, q:"Для внутриобъектовых систем речевого оповещения о пожаре, обслуживающих перемещение или частичную эвакуацию, какой минимальный уровень живучести линий требуется?", opts:["Уровень 0","Уровень 2 (или 3)","Уровень 1","Живучесть не нужна"], re:"NFPA 72 24.3.6 / 12.4: системы, использующие перемещение или частичную эвакуацию, требуют живучести линий Уровня 2 или Уровня 3."},
  {id:175, q:"Уровни 2 и 3 живучести линий, как правило, требуют:", opts:["Никакой особой проводки","Только пластикового короба","Кабеля или оболочки с огнестойкостью 2 часа","Только алюминиевого провода"], re:"NFPA 72 12.4: живучесть Уровня 2 и Уровня 3 требует кабеля или оболочки целостности цепи с огнестойкостью 2 часа; Уровень 3 также требует здания, полностью оснащённого спринклерами."},
  {id:176, q:"Какое дополнительное условие здания требует живучесть линий Уровня 3 сверх Уровня 2?", opts:["Только сухотруб (standpipe)","Янтарные световые оповещатели","Две панели управления","Здание, полностью оснащённое спринклерами"], re:"NFPA 72 12.4: живучесть Уровня 3 требует защиты с огнестойкостью 2 часа И здания, полностью защищённого автоматическими спринклерами."},
  {id:177, q:"Живучесть линий Уровня 4, добавленная в издании 2022 года, требует как минимум:", opts:["Кабеля или оболочки с огнестойкостью 1 час","Никакой защиты","Только металлического канала","Подземной прокладки"], re:"NFPA 72 (2022) 12.4: был добавлен Уровень 4, требующий кабелей или оболочек с огнестойкостью 1 час (вариант, отличный от 2-часовых Уровней 2/3)."},
  {id:178, q:"Кабель целостности цепи (CI) используется в системах пожарной сигнализации специально для обеспечения:", opts:["Меньшей стоимости монтажа","Продолжения работы во время пожара в течение нормированного времени","Большей скорости данных","Только цветовой маркировки"], re:"NFPA 72 12.4: кабель CI / огнестойкий кабель сохраняет работу цепи в течение сертифицированной длительности (например, 2 часа) при воздействии огня, обеспечивая живучесть."},
  {id:179, q:"Чтобы оставаться в синхронизации, световые оповещатели в цепи, как правило, должны быть:", opts:["Из любой смеси изготовителей","Только разной канделы","Совместимы/сертифицированы для синхронизации (часто одного изготовителя/протокола)","Подключены с обратной полярностью"], re:"NFPA 72 / сертификация: световые оповещатели должны использовать совместимый протокол синхронизации (обычно синхронизация одного изготовителя), чтобы надёжно мигать вместе."},
  {id:180, q:"Там, где несколько световых оповещателей видны на пересечении Г-образного коридора, синхронизация решает вопрос:", opts:["Сокращения срока службы батареи","Заполнения канала","Звуковой интерференции","Суммарной (составной) частоты вспышек, видимой наблюдателем"], re:"NFPA 72 Приложение: человек на пересечении коридоров может видеть несколько световых оповещателей; синхронизация удерживает суммарную частоту вспышек на уровне частоты двух оповещателей или ниже для ограничения риска приступа."},
  {id:181, q:"Живучесть линий Уровня 1 обычно допускает стандартный огнестойкий провод, когда он установлен в полностью оснащённом спринклерами здании и проложен в:", opts:["Металлическом канале или кабеле с металлической бронёй","На открытом воздухе","Только в ПВХ","Вообще без канала"], re:"NFPA 72 12.4: Уровень 1 допускает обычный огнестойкий кабель в оснащённом спринклерами здании, когда он установлен в металлическом канале (трубе) или кабеле с металлической бронёй."},
  {id:182, q:"Требования к живучести линий существуют, чтобы обеспечить, что во время пожара цепи оповещения:", opts:["Используют меньше энергии","Продолжают работать достаточно долго, чтобы оповестить и переместить людей","Мигают другим цветом","Снижают звуковой выход"], re:"NFPA 72 12.4 замысел: живучесть сохраняет линии сигнализации работоспособными при воздействии огня, чтобы людей можно было оповестить и переместить в безопасное место."},
  {id:183, q:"Световые оповещатели, выходящие из синхронизации из-за низкого напряжения, создают какую опасность, которую NFPA 72 стремится избежать?", opts:["Избыточную слышимость","Искажение цвета","Недопустимую суммарную частоту вспышек, которая может спровоцировать приступы","Замыкания на землю"], re:"NFPA 72 18.5.5.4.6 / Приложение: потеря синхронизации повышает воспринимаемую суммарную частоту вспышек в поле зрения — то самое условие, которое синхронизация призвана предотвратить."},
  {id:184, q:"Что верно об Уровне 0 живучести линий?", opts:["Он обеспечивает 2-часовую защиту","Он предписывает только класс A","Он требует спринклеров и 1-часового кабеля","Он не обеспечивает конкретной живучести (никакой дополнительной огнезащиты линии)"], re:"NFPA 72 12.4: Уровень 0 означает, что живучесть линии не обеспечивается; более высокие уровни добавляют возрастающую огнезащиту цепи."},
  {id:185, q:"Стандартный звуковой сигнал эвакуации, требуемый NFPA 72, известен как:", opts:["ANSI/Временной код 3 (T-3)","Временной код 4 (T-4)","Маршевый ритм","Непрерывный тон"], re:"NFPA 72 18.4.2: стандартным сигналом эвакуации является временной код 3 (T-3) по ANSI S3.41."},
  {id:186, q:"Временной код 3 состоит из трёх импульсов, каждый 'включён' примерно на:", opts:["0.25 s","0.5 s","1.0 s","1.5 s"], re:"NFPA 72 18.4.2 / ANSI S3.41: T-3 — это три импульса 'включено' по 0.5 s, разделённые паузами 'выключено' по 0.5 s, затем пауза 1.5 s, с повторением."},
  {id:187, q:"После трёх импульсов временной код 3 включает время выключения (паузу) примерно:", opts:["0.5 s","1.0 s","1.5 s","3.0 s"], re:"NFPA 72 / ANSI S3.41: цикл T-3 завершается периодом 'выключено' 1.5 s перед началом следующего набора из трёх импульсов."},
  {id:188, q:"Один полный цикл временного кода 3 (3 импульса включения/выключения плюс длинная пауза) длится примерно:", opts:["2 секунды","8 секунд","6 секунд","4 секунды"], re:"NFPA 72 / ANSI S3.41: три включения по 0.5 s + три выключения по 0.5 s (≈3 s, при этом последнее выключение — пауза 1.5 s) даёт полный цикл около 4 секунд."},
  {id:189, q:"Для сигнала полной эвакуации временной код 3 должен звучать непрерывно как минимум:", opts:["180 секунд (3 минуты)","60 секунд","30 секунд","10 минут"], re:"NFPA 72 / ANSI S3.41: сигнал эвакуации T-3 должен быть способен звучать не менее 180 секунд, когда предполагается полная эвакуация."},
  {id:190, q:"Оповещение публичного режима предназначено для оповещения:", opts:["Только обученного персонала","Общих посетителей здания","Только станции мониторинга","Только обслуживающего персонала"], re:"NFPA 72 3.3 / 18.4: оповещение публичного режима уведомляет общих посетителей и имеет более высокие требования к уровню звука, чем частный режим."},
  {id:191, q:"Оповещение частного режима предназначено для:", opts:["Широкой публики","Пешеходов на улице","Лиц, непосредственно связанных с реализацией/реагированием (например, обученного персонала)","Только спящих гостей"], re:"NFPA 72 3.3: оповещение частного режима уведомляет только лиц, связанных с работой/реагированием системы, и допускает более низкие уровни звука (10 dBA выше фонового)."},
  {id:192, q:"Когда целью является полная эвакуация здания, какой сигнал имеет преимущество над другими тонами?", opts:["Непрерывный звонок","Одиночный колокольчик","Кодированный сигнал маршевого ритма","Эвакуационный временной код 3"], re:"NFPA 72 18.4.2: временной код 3 является характерным сигналом эвакуации и имеет преимущество, когда предполагается полная эвакуация."},
  {id:193, q:"Какой паттерн специально зарезервирован ANSI/NFPA так, чтобы он НЕ использовался для рутинного, неэвакуационного оповещения?", opts:["Временной код 3 (T-3)","Непрерывный тон","Одиночный короткий гудок","Медленное включение/выключение на 0.1 Hz"], re:"NFPA 72 / ANSI S3.41: временной код 3 зарезервирован как стандартный сигнал эвакуации, чтобы люди надёжно распознавали 'эвакуироваться немедленно'."},
  {id:194, q:"NFPA 72 назначает сигнал тревоги по угарному газу как временной код 4 (T-4), чтобы:", opts:["Точно совпадать с пожарным сигналом","Отличать тревоги CO от сигнала пожарной эвакуации (T-3)","Указывать на неисправность контроля","Сигнализировать об окончании проверки"], re:"NFPA 72 / наследие NFPA 720: тревоги CO используют отдельный временной код 4 (T-4), чтобы люди не путали тревогу CO с пожарным эвакуационным сигналом T-3."},
  {id:195, q:"Сообщение речевого оповещения, предписывающее людям конкретных этажей переместиться вместо полной эвакуации, поддерживает какую стратегию?", opts:["Тихая тревога","Только немедленная полная эвакуация","Защита на месте / поэтапная (с перемещением) эвакуация","Без оповещения"], re:"NFPA 72 24.4 / IBC: речевое оповещение обеспечивает стратегии поэтапной эвакуации/перемещения, перемещая только затронутых людей, пока другие укрываются, что распространено в высотных зданиях и здравоохранении."},
  {id:196, q:"В объектах со спальными зонами оповещение людей должно дополнительно удовлетворять какому особому требованию?", opts:["Более тихий звук, чем в публичном режиме","Оповещение не требуется","Только световые оповещатели, без звука","75 dBA у подушки и низкочастотный сигнал"], re:"NFPA 72 18.4.5: спальные зоны требуют не менее 75 dBA у подушки и низкочастотного сигнала 520 Hz для эффективного пробуждения."},
  {id:197, q:"Цель использования единого узнаваемого сигнала эвакуации (T-3) по всей стране состоит в том, чтобы:", opts:["Обеспечить, чтобы люди повсеместно распознавали значение 'эвакуироваться'","Снизить стоимость оповещателей","Ограничить канделу световых оповещателей","Заменить речевые системы"], re:"NFPA 72 / замысел ANSI S3.41: стандартизированный паттерн T-3 создаёт повсеместное распознавание, чтобы люди реагировали правильно независимо от здания."},
  {id:198, q:"Оповещатели для людей должны устанавливаться так, чтобы сигнал был:", opts:["Слышимым/видимым только в коридорах","Слышимым (и видимым, где требуется) по всем зонам, требующим оповещения","Ограничен вестибюлем","Активен только ночью"], re:"NFPA 72 18.4 / 18.5: оповещение должно достигать всех зон, которые требуется оповестить, удовлетворяя критериям уровня звука и видимого покрытия по всем этим зонам."},
  {id:199, q:"Что лучше всего описывает, когда оповещение частного режима (более низкие уровни) допустимо вместо публичного режима?", opts:["Всегда, в любом здании","Только в односемейных домах","Только там, где это разрешают AHJ/нормы и реагирует обученный персонал (например, отдельные объекты здравоохранения)","Никогда"], re:"NFPA 72 18.4.4: частный режим допускается там, где это разрешают нормы/AHJ и персонал отвечает за реагирование людей, например в некоторых отделениях здравоохранения."},
  {id:200, q:"Во время реальной чрезвычайной ситуации авторизованное объявление живым голосом в ECS ценно тем, что оно может:", opts:["Снизить температуру здания","Автоматически увеличить канделу световых оповещателей","Отключить спринклеры","Дать указания в реальном времени, специфичные для ситуации, перекрывая предварительно записанное сообщение"], re:"NFPA 72 24.4: сообщение живым голосом даёт актуальные, конкретные указания и спроектировано так, чтобы перекрывать автоматическое предварительно записанное эвакуационное сообщение."},
  {id:201, q:"В терминологии NFPA 72, какова основная роль контрольной панели пожарной сигнализации (FACU/FACP)?", opts:["Она контролирует входные сигналы извещателей и управляет выходами системы (оповещение и сигнализация)","Она служит только в качестве звукового оповещателя здания","Это приёмник за пределами объекта, расположенный на центральной станции мониторинга","Это ручной извещатель, который используется для начала эвакуации"], re:"NFPA 72 гл. 10/23: контрольная панель пожарной сигнализации — это компонент, который контролирует входы (извещательные устройства/линии) и управляет выходами, такими как оповещение и сигнализация за пределы объекта, — «мозг» системы."},
  {id:202, q:"NFPA 72 требует, чтобы вторичный (резервный) источник питания типовой контрольной панели пожарной сигнализации поддерживал систему в дежурном режиме как минимум в течение какого времени?", opts:["4 часа","12 часов","24 часа","72 часа"], re:"NFPA 72 §10.6 требует, чтобы вторичное питание обеспечивало работу системы в течение 24 часов дежурного режима с последующим требуемым периодом тревоги."},
  {id:203, q:"После 24 часов дежурного режима на вторичном питании базовая (без речевого оповещения) система пожарной сигнализации должна затем обеспечивать полную тревогу как минимум в течение:", opts:["5 минут","10 минут","15 минут","60 минут"], re:"NFPA 72 §10.6: после 24 ч дежурного режима базовая система пожарной сигнализации должна подавать тревогу в течение 5 минут; системы речевого/тревожного оповещения при эвакуации (EVACS) требуют 15 минут."},
  {id:204, q:"Для внутренней системы речевого/тревожного оповещения при эвакуации (EVACS) период работы тревоги на вторичном питании после 24 ч дежурного режима составляет:", opts:["15 минут","5 минут","30 минут","2 часа"], re:"NFPA 72 §10.6: системы речевого/тревожного оповещения требуют 15 минут работы тревоги (против 5 минут для базовых систем) после 24-часового дежурного периода."},
  {id:205, q:"Наиболее распространённым типом аккумулятора, используемым в качестве вторичного источника питания внутри контрольной панели пожарной сигнализации, является:", opts:["Залитая никель-кадмиевая (NiCd) ячейка","Литий-ионная пакетная ячейка","Свинцово-кислотный аккумулятор с регулирующим клапаном (VRLA)","Щелочная первичная ячейка"], re:"Руководство NFPA 72 по источникам питания: герметичные свинцово-кислотные аккумуляторы с регулирующим клапаном (VRLA) являются преобладающим вторичным источником питания, размещаемым внутри или рядом с FACU."},
  {id:206, q:"Какое состояние имеет НАИВЫСШИЙ приоритет в иерархии приоритета сигналов NFPA 72 на контрольной панели пожарной сигнализации?", opts:["Неисправность","Контрольное (надзорное)","Пожарная тревога","Предтревога"], re:"Приоритет сигналов NFPA 72 гл. 10: сигналы пожарной тревоги имеют приоритет над предтревогой, которая имеет приоритет над контрольным сигналом, который имеет приоритет над неисправностью (тревога CO приоритизируется согласно её собственным положениям)."},
  {id:207, q:"Какая последовательность правильно ранжирует приоритет сигналов на FACU от наивысшего к низшему (пожарные сигналы)?", opts:["Тревога > предтревога > контрольный > неисправность","Неисправность > контрольный > предтревога > тревога","Контрольный > тревога > неисправность > предтревога","Предтревога > неисправность > тревога > контрольный"], re:"NFPA 72 гл. 10: тревога имеет приоритет над предтревогой, предтревога над контрольным сигналом, а контрольный сигнал над неисправностью."},
  {id:208, q:"Закрытый запорный (задвижка) клапан спринклерной системы, контролируемый датчиком вскрытия, выдаёт какой тип сигнала на FACU?", opts:["Контрольный (надзорный) сигнал","Сигнал тревоги","Сигнал неисправности","Сигнал предтревоги"], re:"NFPA 72 гл. 10/17: состояние, требующее действия в контролируемом оборудовании (например, закрытый клапан), является контрольным сигналом, отличным от тревоги или неисправности системы."},
  {id:209, q:"Оборванный провод (обрыв) на извещательной линии вызывает на FACU индикацию:", opts:["Сигнала неисправности","Сигнала тревоги","Контрольного сигнала","Сигнала предтревоги"], re:"NFPA 72 гл. 10/12: неисправность проводки системы (такая как оборванный проводник) является состоянием неисправности, которое должно объявляться как сигнал неисправности."},
  {id:210, q:"NFPA 72 требует, чтобы три основных состояния системы чётко индицировались на контрольной панели. Эти три состояния:", opts:["Тревога, контрольное и неисправность","Дежурный режим, тест и сброс","Первичное, вторичное и третичное","Локальное, удалённое и собственное"], re:"NFPA 72 гл. 10: контрольная панель должна чётко индицировать состояния тревоги, контрольное и неисправности (каждое визуально, а также звуком для тревоги/контрольного/неисправности)."},
  {id:211, q:"Аннунциатор, расположенный в вестибюле здания для использования первыми спасателями, в первую очередь обеспечивает:", opts:["Идентификацию зоны или устройства в тревоге/неисправности для спасателей","Основное питание здания 120 В переменного тока","Зарядку вторичного аккумулятора панели","Канал связи за пределы объекта"], re:"NFPA 72 гл. 10/18: аннунциатор предоставляет информацию о состоянии/местоположении (зона или точка в тревоге, контрольном состоянии или неисправности) для помощи спасателям, отдельно от функций питания или сигнализации."},
  {id:212, q:"Когда основное (сетевое) питание FACU отказывает, NFPA 72 требует, чтобы контрольная панель:", opts:["Автоматически переключилась на вторичный источник питания и индицировала неисправность","Заглушила все индикации до возвращения питания","Отправила немедленную пожарную тревогу в пожарную службу","Отключилась для защиты аккумуляторов"], re:"NFPA 72 §10.6: потеря основного питания должна автоматически переключать нагрузку на вторичное питание, и индицируется неисправность потери питания переменного тока."},
  {id:213, q:"Какова природа цепи основного питания FACU и как она идентифицируется согласно NFPA 72?", opts:["Выделенная ответвлённая цепь, механически защищённая и идентифицированная (например, красная, с маркировкой «ПОЖАРНАЯ СИГНАЛИЗАЦИЯ»)","Цепь, совместно используемая с общим освещением, без маркировки","Любая бытовая розетка в помещении","Цепь с защитой GFCI, совместно используемая с HVAC"], re:"NFPA 72 §10.6: основное питание должно быть выделенной ответвлённой цепью, со средством отключения, доступным только уполномоченному персоналу, механически защищённым и чётко идентифицированным (обычно красным и с маркировкой)."},
  {id:214, q:"Сигнал неисправности на FACU, который был заглушён (подтверждён), должен согласно NFPA 72 сделать что, если состояние неисправности позже восстанавливается, а затем возникает снова?", opts:["Снова прозвучать для каждого нового ненормального состояния (неисправности)","Оставаться заглушённым постоянно","Автоматически преобразоваться в тревогу","Сбросить всю панель"], re:"NFPA 72 гл. 10: звуковое оповещение о неисправности, даже если оно ранее было заглушено, должно снова прозвучать для каждого последующего ненормального состояния, гарантируя, что новые неисправности не будут замаскированы."},
  {id:215, q:"Что из перечисленного НЕ является функцией контрольной панели пожарной сигнализации?", opts:["Контроль исправности своих линий","Активация оповещателей при тревоге","Физическое тушение пожара бортовым агентом","Передача сигналов на центральную станцию мониторинга"], re:"FACU контролирует, надзирает, сигнализирует и управляет выходами; она сама не тушит пожар. Пожаротушение выполняется отдельными системами (спринклеры, газовое тушение), которыми панель может управлять при запуске/контроле."},
  {id:216, q:"NFPA 72 требует, чтобы состояние замыкания на землю, которое могло бы нарушить работу системы пожарной сигнализации, было:", opts:["Индицировано отчётливым сигналом неисправности","Проигнорировано, если не возникнут две неисправности","Зарегистрировано только на центральной станции мониторинга","Устранено автоматически без индикации"], re:"NFPA 72 гл. 10/12: единичное замыкание на землю, влияющее на требуемую работу, должно приводить к индикации сигнала неисправности на контрольной панели."},
  {id:217, q:"Маркировка «внесён в перечень» (listed), требуемая на контрольной панели пожарной сигнализации, означает, что панель:", opts:["Была оценена на соответствие применимому стандарту на продукцию признанной испытательной лабораторией","Принадлежит местной пожарной службе","Была установлена до 1990 года","Работает только на 12 В постоянного тока"], re:"NFPA 72 §10.3 требует, чтобы оборудование было внесено в перечень для своего назначения; внесение в перечень означает, что признанная лаборатория (например, UL) оценила продукт на соответствие применимому стандарту."},
  {id:218, q:"В пороговой (зонной) системе пожарной сигнализации, когда извещатель срабатывает, контрольная панель может идентифицировать:", opts:["Только зону (линию), в которой сработало устройство","Точное устройство, которое сработало, по серийному номеру","Конкретное помещение и тип устройства автоматически","Ничего — пороговые панели не дают местоположения"], re:"Пороговые системы группируют устройства на извещательных линиях (зонах); панель определяет местоположение только до зоны, а не до отдельного устройства. (NFPA 72 гл. 23; отраслевая практика.)"},
  {id:219, q:"В адресной системе пожарной сигнализации каждое извещательное устройство:", opts:["Имеет свой собственный уникальный адрес, сообщаемый контрольной панели","Использует один общий адрес со всеми устройствами на петле","Не может сообщить конкретное местоположение","Должно быть на собственной выделенной двухпроводной линии"], re:"Адресные системы присваивают каждому устройству уникальный адрес на сигнальной линии, так что панель идентифицирует конкретное устройство и его местоположение. (NFPA 72 гл. 23; отраслевая практика.)"},
  {id:220, q:"Тип линии, используемый для подключения пороговых извещательных устройств с изменением состояния (дым/тепло/ручные извещатели) к панели, — это:", opts:["Сигнальная линия (SLC)","Линия оповещателей (NAC)","Извещательная линия (IDC)","Шина передачи данных (DCB)"], re:"NFPA 72 гл. 3/23: извещательная линия (IDC) подключает пороговые извещательные устройства к контрольной панели; панель видит изменение тока, когда устройство срабатывает."},
  {id:221, q:"Линия, которая несёт адресную мультиплексированную связь между панелью и интеллектуальными устройствами, — это:", opts:["Сигнальная линия (SLC)","Извещательная линия (IDC)","Линия оповещателей (NAC)","Цепь основного питания"], re:"NFPA 72 гл. 3: сигнальная линия (SLC) несёт сигнализацию множества входов/выходов между адресными устройствами и контрольной панелью (петля данных)."},
  {id:222, q:"Пороговые извещательные устройства на IDC обычно подключаются так, что в нормальном дежурном режиме их контакты:", opts:["Нормально замкнуты и размыкаются при тревоге","Непрерывно циклически размыкаются и замыкаются","Нормально разомкнуты и замыкаются при тревоге","Отключены до проведения испытаний"], re:"Пороговые пожарные извещательные устройства — это нормально разомкнутые устройства с изменением состояния, замыкающиеся при активации; оконечный резистор (EOL) контролирует линию на обрывы/замыкания. (Отраслевой стандарт; NFPA 72 гл. 17/23.)"},
  {id:223, q:"Ключевое преимущество адресной системы перед пороговой для обслуживания заключается в:", opts:["Ей не нужно вторичное питание","Она устраняет необходимость любого контроля проводки","Более быстрое точное определение устройства в тревоге или неисправности","Она не может генерировать ложные тревоги"], re:"Поскольку каждая точка идентифицируется индивидуально, адресные системы позволяют техникам определять точное устройство в тревоге/неисправности, сокращая время поиска неисправностей. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:224, q:"В пороговой системе, если требуется бо́льшая детализация местоположения устройств, проектировщик обычно:", opts:["Добавляет больше зон (больше IDC)","Присваивает адреса каждому извещателю","Удаляет оконечные резисторы","Преобразует NAC в SLC"], re:"Пороговое разрешение местоположения — позонное, поэтому более точное местоположение требует добавления зон/IDC. Адресация — функция адресных (SLC) систем. (Отраслевая практика.)"},
  {id:225, q:"Какое утверждение об адресных извещателях верно?", opts:["Они сообщают только двоичное состояние тревога/норма, как пороговые устройства","Их нельзя индивидуально отключить на панели","Многие могут сообщать аналоговые данные/чувствительность и данные обслуживания (например, «загрязнён») на панель","Они требуют оконечного резистора на каждом извещателе"], re:"Аналоговые/адресные извещатели обычно сообщают значения чувствительности и состояние обслуживания (например, «загрязнённый датчик»), обеспечивая такие функции, как компенсация дрейфа. (NFPA 72 гл. 17 чувствительность; отраслевая практика.)"},
  {id:226, q:"Линия оповещателей (NAC) в ОБЕИХ системах, пороговой и адресной, используется для:", opts:["Питания и управления сиренами, стробами и другими оповещателями","Передачи данных адресных устройств","Обеспечения основного питания здания","Подключения к центральной станции мониторинга за пределами объекта"], re:"NFPA 72 гл. 3: линия оповещателей (NAC) подключает и питает оповещатели (звуковые/световые). Она существует в обоих типах систем."},
  {id:227, q:"В адресной системе адресный модуль, используемый для подключения порогового устройства или зоны к SLC, обычно называется:", opts:["Оконечный резистор","Предохранитель ограниченной мощности","Модуль мониторинга (входной)","Драйвер аннунциатора"], re:"Модуль мониторинга (входной) размещает пороговый контакт/IDC на адресной сигнальной линии (SLC), присваивая ему адрес. Модули управления (реле/выходные) управляют выходами. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:228, q:"По сравнению с пороговой системой, топология проводки адресной петли SLC чаще всего:", opts:["Требует отдельной пары проводов к каждому отдельному устройству","Не может контролироваться","Использует одну пару, проложенную через все устройства (и опционально обратно к панели)","Должна быть коаксиальным кабелем"], re:"Адресные SLC используют одну пару связи, проложенную через устройства; петли класса Class A возвращаются к панели. Пороговым системам нужна линия на каждую зону. (Отраслевая практика.)"},
  {id:229, q:"Какое утверждение точно описывает пороговую и адресную индикацию одного дымового извещателя?", opts:["Пороговая даёт текст на уровне устройства; адресная даёт только зону","Обе дают идентичную идентификацию на уровне устройства","Адресная может отображать конкретный извещатель/местоположение; пороговая отображает зону","Ни одна не может указать местоположение"], re:"Адресная определяет конкретное устройство/местоположение; пороговая определяет только до зоны. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:230, q:"«Гибридная» панель пожарной сигнализации — это панель, которая:", opts:["Использует только адресные устройства","Не имеет вторичного питания","Поддерживает как пороговые модули IDC/зон, так и адресные петли SLC","Не может контролироваться"], re:"Гибридные панели принимают пороговые зонные карты и адресные карты петли, позволяя проектировщикам смешивать технологии. (Отраслевая практика.)"},
  {id:231, q:"В пороговой системе два отдельных извещателя, подключённые на ОДНОЙ зоне (IDC), которые оба переходят в тревогу:", opts:["Будут индивидуально различены панелью","Взаимно компенсируют друг друга","Оба просто укажут, что эта зона в тревоге","Вызовут неисправность, а не тревогу"], re:"Пороговые зонные линии не могут различить, какое устройство в зоне сработало; панель показывает зону в тревоге. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:232, q:"Какой тип линии обычно ОТСУТСТВУЕТ в чисто пороговой (неадресной) системе?", opts:["Извещательная линия (IDC)","Линия оповещателей (NAC)","Сигнальная линия (SLC)","Цепь основного питания"], re:"SLC несут адресную сигнализацию и характерны для адресных систем; чисто пороговые системы используют IDC и NAC. (Определения NFPA 72 гл. 3.)"},
  {id:233, q:"Преимущество, которое часто называют для пороговых систем по сравнению с адресными:", opts:["Индивидуальная адресация устройств","Сообщение аналоговой чувствительности","Меньшая стоимость и простота для очень малых зданий","Встроенная связь с центральной станцией"], re:"Для очень малых установок пороговые системы могут быть дешевле и проще; преимущества адресации (идентификация точек, аналоговые данные) масштабируются с размером здания. (Отраслевая практика.)"},
  {id:234, q:"В терминах NFPA 72, «адресное устройство» — это устройство, которое:", opts:["Имеет дискретный адрес, распознаваемый индивидуально контрольной панелью","Не может сообщать своё состояние","Всегда является оповещателем","Работает только на NAC"], re:"NFPA 72 гл. 3: адресное устройство имеет дискретную идентификацию (адрес), которая позволяет контрольной панели идентифицировать его индивидуально на сигнальной линии."},
  {id:235, q:"Сигнальная линия (SLC) лучше всего описывается как линия, которая:", opts:["Подаёт основное питание 120 В переменного тока на панель","Подключает только оповещатели","Несёт множество входов и/или выходов адресных устройств к контрольной панели","Никогда не контролируется"], re:"NFPA 72 гл. 3: SLC — это линия/путь между устройствами и контрольной панелью, по которому передаются множество системных входов/выходов, — адресная петля данных."},
  {id:236, q:"На SLC класса Class B единичный обрыв (разрыв) в петле:", opts:["Не окажет влияния ни на одно устройство","Преобразует петлю в класс Class A","Вызовет потерю связи с устройствами за местом обрыва","Вызовет немедленную тревогу по всему зданию"], re:"NFPA 72 гл. 12: линия связи класса Class B не имеет резервного обратного пути, поэтому устройства за единичным обрывом теряются (и объявляется неисправность)."},
  {id:237, q:"На SLC класса Class A единичный обрыв в петле приводит к:", opts:["Потере всех устройств на петле","Постоянному состоянию тревоги","Продолжению связи со всеми устройствами через резервный обратный путь","Отсутствию индикации неисправности"], re:"NFPA 72 гл. 12: Class A обеспечивает резервный обратный путь; при единичном обрыве панель питает оба конца, сохраняя связь со всеми устройствами при объявлении неисправности."},
  {id:238, q:"Устройство, устанавливаемое на петле SLC, которое размыкает линию с любой стороны от себя при обнаружении замыкания, чтобы защитить остальную часть петли, — это:", opts:["Оконечный резистор","Модуль управления/реле","Модуль-изолятор короткого замыкания (изоляции)","Реле контроля питания"], re:"Модули-изоляторы короткого замыкания сегментируют SLC: при замыкании они размыкаются, чтобы изолировать неисправный сегмент, так что остальные устройства продолжают работать. (NFPA 72 гл. 12 изоляция неисправностей; отраслевая практика.)"},
  {id:239, q:"Согласно изданиям NFPA 72 2016 года и более поздним, единичная неисправность на SLC, обслуживающей адресные устройства, не должна вызывать потерю устройств более чем в:", opts:["Целом здании","50 зданиях","Одной зоне адресных устройств","Трёх этажах"], re:"NFPA 72 (2016+) пересмотрел прежнее правило «50 устройств», потребовав, чтобы единичная неисправность SLC не выводила из строя более одной зоны оповещения/зоны адресных устройств; для выполнения используются изоляторы."},
  {id:240, q:"Адресные устройства чаще всего устанавливают свой адрес посредством:", opts:["Только физического цвета своего провода","Центральной станции мониторинга","Длины кабеля от панели","Установки DIP-/поворотного переключателя или электронной (программной) адресации"], re:"Адреса устанавливаются DIP-/поворотными переключателями или назначаются электронно панелью (программно/автоадресация), в зависимости от производителя. (Отраслевая практика.)"},
  {id:241, q:"Если два адресных устройства на одной SLC случайно установлены на ОДИН И ТОТ ЖЕ адрес, типичный результат:", opts:["Оба работают идеально","Панель тихо перенумеровывает их","Автоматическая тревога","Неисправность (конфликт адресов) или одно устройство не сообщает"], re:"Дублирующиеся адреса вызывают конфликт сообщения; панели обычно объявляют неисправность или не могут связаться с одним из устройств до исправления. (Отраслевая практика.)"},
  {id:242, q:"SLC классифицируется (класс Class A, B, X, N) на основе:", opts:["Только её калибра провода","Цвета проводников","Марки панели","Её характеристик в условиях неисправности (обрыв, замыкание, замыкание на землю)"], re:"NFPA 72 гл. 12: обозначения класса линии связи описывают требуемые характеристики в указанных условиях неисправности, а не один лишь физический провод."},
  {id:243, q:"SLC класса Class X отличается от SLC класса Class A тем, что Class X дополнительно:", opts:["Не требует обратного пути","Использует только пороговые устройства","Не может контролироваться","Работает при единичном ЗАМЫКАНИИ, а также при единичном обрыве (с изоляцией между устройствами)"], re:"NFPA 72 гл. 12: Class X — это линия с резервным путём, которая, в отличие от Class A, должна также продолжать работать при единичном замыкании, изолируя неисправности между элементами."},
  {id:244, q:"Модуль управления (выходной) на SLC используется для:", opts:["Установки часов панели","Замены резистора EOL на NAC","Обеспечения основного питания","Управления выходом, таким как реле, NAC или разблокировка двери, по адресу"], re:"Модули управления/реле занимают адрес SLC и приводят в действие выходы (реле, пороговые NAC, запуск, функции дверей) по команде панели. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:245, q:"Модуль мониторинга (входной) на SLC используется для:", opts:["Прямого питания оповещателей","Связи с центральной станцией мониторинга","Зарядки вторичных аккумуляторов","Вывода порогового контакта или IDC на адресную петлю с адресом"], re:"Модули мониторинга/входные обеспечивают адрес для сухого контакта или порогового IDC (например, контроль потока воды, контрольный выключатель) на SLC. (Отраслевая практика; NFPA 72 гл. 23.)"},
  {id:246, q:"NFPA 72 требует, чтобы исправность SLC была:", opts:["Проверена только при монтаже, никогда снова","Оставлена без контроля, если она адресная","Контролируема только центральной станцией мониторинга","Автоматически и непрерывно контролируема на условия неисправности"], re:"NFPA 72 гл. 12/10: монтажные проводники и линии связи, включая SLC, должны автоматически контролироваться на исправность, чтобы неисправности вызывали сигнал неисправности."},
  {id:247, q:"Какую неисправность на SLC класса Class B надлежащим образом контролируемая панель объявит как неисправность?", opts:["Только замыкание, никогда не обрыв","На Class B неисправности не объявляются","Только загрязнённый датчик на уровне устройства","Единичный обрыв ИЛИ единичное замыкание на землю на петле"], re:"NFPA 72 гл. 12: единичный обрыв или единичное замыкание на землю на контролируемой линии связи должны объявляться как неисправность в течение требуемого времени."},
  {id:248, q:"Использование изоляторов короткого замыкания на SLC в первую очередь улучшает:", opts:["Ёмкость основного питания панели","Цветопередачу стробов","Слышимость сирен","Живучесть петли за счёт ограничения количества устройств, которые может вывести из строя единичное замыкание"], re:"Изоляторы ограничивают замыкание одним сегментом, так что остальная часть петли продолжает связь, улучшая отказоустойчивость/живучесть SLC. (NFPA 72 гл. 12; отраслевая практика.)"},
  {id:249, q:"На SLC термин «T-tap» (ответвление) в проводке относится к:", opts:["Резервному обратному пути обратно к панели","Только изолятору короткого замыкания","Местоположению оконечного резистора","Отводу/ответвлению от основного хода петли"], re:"T-tap — это ответвление от магистрали SLC; допустимость T-tap зависит от класса линии связи и производителя (классы Class A/X требуют непрерывности, которая ограничивает неконтролируемые ответвления). (Отраслевая практика.)"},
  {id:250, q:"В адресной системе панель узнаёт, что устройство было СНЯТО с SLC, потому что:", opts:["Адрес устройства перестаёт отвечать на опрос, и генерируется неисправность","Снятые устройства не оказывают влияния","Активируется тревога здания","Центральная станция мониторинга перезванивает"], re:"Панель непрерывно опрашивает каждый адрес; отсутствующий/неотвечающий адрес вызывает неисправность (например, «устройство отсутствует»). (NFPA 72 гл. 10/12 контроль исправности; отраслевая практика.)"},
  {id:251, q:"Согласно NFPA 72 гл. 12, линия связи класса Class B — это линия, которая:", opts:["Включает резервный обратный путь к контрольной панели","Зарезервирована для сетевых (Ethernet) линий связи","Продолжает работать при единичном обрыве и единичном замыкании","Работает без резервного пути; устройства за единичным обрывом теряются"], re:"NFPA 72 гл. 12: Class B не имеет резервного пути; единичный обрыв выводит из строя устройства ниже места неисправности (объявляется неисправность)."},
  {id:252, q:"Согласно NFPA 72 гл. 12, линия связи класса Class A:", opts:["Не имеет контроля исправности","Требует волоконно-оптического кабеля","Не может обнаружить замыкание на землю","Включает резервный путь и продолжает работать при единичном обрыве"], re:"NFPA 72 гл. 12: Class A включает резервный (обратный) путь, так что работа продолжается при единичном обрыве; неисправность всё равно объявляется как неисправность."},
  {id:253, q:"Согласно NFPA 72 гл. 12, линия связи класса Class X должна продолжать работать при:", opts:["Только единичном обрыве","Никаких неисправностях вообще","Только единичном замыкании на землю","Как единичном обрыве, так и единичном замыкании (с изоляцией неисправностей)"], re:"NFPA 72 гл. 12: Class X — это линия связи с резервным путём, которая продолжает работать при единичном обрыве И единичном замыкании, обеспечивая изоляцию между устройствами."},
  {id:254, q:"Согласно NFPA 72 гл. 12, линия связи класса Class N относится к:", opts:["Одиночному неконтролируемому ходу провода","Только двусторонней радиочастотной линии","Пороговому IDC с резистором EOL","Сетевой линии связи с резервированием, проверяемым связью из конца в конец"], re:"NFPA 72 гл. 12: Class N — это сетевая (например, Ethernet) линия связи; где существуют два или более путей, операционная способность к каждому устройству проверяется связью из конца в конец, а её потеря объявляется как неисправность."},
  {id:255, q:"На линии связи класса Class N единичный обрыв, замыкание или замыкание на землю на одной линии связи должны:", opts:["Вывести из строя всю сеть","Запустить тревогу здания","Быть полностью проигнорированы","Не повлиять на работу любой другой (резервной) линии связи"], re:"NFPA 72 гл. 12: для Class N единичная неисправность на одной линии связи не должна влиять на любую другую линию связи, а потеря предполагаемой связи объявляется как неисправность."},
  {id:256, q:"Какое устаревшее обозначение «стиля» (Style) соответствует современной сигнальной линии класса Class A?", opts:["Style 4","Style 0.5","Style Z","Style 6"], re:"История NFPA 72: прежний SLC Style 6 (резервный путь, переживает единичный обрыв) соответствует сегодняшнему Class A; Style 4 соответствует Class B; Style 7 соответствует Class X."},
  {id:257, q:"Какое устаревшее обозначение «стиля» (Style) SLC соответствует современной линии класса Class B?", opts:["Style 4","Style 6","Style 7","Style N"], re:"История NFPA 72: SLC Style 4 (без резервного пути) соответствует Class B; Style 6 — Class A; Style 7 — Class X."},
  {id:258, q:"Какое устаревшее обозначение «стиля» (Style) SLC соответствует современной линии класса Class X?", opts:["Style 4","Style 6","Style 7","Style B"], re:"История NFPA 72: SLC Style 7 (резервный путь, который также переживает замыкание, с изоляцией) соответствует Class X."},
  {id:259, q:"ЖИВУЧЕСТЬ линии связи NFPA 72 рассматривает способность линии связи:", opts:["Сопротивляться электрическим помехам","Снижать стоимость монтажа","Нести более высокое напряжение","Продолжать работать в течение некоторого периода при воздействии огня"], re:"NFPA 72 гл. 12: живучесть линии связи касается того, сохраняется ли целостность цепи при воздействии огня, чтобы сообщения всё равно достигали зон, ещё не оповещённых."},
  {id:260, q:"Уровень 0 (Level 0) живучести линии связи NFPA 72 означает, что линия связи:", opts:["Требует кабель с огнестойкостью 2 часа","Требует металлический короб","Должна быть в полностью оснащённом спринклерами здании","Не имеет определённого требования к живучести"], re:"NFPA 72 гл. 12: Level 0 не налагает никаких требований к живучести на линию связи."},
  {id:261, q:"Уровень 1 (Level 1) живучести линии связи NFPA 72 обычно опирается на:", opts:["Кабель целостности цепи с огнестойкостью 2 часа","Только автоматическую спринклерную систему без короба","Никакой защиты вообще","Проводники в металлическом коробе/бронированном кабеле внутри полностью оснащённого спринклерами здания"], re:"NFPA 72 гл. 12: Level 1 использует линии связи в здании, полностью защищённом автоматическими спринклерами, с проводниками в металлическом коробе или кабеле с металлической бронёй."},
  {id:262, q:"Уровень 2 (Level 2) живучести линии связи NFPA 72 достигается такими методами, как:", opts:["Обычный THHN в EMT, без огнестойкости","Только кабель с рейтингом для воздуховодов","Работа на 12 В постоянного тока","Кабель целостности цепи (CI) с огнестойкостью 2 часа, кабельная система с огнестойкостью 2 часа или ограждение с рейтингом 2 часа"], re:"NFPA 72 гл. 12: Level 2 состоит из кабеля CI с огнестойкостью 2 часа, внесённой в перечень защитной системы электрической цепи на 2 часа или огнестойкого ограждения/защищённой зоны на 2 часа."},
  {id:263, q:"Уровень 3 (Level 3) живучести линии связи NFPA 72 отличается от Уровня 2 тем, что Уровень 3 также требует:", opts:["Никакой огнестойкости вообще","Вторую контрольную панель","Волоконно-оптический кабель","Чтобы здание было полностью защищено автоматической спринклерной системой (в дополнение к методам Level 2)"], re:"NFPA 72 гл. 12: Level 3 сочетает методы с рейтингом 2 часа из Level 2 с полностью оснащённым спринклерами зданием."},
  {id:264, q:"Для системы экстренной связи, использующей частичную эвакуацию или перемещение, NFPA 72 требует живучести линии связи как минимум:", opts:["Level 0","Level 1","Level 2 (или Level 3)","Без требования"], re:"NFPA 72 гл. 12/24: системы, использующие перемещение или частичную эвакуацию, должны иметь живучесть линии связи Level 2 или Level 3, чтобы сообщения достигали обитателей, ещё не оповещённых."},
  {id:265, q:"Важный нюанс уровней живучести NFPA 72 в том, что они:", opts:["Строго иерархичны, где более высокие числа всегда лучше","Только о громкости оповещателей","Идентичны классам линий связи A/B/X/N","Перечень разных методов исполнения, а не простое ранжирование «выше — лучше»"], re:"NFPA 72 гл. 12 приложение/намерение: уровни описывают разные методы/критерии защиты; это не строгое ранжирование, где более высокое число автоматически лучше во всех отношениях."},
  {id:266, q:"Требования к живучести линии связи обычно применяются к цепям до тех пор, пока они:", opts:["Не покинут здание","Не получат питание","Не достигнут первого устройства","Не войдут в зону оповещения, которую они обслуживают"], re:"NFPA 72 гл. 12/24: живучесть требуется для цепей, проходящих через другие зоны; как только цепь находится внутри зоны оповещения, которую она обслуживает, может быть приемлема более низкая живучесть."},
  {id:267, q:"Какое утверждение правильно противопоставляет КЛАСС линии связи и ЖИВУЧЕСТЬ линии связи?", opts:["Класс рассматривает воздействие огня; живучесть рассматривает электрические неисправности","Ни то, ни другое не относится к отказоустойчивости","Это одно и то же требование","Класс рассматривает характеристики при электрических неисправностях; живучесть рассматривает физическую/противопожарную защиту линии связи"], re:"NFPA 72 гл. 12: КЛАСС линии связи (A/B/X/N) определяет характеристики при электрических неисправностях; ЖИВУЧЕСТЬ линии связи (Level 0-3) определяет физическую стойкость к воздействию огня — два отдельных понятия."},
  {id:268, q:"Основное назначение оконечного резистора (EOLR) на пороговом IDC или NAC заключается в:", opts:["Увеличении громкости оповещателей","Установке адреса устройства","Обеспечении вторичного питания","Позволить панели контролировать проводку на условия обрыва и замыкания"], re:"EOLR устанавливает известный контрольный ток, так что панель может обнаружить обрыв (потеря тока) или замыкание (избыточный ток) в цепи, генерируя неисправность. (NFPA 72 гл. 10/23; отраслевая практика.)"},
  {id:269, q:"На контролируемом пороговом IDC ОБРЫВ цепи (оборванный провод) обычно отображается панелью как:", opts:["Потеря контрольного тока → неисправность","Избыточный ток → тревога","Норма","Повышенное напряжение на устройстве"], re:"При установленном EOLR обрыв устраняет путь контрольного тока; панель видит потерю тока и объявляет неисправность. (Отраслевая практика; NFPA 72 гл. 10.)"},
  {id:270, q:"На контролируемом пороговом IDC с нормально разомкнутыми устройствами ЗАМЫКАНИЕ между проводниками обычно создаёт:", opts:["Только неисправность","Индикацию ТРЕВОГИ (замыкание имитирует замкнутое устройство)","Ничего","Контрольный сигнал"], re:"Поскольку пороговые извещательные устройства подают тревогу замыканием/замыканием петли, замыкание проводки на IDC обычно считывается как тревога. (Отраслевая практика; именно поэтому важны надлежащий контроль исправности и практики прокладки.)"},
  {id:271, q:"Где должен физически располагаться оконечный резистор на пороговой контролируемой цепи?", opts:["Только внутри контрольной панели","На клеммах панели","На электрическом конце цепи (после последнего устройства)","В середине хода"], re:"EOLR должен быть на дальнем/электрическом конце цепи, чтобы весь ход проводки находился внутри контролируемой петли; размещение его на панели оставило бы полевую проводку без контроля. (Отраслевая практика; NFPA 72 гл. 10.)"},
  {id:272, q:"NFPA 72 требует, чтобы единичный обрыв или замыкание на землю в цепи объявлялись как неисправность в течение максимум:", opts:["200 seconds","10 минут","1 час","24 часа"], re:"NFPA 72 гл. 12/10: единичный обрыв или единичное замыкание на землю должны обнаруживаться и объявляться как неисправность в течение 200 seconds."},
  {id:273, q:"На линии оповещателей (NAC) оконечное устройство также позволяет панели проверить:", opts:["Адрес каждого строба","Исправность проводки (обрыв/замыкание), чтобы разрыв был обнаружен до того, как понадобится тревога","Цветовую температуру стробов","Основное напряжение здания"], re:"Оконечное устройство NAC контролирует непрерывность/полярность проводки, так что неисправность объявляется как неисправность, гарантируя, что оповещатели сработают при вызове. (NFPA 72 гл. 10; отраслевая практика.)"},
  {id:274, q:"Почему пороговые оповещатели NAC обычно поляризованы (с блокирующими диодами)?", opts:["Чтобы сделать их громче","Чтобы цепь можно было контролировать в дежурном режиме с обратной полярностью и запитывать с нормальной полярностью при тревоге","Чтобы установить их адрес","Чтобы снизить их потребление тока до нуля"], re:"Поляризованные оповещатели позволяют панели подавать небольшое контрольное напряжение обратной полярности в дежурном режиме (оповещатели выключены) и нормальную полярность при тревоге (оповещатели включены), обеспечивая контроль исправности. (Отраслевая практика; NFPA 72 гл. 10.)"},
  {id:275, q:"«Контроль исправности» цепи в NFPA 72 фундаментально означает, что система:", opts:["Записывает видео панели","Автоматически контролирует исправность проводников/линий связи и сигнализирует о неисправностях","Требует охранника для наблюдения за панелью","Проверяет устройства только ежегодно"], re:"NFPA 72 гл. 10/12: контроль исправности/мониторинг целостности означает, что система автоматически обнаруживает неисправности (обрывы, замыкания на землю и т. д.) в своих цепях и индицирует неисправность."},
  {id:276, q:"Замыкание на землю в проводке пожарной сигнализации вызывает беспокойство, потому что оно может:", opts:["Повысить надёжность цепи","Потенциально нарушить правильную работу, поэтому оно должно объявляться как неисправность","Увеличить срок службы аккумулятора","Устанавливать адреса устройств автоматически"], re:"NFPA 72 гл. 10/12: замыкание на землю, которое могло бы повлиять на требуемую работу, должно обнаруживаться и объявляться как неисправность в течение требуемого времени (200 с)."},
  {id:277, q:"В адресной системе функция, выполняемая EOLR на пороговых цепях, вместо этого достигается посредством:", opts:["Более крупного аккумулятора","Непрерывного контроля исправности опросом/связью каждого адресного устройства","Удаления всего контроля исправности","Более громкой сирены"], re:"Адресные петли контролируются опросом каждого адреса; потеря отклика даёт неисправность, заменяя роль EOLR на пороговых цепях. (Отраслевая практика; NFPA 72 гл. 10/12.)"},
  {id:278, q:"Замена требуемого оконечного резистора перемычкой (закорачивание его) на пороговом NAC:", opts:["Не окажет влияния","Отключит контроль исправности и может замаскировать неисправность обрыва/замыкания — нарушение нормы","Сделает оповещатели ярче","Добавит адрес в цепь"], re:"Удаление/закорачивание EOLR отключает контроль исправности проводки, нарушая требование NFPA 72 о мониторинге целостности и рискуя необнаруженными неисправностями. (NFPA 72 гл. 10; отраслевая практика.)"},
  {id:279, q:"Значение оконечного резистора для данной цепи определяется:", opts:["Предпочтением монтажника","Спецификациями производителя контрольной панели для этой цепи","Центральной станцией мониторинга","Длиной здания"], re:"Значение EOLR должно соответствовать внесённой в перечень схеме цепи панели; использование неправильного значения может помешать правильному различению обрыва/замыкания. (Спецификация производителя; NFPA 72 гл. 10.)"},
  {id:280, q:"Контроль исправности вторичного (аккумуляторного) питания требуется, чтобы панель могла обнаружить:", opts:["Загрязнённый дымовой извещатель","Отключённый, разряженный или вышедший из строя аккумулятор и индицировать неисправность","Закрытый спринклерный клапан","Потерю синхронизации стробов"], re:"NFPA 72 §10.6: система должна контролировать наличие/состояние вторичного источника питания (аккумулятора), индицируя неисправность при отсутствующем или разряженном аккумуляторе."},
  {id:281, q:"«Смена класса» проводки с класса Class B на класс Class A улучшает контроль исправности, добавляя:", opts:["Более крупный EOLR","Резервный обратный путь, так что единичный обрыв всё равно позволяет работу","Больше оповещателей","Вторую центральную станцию мониторинга"], re:"Class A прокладывает цепь обратно к панели (резервный путь); единичный обрыв тогда перекрывается, сохраняя работу при объявлении неисправности. (NFPA 72 гл. 12.)"},
  {id:282, q:"NFPA 72 обычно требует, чтобы состояние неисправности в системе было:", opts:["Видимым на контрольной панели и создавать звуковое оповещение о неисправности","Регистрировалось только на центральной станции мониторинга, никогда не показывалось локально","Индицировалось только в рабочее время","Заглушено постоянно после первого возникновения"], re:"NFPA 72 гл. 10: состояния неисправности должны визуально индицироваться на контрольной панели и сопровождаться звуковым сигналом неисправности (который снова звучит для новых неисправностей)."},
  {id:283, q:"Что лучше всего описывает, почему цепи пожарной сигнализации «контролируются», а не просто проложены?", opts:["Чтобы снизить стоимость провода","Чтобы неисправности проводки обнаруживались автоматически, а готовность системы непрерывно проверялась","Чтобы устранить необходимость в испытаниях","Чтобы ускорить монтаж"], re:"Контроль исправности гарантирует, что скрытые неисправности проводки (обрывы/замыкания на землю/замыкания) обнаруживаются и объявляются до того, как они помешают системе работать в экстренной ситуации. (NFPA 72 гл. 10/12.)"},
  {id:284, q:"На пороговом IDC контрольный ток, протекающий через EOLR в нормальном дежурном режиме:", opts:["Ноль ампер","Небольшой ток, слишком низкий для активации оповещения, но достаточный для того, чтобы панель чувствовала исправность","Такой же, как полный ток тревоги","Равный основным 120 В переменного тока"], re:"В дежурном режиме небольшой контрольный ток протекает через EOLR; панель чувствует его для подтверждения непрерывности, при этом он слишком мал для работы оповещателей. (Отраслевая практика; NFPA 72 гл. 10.)"},
  {id:285, q:"Глава 26 NFPA 72 охватывает какую категорию систем?", opts:["Бытовые сигнализации одиночной и множественных станций","Системы сигнализации станций мониторинга (центральная, собственная, удалённая)","Расстановку оповещателей","Испытание чувствительности извещателей"], re:"NFPA 72 гл. 26 рассматривает системы сигнализации станций мониторинга — обслуживание центральной станцией, собственной станцией и удалённой станцией мониторинга."},
  {id:286, q:"Цифровой коммуникаторный передатчик тревоги (DACT) на защищаемом объекте при передаче должен:", opts:["Оставить телефонную линию свободной для исходящих звонков","Захватить телефонную линию (захват линии) и отключить любой текущий звонок, чтобы отправить сигнал","Подождать до рабочего времени","Использовать только волоконно-оптический кабель"], re:"NFPA 72 гл. 26: DACT должен захватить линию (снять трубку), отключив любой существующий звонок, и предотвратить исходящие звонки до отправки сигнала — гарантируя, что тревога пройдёт."},
  {id:287, q:"Максимальное время от инициирования единичного сигнала тревоги на защищаемом объекте до его регистрации на станции мониторинга не должно превышать:", opts:["10 секунд","90 seconds","10 минут","1 час"], re:"NFPA 72 гл. 26: максимальное прошедшее время от инициирования единичного сигнала тревоги до его регистрации на станции мониторинга составляет 90 seconds."},
  {id:288, q:"Традиционная схема DACT, использующая телефонные линии, исторически требовала, чтобы передатчик был подключён к:", opts:["Только одной неконтролируемой линии","Двум средствам передачи (например, двум телефонным линиям, или одной линии плюс другая технология)","Четырём телефонным линиям","Никакому контролируемому пути"], re:"NFPA 72 гл. 26: устаревшие DACT использовали две телефонные линии; более поздние издания допускают одну линию плюс другую технологию (сотовая/IP), так что единичный отказ не блокирует сообщение."},
  {id:289, q:"Неполучение станцией мониторинга запланированного тестового сигнала от DACT/коммуникатора рассматривается как:", opts:["Сигнал тревоги","Сигнал неисправности","Контрольный сигнал","Нормальное событие"], re:"NFPA 72 гл. 26: неполучение ожидаемого тестового сигнала/сигнала регистрации указывает на возможную потерю связи и обрабатывается как сигнал неисправности."},
  {id:290, q:"Технологии связи на основе характеристик, признанные NFPA 72 для пожарной сигнализации за пределы объекта, включают:", opts:["Только медные телефонные линии","Сотовые коммуникаторы и коммуникаторы интернет-протокола (IP)","Дымовые сигналы","Только громкоговорящую связь"], re:"Технология на основе характеристик NFPA 72 гл. 26 охватывает IP- и сотовые коммуникаторы, которые могут служить технологиями одиночного пути, когда они соответствуют требованиям к характеристикам/контролю исправности."},
  {id:291, q:"В «обслуживании центральной станцией» NFPA 72 обязанности на месте, входящие в обслуживание, включают монтаж, испытание, обслуживание и:", opts:["Изготовление панели","Курьерское (реагирующее) обслуживание","Написание строительного кодекса","Обеспечение основного сетевого питания"], re:"NFPA 72 гл. 26: обслуживание центральной станцией включает функции станции мониторинга (мониторинг, ретрансляция, ведение записей) плюс функции защищаемого объекта по монтажу, испытанию, обслуживанию и курьерскому обслуживанию."},
  {id:292, q:"Когда состояние требует направления курьера на защищаемый объект, обслуживание центральной станцией NFPA 72 требует прибытия в течение:", opts:["15 минут","30 минут","2 часов","8 часов"], re:"NFPA 72 гл. 26: где требуется курьер (например, невосстановленное состояние), курьер должен прибыть на защищаемый объект в течение 2 часов после сигнала."},
  {id:293, q:"Собственная станция мониторинга отличается от центральной станции тем, что собственная станция:", opts:["Эксплуатируется сторонней компанией для многих владельцев","Принадлежит владельцу собственности и эксплуатируется им, контролируя собственность под этим единственным владением","Расположена только внутри пожарной службы","Никогда не обслуживается персоналом"], re:"NFPA 72 гл. 26: собственная станция мониторинга принадлежит владельцу защищаемой собственности и эксплуатируется им, и обслуживает прилегающие/связанные объекты под этим владением, с обученным персоналом в присутствии."},
  {id:294, q:"Система сигнализации удалённой станции мониторинга характеризуется:", opts:["Обслуживанием множества несвязанных владельцев, часто с приёмом сигналов в удалённом месте, таком как пожарный/коммуникационный центр","Расположением только на защищаемом объекте","Отсутствием необходимости в персонале мониторинга","Использованием только ручного телефонного сообщения"], re:"NFPA 72 гл. 26: обслуживание удалённой станцией мониторинга принимает сигналы в месте, удалённом от защищаемого объекта (например, пожарная служба или подрядный объект), для собственности под различными владениями."},
  {id:295, q:"Вторичный источник питания для передатчиков/оборудования на защищаемом объекте, необходимый для сигнализации за пределы объекта, должен обеспечивать минимум:", opts:["2 часа","8 часов","24 часа","7 дней"], re:"NFPA 72 гл. 26: вторичное питание для передающего оборудования на защищаемом объекте должно составлять минимум 24 часа."},
  {id:296, q:"DACR (цифровой коммуникаторный приёмник тревоги) располагается:", opts:["На защищаемом объекте","На станции мониторинга, где он принимает сигналы от DACT","Внутри каждого дымового извещателя","На линии оповещателей"], re:"NFPA 72 гл. 26: DACR — это приёмное оборудование на станции мониторинга, которое принимает и подтверждает сигналы, передаваемые DACT на защищаемых объектах."},
  {id:297, q:"Для DACT время от снятия трубки до её опускания при попытке передачи не должно превышать:", opts:["5 секунд","90 seconds","5 минут","30 минут"], re:"NFPA 72 гл. 26: попытка передачи DACT (от снятия трубки до её опускания) не должна превышать 90 seconds за попытку."},
  {id:298, q:"Главное преимущество для безопасности жизни от сигнализации за пределы объекта (станции мониторинга) в том, что:", opts:["Она заглушает сирены здания","Квалифицированный персонал уведомляется, и пожарная служба может быть направлена, даже если на объекте никого нет","Она устраняет необходимость в контрольной панели","Она заменяет спринклерные системы"], re:"Намерение NFPA 72 гл. 26: обслуживание станцией мониторинга гарантирует, что сигналы тревоги, контрольные и неисправности достигают обслуживающего персонала для реагирования/направления независимо от заполненности здания."},
  {id:299, q:"Какие сигналы обычно передаются за пределы объекта на станцию мониторинга?", opts:["Только сигналы пожарной тревоги","Сигналы тревоги, контрольные и неисправности","Только сигналы неисправности","Только потребление энергии зданием"], re:"NFPA 72 гл. 26: соединение за пределы объекта передаёт сигналы тревоги, контрольные и неисправности, чтобы по каждому состоянию можно было предпринять соответствующие действия."},
  {id:300, q:"Когда для сигнализации за пределы объекта используется одна технология связи (например, один IP- или сотовый путь), NFPA 72 требует, чтобы отказ этого пути был:", opts:["Никогда не сообщался","Объявлен/зарегистрирован на станции мониторинга в течение требуемого кодексом интервала контроля исправности","Сообщён только при следующем ежегодном испытании","Допущен оставаться необнаруженным в течение недели"], re:"NFPA 72 гл. 26: пути с одной технологией должны контролироваться, чтобы отказ связи объявлялся на станции мониторинга в течение предписанного интервала (например, 60 минут в недавних изданиях). (Точный интервал зависит от издания.)"},
  {id:301, q:"Согласно NFPA 72, что чаще всего является основным источником питания системы пожарной сигнализации?", opts:["Ответвлённая цепь коммерческой сети освещения и силового электроснабжения","Резервный комплект аккумуляторных батарей","Генератор с автоматическим запуском, приводимый двигателем","Источник бесперебойного питания (ИБП), используемый отдельно"], re:"NFPA 72, гл.10, определяет основной (главный) источник как сеть освещения и силового электроснабжения, обычно выделенную ответвлённую цепь от коммерческой сети. (NFPA 72-2022, 10.6.5)"},
  {id:302, q:"Каков МИНИМАЛЬНЫЙ период резерва (дежурного режима), который вторичный источник питания системы пожарной сигнализации защищаемого объекта должен обеспечивать до подключения любой нагрузки сигнала тревоги?", opts:["24 h","12 h","48 h","60 h"], re:"NFPA 72 требует, чтобы вторичный источник нёс дежурную нагрузку не менее 24 h. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:303, q:"После требуемого периода резерва вторичное питание неголосовой системы пожарной сигнализации должно обеспечивать работу всех оповещателей эвакуации не менее какого времени?", opts:["10 min","5 min","15 min","30 min"], re:"NFPA 72 требует 5 min полной работы сигнала тревоги после 24 h резерва для стандартной (неголосовой) системы. (NFPA 72-2022, 10.6.7.2)"},
  {id:304, q:"Для внутренней системы голосового/тревожного оповещения при пожаре (EVACS) длительность работы сигнала тревоги от вторичного питания после резерва увеличивается с 5 min до какого значения?", opts:["15 min","10 min","20 min","60 min"], re:"Когда система включает внутреннее голосовое/тревожное оповещение, время работы сигнала тревоги после резерва составляет 15 min. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:305, q:"NFPA 72 разрешает, чтобы вторичным источником питания системы защищаемого объекта было что из следующего?", opts:["Только аккумуляторная батарея во всех случаях","Только генератор во всех случаях","Конденсаторный блок, рассчитанный на 24 h","Аккумуляторная батарея ИЛИ генератор с автоматическим запуском, приводимый двигателем"], re:"Допустимые вторичные источники - аккумуляторная батарея или генератор с автоматическим запуском, приводимый двигателем. (NFPA 72-2022, 10.6.7)"},
  {id:306, q:"Когда генератор, приводимый двигателем, используется как вторичный источник питания, NFPA 72 всё равно требует аккумуляторные батареи, рассчитанные не менее чем на сколько часов, чтобы система работала, если генератор не запустится?", opts:["1 h","4 h","2 h","24 h"], re:"Генератор, используемый как вторичное питание, должен быть подкреплён батареями, обеспечивающими не менее 4 h работы на случай, если он не запустится. (NFPA 72-2022, 10.6.7.2)"},
  {id:307, q:"Потеря основного источника питания (переменного тока) для прибора управления пожарной сигнализацией должна индицироваться как какой тип сигнала на приборе управления?", opts:["Сигнал неисправности","Сигнал тревоги","Сигнал предтревоги","Индикация не требуется"], re:"Потеря основного питания - это аварийное состояние; NFPA 72 требует, чтобы оно индицировалось как сигнал неисправности. (NFPA 72-2022, 10.6 / 10.15)"},
  {id:308, q:"Выделенная ответвлённая цепь, подающая основное питание на прибор управления пожарной сигнализацией, должна иметь идентифицированное средство отключения. Маркировка обычно гласит:", opts:["\"НЕ ПРИКАСАТЬСЯ\" жёлтым","\"УПРАВЛЕНИЕ ЦЕПЬЮ ПОЖАРНОЙ СИГНАЛИЗАЦИИ\" красным","\"ОБЩЕЕ ОСВЕЩЕНИЕ\" чёрным","Маркировка не требуется"], re:"NFPA 72 / NEC 760.41 требуют, чтобы отключатель ответвлённой цепи был идентифицирован красным цветом как управление цепью пожарной сигнализации, со средством блокировки/бирки. (NFPA 72-2022, 10.6.6; NEC 760.41)"},
  {id:309, q:"ИБП или система накопленной электроэнергии, используемая как вторичный источник питания системы пожарной сигнализации, должна быть построена и обслуживаться в соответствии с каким стандартом?", opts:["NFPA 13","NFPA 111 (с двигатель-генераторами по NFPA 110)","NFPA 25","Только NFPA 1221"], re:"NFPA 72 ссылается на системы накопленной энергии/ИБП по NFPA 111 и на двигатель-генераторы по NFPA 110. (NFPA 72-2022, 10.6.9)"},
  {id:310, q:"Прибор управления пожарной сигнализацией должен быть способен полностью перезарядить полностью разряженный вторичный аккумулятор в течение какого максимального времени?", opts:["24 h","72 h","96 h","48 h"], re:"NFPA 72 требует, чтобы аккумулятор мог быть полностью перезаряжен прибором управления в течение 48 h после полного разряда. (NFPA 72-2022, 10.6.10.3.2)"},
  {id:311, q:"Какой документ регулирует методы прокладки проводки и классификацию цепей (с ограничением мощности или без него) для проводников системы пожарной сигнализации?", opts:["NEC (NFPA 70) Статья 760","NFPA 13","NFPA 101 Глава 7","ASME A17.1"], re:"Статья 760 NEC охватывает монтаж проводки цепей пожарной сигнализации, включая классификации PLFA и NPLFA. (NEC-2020, ст. 760)"},
  {id:312, q:"Цепь пожарной сигнализации с ограничением мощности (PLFA) имеет ограничение напряжения и мощности каким устройством?", opts:["Обычным ответвлённым автоматом на 20 A","Сертифицированным источником питания, соответствующим NEC 760.121","Катушкой реле","Самим оповещателем"], re:"Цепи PLFA ограничены сертифицированным источником питания по NEC 760.121; выход обычно 24 VDC или менее. (NEC-2020, 760.121)"},
  {id:313, q:"Каково типичное номинальное выходное напряжение источника питания цепи пожарной сигнализации с ограничением мощности, используемого для цепей запуска и оповещения?", opts:["120 VAC","240 VAC","24 VDC или менее","600 VDC"], re:"Сертифицированные источники PLFA для большинства цепей пожарной сигнализации работают при номинале 24 VDC или менее. (NEC-2020, 760.121; NFPA 72, гл.10)"},
  {id:314, q:"NEC 760.136 требует что из следующего между проводниками пожарной сигнализации с ограничением мощности и проводниками электрического освещения, силового электроснабжения и Класса 1?", opts:["Требуется совместное использование одного короба","Идентичный цвет изоляции","Физическое разделение (не в одном коробе/корпусе, кроме разрешённых случаев)","Только общий винт заземления"], re:"NEC 760.136 требует, чтобы проводники PLFA были отделены от проводников освещения, силового электроснабжения, Класса 1 и NPLFA. (NEC-2020, 760.136)"},
  {id:315, q:"Герметичные свинцово-кислотные (SLA) аккумуляторы являются наиболее распространённым вторичным накопителем энергии для панелей пожарной сигнализации главным образом потому, что они:", opts:["Самая лёгкая из доступных химий аккумуляторов","Способны на неограниченное число циклов перезаряда","Необслуживаемые, перезаряжаемые и доступны в стандартизированных размерах корпуса","Полностью невосприимчивы к воздействию температуры"], re:"Аккумуляторы SLA - отраслевой стандарт для FACU: герметичные, необслуживаемые, перезаряжаемые, в стандартных размерах, таких как 12 V 7 Ah / 12 V 12 Ah. (NFPA 72, гл.10; отраслевая практика)"},
  {id:316, q:"Стандартный 12-вольтовый герметичный свинцово-кислотный аккумулятор внутренне состоит из скольких 2-вольтовых элементов, соединённых последовательно?", opts:["3 элемента","12 элементов","24 элемента","6 элементов"], re:"Каждый свинцово-кислотный элемент номинально 2 V, поэтому шесть элементов последовательно дают аккумулятор 12 V. (Основы аккумуляторов)"},
  {id:317, q:"NFPA 72 требует, чтобы переход с основного на вторичное питание был:", opts:["Ручным, выполняемым оператором на месте","Задержанным фиксированным таймером на 5 min","Выполняемым только через 24 h","Автоматическим, без потери сигналов или функций системы"], re:"Переключение на вторичное питание должно быть автоматическим и не нарушать работу, чтобы защита была непрерывной. (NFPA 72-2022, 10.6.8)"},
  {id:318, q:"В расчёте резервного аккумулятора пожарной сигнализации дежурный ток (в режиме покоя) умножается на сколько часов?", opts:["5 h","12 h","48 h","24 h"], re:"Резервная энергия = дежурный ток x 24 h, минимальный период покоя. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:319, q:"Для стандартной (неголосовой) системы ток сигнала тревоги в расчёте аккумулятора умножается на какое время, выраженное в часах?", opts:["15 min = 0.25 h","30 min = 0.5 h","60 min = 1.0 h","5 min = 0.083 h"], re:"Пять минут равны 5/60 = 0.0833 h для тревожной части стандартной системы. (NFPA 72-2022, 10.6.7.2)"},
  {id:320, q:"Издание NFPA 72 2022 года требует, какой понижающий/защитный множитель применить к расчётной ёмкости аккумулятора в ампер-часах для учёта старения и температуры?", opts:["1.10","1.25","1.20","2.00"], re:"Издание 2022 года повысило поправочный коэффициент до 1.25 (25% запас прочности). (NFPA 72-2022, 10.6.7.2.14)"},
  {id:321, q:"Система потребляет 0.5 A в дежурном режиме и 2.0 A в режиме тревоги. Используя 24 h резерва, 5 min тревоги и коэффициент 1.25, минимальная ёмкость аккумулятора ближе всего к:", opts:["15.2 Ah","12.2 Ah","13.5 Ah","18.0 Ah"], re:"(0.5x24)+(2x0.0833)=12.0+0.167=12.167 Ah; x1.25=15.21 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:322, q:"Система потребляет 0.25 A в дежурном режиме и 1.5 A в режиме тревоги. При 24 h резерва, 5 min тревоги и коэффициенте 1.25 минимальная ёмкость ближе всего к:", opts:["6.1 Ah","9.0 Ah","7.7 Ah","11.0 Ah"], re:"(0.25x24)+(1.5x0.0833)=6.0+0.125=6.125 Ah; x1.25=7.66 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:323, q:"Голосовая система (EVACS) потребляет 0.3 A в дежурном режиме и 3.0 A в режиме тревоги. Используя 24 h резерва, 15 min тревоги и коэффициент 1.25, минимальная ёмкость ближе всего к:", opts:["9.9 Ah","7.2 Ah","8.5 Ah","12.0 Ah"], re:"(0.3x24)+(3x0.25)=7.2+0.75=7.95 Ah; x1.25=9.94 Ah. Голосовая использует 15 min = 0.25 h. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:324, q:"Какова резервная энергия (ампер-часы), вносимая дежурной нагрузкой 0.4 A за требуемый 24-часовой период резерва?", opts:["4.8 Ah","12.0 Ah","9.6 Ah","19.2 Ah"], re:"0.4 A x 24 h = 9.6 Ah резервной энергии до добавления тревожной нагрузки и коэффициента 1.25. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:325, q:"Система имеет 0.4 A в дежурном режиме и 2.5 A в режиме тревоги (24 h / 5 min / 1.25). Минимальная ёмкость аккумулятора ближе всего к:", opts:["12.3 Ah","10.0 Ah","11.0 Ah","14.0 Ah"], re:"(0.4x24)+(2.5x0.0833)=9.6+0.208=9.808 Ah; x1.25=12.26 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:326, q:"Как определяется ОБЩИЙ дежурный ток системы перед расчётом?", opts:["Использовать только дежурный ток панели","Использовать дежурный ток самого крупного отдельного устройства","Использовать ток сигнала тревоги, делённый на 2","Умножить дежурный ток каждого устройства на его количество и просуммировать все устройства плюс панель"], re:"Общий дежурный ток = сумма (дежурный ток каждого устройства x количество), включая прибор управления. (NFPA 72, гл.10; стандартный расчётный лист)"},
  {id:327, q:"В столбце сигнала тревоги расчётного листа аккумулятора оповещатели учитываются по их:", opts:["Дежурному току","Половине тока сигнала тревоги","Нулю, потому что их питает панель","Полному (активному) току сигнала тревоги"], re:"Оповещатели потребляют свой номинальный ток сигнала тревоги в активном состоянии; это значение заполняет столбец сигнала тревоги. (Стандартный расчётный лист NFPA 72)"},
  {id:328, q:"После вычисления требуемых ампер-часов монтажник выбирает аккумулятор, номинальная ёмкость которого:", opts:["Точно равна расчётному значению","Равна или больше расчётного значения","Не менее чем на 50% ниже расчётного значения","Любое значение, так как панели самонастраиваются"], re:"Номинал установленного аккумулятора в Ah должен равняться расчётному минимуму или превышать его; занижение - нарушение нормы. (NFPA 72, гл.10)"},
  {id:329, q:"Почему NFPA 72 применяет защитный/понижающий коэффициент к расчётной ёмкости аккумулятора?", opts:["Для учёта старения аккумулятора и потери ёмкости из-за температуры в течение срока службы","Чтобы оплатить монтажные работы","Чтобы сократить время резерва ниже 24 h","Потому что панели регулярно перезаряжают аккумуляторы"], re:"Коэффициент 1.25 компенсирует потерю ёмкости от старения и температуры, чтобы аккумулятор всё ещё соответствовал режиму в конце срока службы. (NFPA 72-2022, 10.6.7.2.14)"},
  {id:330, q:"Если системе требуется 15.2 Ah, какой номинал одного стандартного аккумулятора SLA является наименьшим приемлемым вариантом?", opts:["12 V 7 Ah","12 V 18 Ah","12 V 12 Ah","12 V 5 Ah"], re:"18 Ah - наименьший сертифицированный стандартный размер, который соответствует 15.2 Ah или превышает их. (Принцип подбора NFPA 72, гл.10)"},
  {id:331, q:"Два аккумулятора по 12 V (каждый 12 V 7 Ah), соединённые ПОСЛЕДОВАТЕЛЬНО для питания панели 24 V, обеспечивают какое напряжение системы и ёмкость?", opts:["12 V, 14 Ah","24 V, 14 Ah","24 V, 7 Ah","12 V, 7 Ah"], re:"Последовательное соединение складывает напряжение (12+12=24 V), но ёмкость остаётся той же (7 Ah). (Основы аккумуляторов)"},
  {id:332, q:"Два аккумулятора 12 V 7 Ah, соединённые ПАРАЛЛЕЛЬНО, обеспечивают:", opts:["12 V, 14 Ah","24 V, 7 Ah","24 V, 14 Ah","6 V, 7 Ah"], re:"Параллельное соединение сохраняет напряжение (12 V), но складывает ёмкость (7+7=14 Ah). (Основы аккумуляторов)"},
  {id:333, q:"Добавление блока магнитных держателей дверей в систему наиболее прямо увеличивает какое значение в расчёте аккумулятора?", opts:["Только ток сигнала тревоги","Дежурный ток (и, следовательно, резервные Ah)","Ни один из токов","Только время перезаряда"], re:"Держатели дверей запитаны постоянно, чтобы удерживать двери открытыми, поэтому они добавляются к току покоя/дежурному току и увеличивают размер аккумулятора. (NFPA 72, гл.10; отраслевая практика)"},
  {id:334, q:"Когда нагрузки делают требуемую ёмкость превышающей предел перезаряжаемого аккумулятора одной панели, правильным решением является:", opts:["Завысить внутренний аккумулятор сверх предела зарядки панели","Сократить время резерва до 12 h","Добавить сертифицированный удалённый источник питания / расширитель NAC с собственными контролируемыми аккумуляторами","Убрать оповещатели из проекта"], re:"Большие нагрузки обеспечиваются сертифицированными вспомогательными/усилительными источниками питания (расширителями NAC) с собственными контролируемыми вторичными аккумуляторами. (NFPA 72, гл.10; NEC 760)"},
  {id:335, q:"В NFPA 72 функции здания, которые активирует система пожарной сигнализации (отключение вентиляторов, возврат лифта, разблокировка дверей, дымоудаление), вместе называются:", opts:["Обходы контроля","Выходы неисправности","Нагрузки покоя","Функции аварийного управления"], re:"Глава 21 регулирует функции аварийного управления (ECF) и их интерфейсы. (NFPA 72-2022, гл. 21)"},
  {id:336, q:"NFPA 72, глава 21, разрешает межсоединению между устройством интерфейса функции аварийного управления и управляемым оборудованием использовать какой метод?", opts:["Сертифицированные электрические контакты для подключённой нагрузки или выделенную/общую сигнальную линейную цепь","Только пневматические трубки","Только оптоволокно","Только беспроводную радиосвязь"], re:"Глава 21 разрешает сертифицированные электрические контакты для подключённой нагрузки или передачу данных по SLC. (NFPA 72-2022, 21.2)"},
  {id:337, q:"Реле или устройство интерфейса, используемое для выполнения функции аварийного управления, должно располагаться:", opts:["В любом удобном месте; контроль необязателен","Не менее чем в 100 ft от управляемого компонента","В пределах 3 ft (1 m) от управляемого компонента ИЛИ проводка должна контролироваться на целостность","Только снаружи"], re:"Глава 21 требует, чтобы реле интерфейса было в пределах 3 ft от управляемого оборудования или чтобы соединительные проводники контролировались на целостность. (NFPA 72-2022, 21.2.4)"},
  {id:338, q:"Контакт реле 'Form C', предусмотренный на приборе управления пожарной сигнализацией, даёт монтажнику какую схему контактов?", opts:["Только нормально разомкнутый","Только нормально замкнутый","Один общий с нормально разомкнутым и нормально замкнутым контактами (SPDT)","Фиксируемый контакт без общего"], re:"Контакт Form C - однополюсный на два направления: общий вывод с контактами НР и НЗ для гибкого интерфейса. (Соглашения о реле/контактах)"},
  {id:339, q:"Для управления нагрузкой, потребляющей больший ток или более высокое напряжение, чем может коммутировать встроенное реле панели, технику следует использовать:", opts:["Сертифицированное управляющее (промежуточное) реле, рассчитанное на нагрузку, приводимое в действие панелью","Только более крупный предохранитель","Более длинный кабельный прогон","Цепь оповещения напрямую"], re:"Промежуточное/управляющее реле, сертифицированное и рассчитанное на нагрузку, изолирует и коммутирует её, пока панель приводит в действие катушку реле. (NFPA 72, гл.21; NEC 760)"},
  {id:340, q:"Когда система пожарной сигнализации приводит в действие систему HVAC в целях дымоудаления, NFPA 72 требует, чтобы зоны запуска были:", opts:["Игнорированы во время тревоги","Согласованы с зонами дымоудаления, которые они приводят в действие","Подключены к цепи оповещения","Отключены для предотвращения ложных тревог"], re:"Когда FACU приводит в действие HVAC для дымоудаления, тревожные зоны запуска должны быть согласованы с зонами дымоудаления, которые они приводят в действие. (NFPA 72-2022, 21.7)"},
  {id:341, q:"Управляющее реле, которое освобождает магнитный держатель двери при тревоге, должно при потере питания или неисправности системы заставить дверь:", opts:["Оставаться удерживаемой открытой","Заблокироваться электрически","Включить только местный звуковой сигнал","Освободиться и закрыться (отказоустойчиво)"], re:"Устройства удержания открытыми отказоустойчивы: потеря питания освобождает магнит, чтобы дверь закрылась, сохраняя противопожарный/противодымный барьер. (NFPA 72, гл.21; NFPA 80)"},
  {id:342, q:"Проводники, несущие функцию аварийного управления, но НЕ контролируемые на целостность системой пожарной сигнализации, должны, как минимум:", opts:["Быть неконтролируемыми без ограничения длины","Использовать изоляцию на 600 V независимо от напряжения","Быть установлены в отдельном здании","Иметь реле интерфейса, расположенное в пределах 3 ft (1 m) от управляемого оповещателя"], re:"Неконтролируемая проводка ECF ограничивается размещением реле в пределах 3 ft от управляемого оборудования согласно главе 21. (NFPA 72-2022, 21.2.4)"},
  {id:343, q:"'Адресуемый модуль реле (управления)' в сигнальной линейной цепи используется главным образом для того, чтобы:", opts:["Увеличить громкость оповещателя","Заменить аккумулятор системы","Измерять замыкания на землю","Обеспечить управляемый сухой/релейный контакт в удалённой точке SLC для функций управления"], re:"Адресуемые модули реле дают панели удалённо расположенный, индивидуально адресуемый контакт для приведения в действие функций управления по SLC. (NFPA 72, гл.10/23, функции устройств)"},
  {id:344, q:"Что из следующего является примером функции противопожарного управления в отличие от функции оповещения?", opts:["Включение сирены/строба в коридоре","Мигание стробом в санузле","Возврат лифта на назначенный уровень","Воспроизведение голосового сообщения об эвакуации"], re:"Возврат лифта - это функция аварийного (противопожарного) управления по главе 21; сирены, стробы и голосовые сообщения - это оповещение. (NFPA 72-2022, гл.21 против гл.18)"},
  {id:345, q:"Для функции аварийного управления NFPA 72 требует, чтобы неисправность между FACU и контролируемым устройством интерфейса приводила к:", opts:["Отсутствию индикации","Немедленной общей тревоге","Сигналу неисправности на приборе управления","Автоматической активации функции"], re:"Неисправность в контролируемой цепи интерфейса ECF должна выдавать сигнал неисправности на FACU. (NFPA 72-2022, 21.2.5)"},
  {id:346, q:"Модуль реле, используемый для отключения вентиляторов при тревоге, подключён так, что вентилятор останавливается, когда реле:", opts:["Активируется FACU при тревоге, размыкая/изменяя цепь управления вентилятором","Катушка просто обесточена постоянно","Удалено из панели","Достигает 24 h наработки"], re:"При тревоге FACU активирует реле интерфейса, которое размыкает/изменяет цепь управления вентилятором для команды отключения. (NFPA 72-2022, 21.7; NFPA 90A)"},
  {id:347, q:"Приоритет сигналов на приборе управления пожарной сигнализацией ставит какой тип сигнала выше всего?", opts:["Сигналы неисправности","Контрольные сигналы","Сигналы покоя","Сигналы тревоги"], re:"NFPA 72 устанавливает сигналы тревоги как наивысший приоритет, выше контрольных, затем неисправности. (NFPA 72-2022, приоритет сигналов)"},
  {id:348, q:"Функция управления 'выпуском' (например, для выпуска системы пожаротушения чистым агентом) требует, чтобы цепь выпуска была:", opts:["Без надзора и контроля","Под надзором/контролем, с использованием оборудования, сертифицированного для службы выпуска","Подключена к цепи держателя двери","Запитана только держателями дверей"], re:"Служба выпуска использует сертифицированные панели/цепи выпуска под надзором; неисправности целостности индицируются. (NFPA 72-2022, гл.23; интерфейс NFPA 12/2001)"},
  {id:349, q:"Когда один адресуемый модуль обеспечивает И контроль устройства, И управление функцией, проводка всё равно должна гарантировать, что:", opts:["Управление и контроль используют один неконтролируемый провод","Модуль игнорирует замыкания на землю","Потеря целостности обнаруживается и сообщается как неисправность","Функция активируется при любой неисправности"], re:"Независимо от совмещённой функции, целостность интерфейса должна контролироваться, а неисправности сообщаться как неисправность. (NFPA 72-2022, 21.2.5)"},
  {id:350, q:"Функция управления, которая должна продолжать работать во время пожара (например, вентиляторы подпора лестничных клеток для дымоудаления), обычно запитывается и прокладывается как:", opts:["Стандартная негорючестойкая ответвлённая цепь","Цепь держателя двери","Цепь только для неисправностей","Огнестойкая / защищённая цепь согласно требованиям дымоудаления и глав 21/24"], re:"Оборудование дымоудаления, которое должно работать во время пожара, требует огнестойкой целостности цепи и резервного питания согласно применимым положениям. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:351, q:"Аварийный возврат лифта Фазы I, инициированный системой пожарной сигнализации, заставляет кабину:", opts:["Автоматически вернуться на назначенный уровень возврата и быть выведенной из нормальной эксплуатации","Немедленно остановиться между этажами","Ускориться к верхнему этажу","Открыть все двери шахты"], re:"Возврат Фазы I возвращает кабину на назначенную площадку и выводит её из нормальной эксплуатации согласно аварийной операции пожарных по ASME A17.1. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:352, q:"Какой стандарт определяет фактическое поведение лифта (Аварийная операция пожарных, Фаза I и Фаза II), с которым взаимодействует система пожарной сигнализации?", opts:["NFPA 13","ASME A17.1 / CSA B44","NFPA 25","NEC Статья 700"], re:"ASME A17.1/CSA B44 определяет FEO Фазы I/II; NFPA 72, гл.21, определяет, как пожарная сигнализация взаимодействует с ней. (NFPA 72-2022, 21.3; ASME A17.1 2.27)"},
  {id:353, q:"Активация какого устройства обычно инициирует возврат лифта Фазы I на НАЗНАЧЕННЫЙ (основной) уровень?", opts:["Дымовой извещатель в лифтовом холле (кроме назначенного уровня), машинном помещении или шахте","Ручной извещатель в коридоре","Извещатель протока воды на третьем этаже","Канальный извещатель в HVAC холла"], re:"Дымовые извещатели холла, машинного помещения и шахты (кроме назначенного уровня) возвращают кабину на назначенный уровень. (NFPA 72-2022, 21.3.5; ASME A17.1)"},
  {id:354, q:"Когда срабатывает дымовой извещатель на НАЗНАЧЕННОМ уровне возврата, лифт возвращается на:", opts:["Тот же назначенный уровень","Верхний этаж","Только подвал во всех случаях","Альтернативный (запасной) уровень возврата"], re:"Если срабатывает извещатель назначенного уровня, возврат направляется на альтернативный уровень, чтобы кабина не открылась в задымлённый назначенный холл. (NFPA 72-2022, 21.3.6; ASME A17.1)"},
  {id:355, q:"Дымовые извещатели, используемые исключительно для возврата лифта, должны инициировать возврат, а также:", opts:["Быть скрытыми из вида","Запитываться только от контроллера лифта","Включать только местный зуммер","Заставлять систему пожарной сигнализации здания индицировать тревогу (они подключаются к FACU)"], re:"Извещатели возврата подключены к FACU здания и контролируются ею, инициируя тревогу/возврат, а не только местную функцию. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:356, q:"NFPA 72 требует предусмотреть ОТДЕЛЬНЫЕ выходы прибора управления пожарной сигнализацией для реализации каких функций лифта?", opts:["Только сирену тревоги","Возврат Фазы I И любое требуемое отключение питания (шунтовой расцепитель), как отдельные выделенные выходы","Только систему музыки лифта","Только освещение кабины лифта"], re:"Глава 21 требует отдельные выделенные выходы для возврата Фазы I и для отключения питания (шунтовой расцепитель). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:357, q:"Шунтовой расцепитель питания лифта (автоматическое отключение питания лифта) предусматривается там, где спринклеры установлены в машинном помещении или шахте, чтобы питание снималось:", opts:["Намного позже выпуска воды","До выпуска воды спринклерами на запитанное оборудование лифта","Только во время планового тестирования","Никогда, потому что шунтовой расцепитель запрещён"], re:"Шунтовой расцепитель снимает питание лифта до выпуска спринклеров для предотвращения неконтролируемого движения и опасности поражения током. (NFPA 72-2022, 21.4; ASME A17.1)"},
  {id:358, q:"Для срабатывания шунтового расцепителя ДО срабатывания спринклера тепловой извещатель устанавливается рядом с каждым соответствующим спринклером. NFPA 72 требует, чтобы этот извещатель был:", opts:["С более высокой температурой и медленнее спринклера","В пределах 2 ft (0.6 m) от каждого спринклера, срабатывая раньше спринклера","Расположен в 25 ft от спринклера","Только дымовым извещателем"], re:"Тепловой извещатель в пределах 2 ft от каждого спринклера, с соответствующей температурой/откликом, приводит в действие шунтовой расцепитель раньше срабатывания спринклера. (NFPA 72-2022, 21.4.2; ASME A17.1)"},
  {id:359, q:"Почему возврат лифта должен использовать дымовое обнаружение (а не тепловое) в холлах, машинных помещениях и шахтах для функции возврата?", opts:["Чтобы вернуть кабины рано, до того как дым подвергнет опасности людей, использующих или покидающих лифт","Потому что тепловые извещатели дешевле","Потому что дымовые извещатели никогда не дают ложных тревог","Потому что норма запрещает тепло где-либо рядом с лифтами"], re:"Дымовое обнаружение обеспечивает ранний возврат, чтобы люди не оказались в ловушке из-за дыма; тепло зарезервировано для функции шунтового расцепителя. (NFPA 72-2022, 21.3 против 21.4)"},
  {id:360, q:"Выделенный визуальный сигнал (подсвеченный индикатор 'каски пожарного') внутри кабины лифта сообщает людям, что:", opts:["Аварийная операция пожарных (возврат) действует","Кабина нуждается в обслуживании","Аккумулятор разряжен","Двери механически заблокированы"], re:"Подсвеченная каска/визуальный сигнал указывает, что возврат Фазы I/FEO активен по ASME A17.1; пожарная сигнализация выдаёт сигнал инициации. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:361, q:"Какое устройство запуска НЕ должно использоваться для инициации возврата лифта Фазы I?", opts:["Дымовой извещатель лифтового холла","Ручной пожарный извещатель (ручной извещатель)","Дымовой извещатель машинного помещения лифта","Дымовой извещатель шахты лифта"], re:"Возврат инициируется дымовыми извещателями в холлах, машинных помещениях и шахтах, а не ручными извещателями. (NFPA 72-2022, 21.3.5)"},
  {id:362, q:"В здании с несколькими лифтами в общей шахте или сгруппированными вместе активация устройства, инициирующего возврат, обычно возвращает:", opts:["Только одну случайно выбранную кабину","Все лифты, обслуживаемые этим холлом/группой, согласно проекту и ASME A17.1","Ни одного лифта","Только грузовые лифты"], re:"Возврат затрагивает лифты, обслуживаемые активированной зоной/группой, согласованно с проектом лифта и ASME A17.1. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:363, q:"Интерфейс между системой пожарной сигнализации и контроллером лифта для возврата обычно выполняется через:", opts:["Цепь оповещателей","Цепь держателя двери","Выделенные релейные выходы/контакты, сертифицированные для интерфейса лифта","Извещатель протока воды спринклера"], re:"Сигналы возврата и отключения подаются через выделенные контролируемые релейные выходы на контроллер лифта. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:364, q:"Дымовые извещатели, установленные в лифтовых холлах для возврата, размещаются согласно:", opts:["Фиксированному шагу 100 ft независимо от геометрии","Только одному на здание","Стандартным правилам размещения точечных дымовых извещателей, не менее одного в каждом холле","Шагу спринклерных оросителей"], re:"Извещатели возврата холла следуют стандартному размещению дымовых извещателей с охватом каждого лифтового холла. (NFPA 72-2022, 17.7; 21.3)"},
  {id:365, q:"Если в машинном помещении лифта есть и дымовой извещатель, и (где есть спринклеры) тепловой извещатель, их функции:", opts:["Идентичны: оба возвращают кабину","Оба немедленно отключают питание","Ни один не подключается к FACU","Дымовой извещатель возвращает кабину; тепловой извещатель инициирует отключение питания шунтовым расцепителем"], re:"Дым машинного помещения возвращает (Фаза I); тепловой извещатель рядом со спринклером управляет шунтовым расцепителем. (NFPA 72-2022, 21.3 / 21.4)"},
  {id:366, q:"После того как возврат Фазы I вернул кабину на уровень возврата, двери кабины:", opts:["Остаются закрытыми, и кабина остаётся в эксплуатации","Постоянно открываются и закрываются","Открываются и остаются открытыми, и кабина выводится из нормальной автоматической эксплуатации","Запирают людей внутри кабины"], re:"На уровне возврата двери открываются, и кабина выводится из нормальной эксплуатации, доступная только для операции пожарных Фазы II. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:367, q:"Объединение обнаружения возврата лифта и шунтового расцепителя на ОДНОМ устройстве запрещено, потому что:", opts:["Возврат (рано, дым) и отключение (тепло, прямо перед водой) служат разным целям и срокам и требуют отдельных выходов","Это слишком экономит деньги","Тепловые извещатели нельзя контролировать","Дымовые извещатели не разрешены в машинных помещениях"], re:"NFPA 72 требует отдельные выходы: возврат (рано, дым) против отключения (тепло, непосредственно перед выпуском спринклера). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:368, q:"Основное требуемое нормой назначение канального дымового извещателя по NFPA 90A состоит в том, чтобы:", opts:["Заменить обнаружение дыма по площади (открытому пространству)","Включить сигнал эвакуации здания самостоятельно","Остановить вентилятор воздухообработки для предотвращения распространения дыма по каналам","Удерживать противопожарные двери открытыми"], re:"Согласно NFPA 90A, канальные дымовые извещатели отключают приточный вентилятор, чтобы остановить рециркуляцию/распространение дыма; они не заменяют обнаружение по площади. (NFPA 90A; NFPA 72-2022, 17.7.5)"},
  {id:369, q:"NFPA 90A требует канальные дымовые извещатели в системах воздухообработки с производительностью на приточной стороне больше какого значения расхода воздуха?", opts:["500 cfm","1,000 cfm","2,000 cfm","5,000 cfm"], re:"NFPA 90A требует канальное дымовое обнаружение в приточных системах, превышающих 2,000 cfm. (NFPA 90A)"},
  {id:370, q:"Канальный дымовой извещатель на приточной стороне должен устанавливаться:", opts:["За фильтрами и до любых ответвлённых соединений","В самом конце самого длинного ответвлённого канала","Только в потолке занятого помещения","На наружной стене здания"], re:"NFPA 90A располагает приточный канальный извещатель за фильтрами и перед любыми ответвлёнными отводами. (NFPA 90A)"},
  {id:371, q:"Канальные дымовые извещатели сертифицированы для работы в заданном диапазоне скорости воздуха в канале, обычно указываемом приблизительно как:", opts:["0 до 50 fpm","5,000 до 10,000 fpm","100 до 4,000 fpm (проверять сертификацию каждого устройства)","Ограничения по скорости не применяются"], re:"Сертифицированные канальные извещатели работают в номинальном диапазоне скоростей (обычно ~100-4,000 fpm); устройство должно применяться в пределах своей сертификации. (Сертификации; NFPA 72-2022, 17.7.5)"},
  {id:372, q:"Когда ЕДИНСТВЕННАЯ функция канального дымового извещателя - отключение вентилятора, NFPA 90A разрешает что из следующего в отношении резервного питания?", opts:["Он всегда должен иметь 24 h резерва, как FACU","Он может быть без вторичного (аккумуляторного) питания, когда его единственная функция - отключение вентилятора HVAC","Он должен работать 15 min в режиме тревоги","Он должен запитываться от контроллера лифта"], re:"NFPA 90A разрешает канальному извещателю не иметь резервного питания только когда его единственная функция - отключение вентилятора. (NFPA 90A)"},
  {id:373, q:"Магнитный держатель двери удерживает открытой самозакрывающуюся противопожарную/противодымную дверь. В нормальном состоянии (без тревоги) держатель:", opts:["Обесточен","Импульсируется раз в час","Запитан только во время тестирования","Постоянно запитан, чтобы удерживать дверь открытой"], re:"Держатели дверей запитаны постоянно, чтобы удерживать двери открытыми; при тревоге или потере питания они обесточиваются, и дверь закрывается. (NFPA 72, гл.21; NFPA 80)"},
  {id:374, q:"Комбинированный противопожарный/противодымный клапан, управляемый системой пожарной сигнализации, при тревоге будет:", opts:["Полностью открываться для увеличения расхода воздуха","Оставаться в своём последнем положении","Вибрировать для очистки от мусора","Закрываться, чтобы заблокировать прохождение дыма/огня через проход канала"], re:"При тревоге FACU подаёт клапану сигнал закрыться, сохраняя нормированный барьер в проходе канала. (NFPA 72-2022, 21.6; NFPA 90A; NFPA 80/105)"},
  {id:375, q:"Активация канального дымового извещателя должна вызывать какую реакцию согласно NFPA 72 и NFPA 90A?", opts:["Как минимум индицируемый сигнал на FACU (контрольный или тревожный, где требуется) и отключение вентилятора","Индикация не требуется","Только зелёный индикатор 'норма'","Только освобождение держателя двери"], re:"Активация канального извещателя индицируется (обычно контрольный, или тревожный, где норма/AHJ требует) и инициирует отключение вентилятора. (NFPA 72-2022, 17.7.5; 21.7)"},
  {id:376, q:"Почему канальные дымовые извещатели НЕ являются заменой обнаружения дыма по площади (точечного) в открытом пространстве?", opts:["Дым может не достичь канала, а вентилятор может быть выключен, поэтому пожар в помещении может остаться необнаруженным","Они намного чувствительнее точечных извещателей","Они дороже в установке","Их нельзя контролировать электрически"], re:"Канальные извещатели отбирают пробы только движущегося воздуха в канале; при выключенном вентиляторе или если дым не поступает в обратку, пожар в помещении может остаться необнаруженным. (NFPA 72-2022, 17.7.5.1; NFPA 90A)"},
  {id:377, q:"Когда система пожарной сигнализации отключает воздухообработчик при тревоге, цель состоит в том, чтобы:", opts:["Остановить механическое перемещение/распространение дыма по зданию","Увеличить забор свежего воздуха","Охладить огонь","Создать подпор в помещении пожара"], re:"Отключение вентилятора останавливает распространение дыма по каналам в другие зоны. (NFPA 90A; NFPA 72-2022, 21.7)"},
  {id:378, q:"Удалённая станция тестирования / принадлежность для канального дымового извещателя обычно обеспечивает:", opts:["Способ перезарядить аккумулятор системы","Дополнительную громкость оповещения","Питание для приведения в действие клапанов","Удалённые светодиоды тревоги/неисправности и сброс/тест с ключом для датчика внутри канала"], re:"Удалённые станции тестирования выводят светодиоды состояния и тест/сброс для канального извещателя, смонтированного в недоступном канале. (Сертификации; NFPA 72-2022, 17.7.5)"},
  {id:379, q:"Для инженерных систем дымоудаления NFPA 72 согласуется с каким стандартом, определяющим проектирование и работу дымоудаления?", opts:["NFPA 13","NFPA 25","NFPA 92","NFPA 1221"], re:"NFPA 92 (Системы дымоудаления) определяет проектирование/работу; NFPA 72, гл.21, охватывает интерфейс и контроль пожарной сигнализации. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:380, q:"Система магнитного удержания/закрывания дверей, являющаяся частью системы пожарной сигнализации, должна освобождать двери при:", opts:["Только ручной команде с панели","Активации системы пожарной сигнализации (например, обнаружение дыма по площади) или потере питания","Только сигнале протока воды спринклера","Только сигнале возврата лифта"], re:"Устройства удержания освобождаются при срабатывании пожарной сигнализации (обычно местное обнаружение дыма) и при потере питания, позволяя дверям самозакрыться. (NFPA 72, гл.21; NFPA 80)"},
  {id:381, q:"Выделенные дымовые извещатели, освобождающие устройства удержания дверей открытыми, являются примером обнаружения, используемого для:", opts:["Функции противопожарного управления (управления) - освобождение двери - интегрированной с FACU","Только общей эвакуации здания","Управления энергопотреблением","Замены канальных извещателей"], re:"Обнаружение для освобождения двери - это функция управления по главе 21, контролируемая FACU. (NFPA 72-2022, гл.21; NFPA 80)"},
  {id:382, q:"В инженерной системе дымоудаления приведение в действие оборудования HVAC системой пожарной сигнализации должно быть согласовано так, чтобы:", opts:["Все вентиляторы просто выключались","Нужные зоны создавали подпор/вытяжку согласно последовательности дымоудаления (которая может оставлять некоторые вентиляторы ВКЛЮЧЁННЫМИ)","Двери запирали людей внутри","Лифты ускорялись"], re:"Инженерное дымоудаление может оставлять вентиляторы работающими для подпора/вытяжки; тревожные зоны должны соответствовать последовательности дымоудаления. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:383, q:"Соединительная проводка от FACU к приводу противодымного клапана рассматривается как какой тип цепи?", opts:["Цепь оповещателей","Цепь функции аварийного управления (контролируемая по гл.21 или реле в пределах 3 ft)","Только ответвлённая цепь держателя двери","Контрольная цепь спринклеров"], re:"Управление клапаном - это функция аварийного управления; её интерфейс следует правилам целостности главы 21. (NFPA 72-2022, 21.2 / 21.6)"},
  {id:384, q:"Если канальный дымовой извещатель также служит для инициации эвакуации здания (а не только отключения вентилятора), то он требует:", opts:["Никакого резервного питания вообще","Только местного звукового устройства","Вторичного (резервного) питания, как другие устройства запуска тревоги","Подключения к контроллеру лифта"], re:"Как только канальный извещатель выполняет роль запуска тревоги сверх отключения вентилятора, он должен иметь вторичное питание согласно NFPA 72. (NFPA 72-2022, 10.6; NFPA 90A)"},
  {id:385, q:"Извещатель протока воды в спринклерной системе с заполненными трубопроводами, обнаруживающий проток, генерирует какой сигнал на приборе управления пожарной сигнализацией?", opts:["Сигнал тревоги","Контрольный сигнал","Только сигнал неисправности","Никакого сигнала"], re:"Проток воды указывает, что спринклер работает (состояние пожара), поэтому это сигнал тревоги. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:386, q:"Контрольный выключатель положения/вскрытия (tamper) запорной (задвижной) арматуры, обнаруживающий закрытую задвижку, генерирует какой сигнал?", opts:["Контрольный сигнал","Сигнал тревоги","Сигнал неисправности","Сигнал предтревоги"], re:"Контроль положения задвижки (нештатное положение задвижки) - это контрольный сигнал, предупреждающий, что система может быть нарушена. (NFPA 72-2022, 17.16; 17.12)"},
  {id:387, q:"Лопастной выключатель протока воды имеет встроенную задержку главным образом для того, чтобы:", opts:["Замедлить тревогу, чтобы люди могли эвакуироваться","Экономить энергию аккумулятора","Позволить запорной задвижке закрыться","Предотвратить ложные тревоги от скачков давления/гидроударов в подаче"], re:"Задержка поглощает кратковременные скачки, так что только устойчивый проток вызывает тревогу, снижая ложные тревоги. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:388, q:"Контрольный выключатель запорной задвижки спринклера должен инициировать сигнал, когда задвижка сместилась из полностью открытого положения не более чем на:", opts:["Половину своего хода","Только когда полностью закрыта","Одну пятую (около 20%) пути от полностью открытого","75% закрытия"], re:"NFPA 72 требует контрольный сигнал в пределах двух оборотов или одной пятой (около 20%) хода задвижки от полностью открытого. (NFPA 72-2022, 17.16.4)"},
  {id:389, q:"Устройство запуска по проётоку воды должно индицировать проток в течение скольких секунд при протоке, равном протоку одного наименьшего спринклера?", opts:["30 s","60 s","90 s","120 s"], re:"NFPA 13/72 допускают, чтобы устройство протока воды сработало в течение 90 s при таком протоке. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:390, q:"После активации устройства запуска по проётоку воды оповещатели должны сработать в течение скольких дополнительных секунд?", opts:["30 s","60 s","10 s","90 s"], re:"Оповещение должно последовать в течение 10 s после устройства запуска, так что общее время может приближаться к ~100 s. (NFPA 72-2022 / NFPA 13)"},
  {id:391, q:"В спринклерной системе с сухими трубопроводами низкое давление воздуха, которое могло бы вызвать нежелательное срабатывание клапана, контролируется и сообщается как какой сигнал?", opts:["Сигнал тревоги","Сигнал неисправности","Сигнал не требуется","Контрольный сигнал"], re:"Нештатное давление воздуха/воды в сухой системе/системе предварительного действия - это контрольное состояние. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:392, q:"Низкая температура в помещении, содержащем трубопроводы спринклеров с заполненными трубопроводами (риск замерзания), контролируется и сообщается как:", opts:["Сигнал тревоги","Сигнал неисправности","Контрольный сигнал","Сигнал оповещения"], re:"Контроль низкой температуры помещения, защищающий от замерзания, - это контрольный сигнал по NFPA 72. (NFPA 72-2022, 17.16)"},
  {id:393, q:"Выключатель протока воды по давлению на сигнальном клапане обнаруживает проток, измеряя:", opts:["Падение напряжения аккумулятора","Скорость воздуха в канале","Положение двери","Изменение/скачок давления воды в сигнальной линии при срабатывании клапана"], re:"Выключатели по давлению измеряют рост давления/проток в сигнальной линии, когда клапаны сигнального клапана открываются. (NFPA 13; NFPA 72-2022, 17.12)"},
  {id:394, q:"Согласно NFPA 72, задвижки, управляющие подачей воды, питанием насоса, уровнями в баках и давлением воздуха спринклерных систем, должны быть:", opts:["Оставлены без контроля","Контролироваться только в рабочее время","Проверяться ежегодно вместо контроля","Электрически контролироваться сертифицированным прибором управления пожарной сигнализацией"], re:"NFPA 72/13 требуют электрического контроля таких задвижек и состояний сертифицированной FACU. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:395, q:"Состояния, такие как работающий пожарный насос и статус его источника питания, контролируются и сообщаются (где требуется) как какой сигнал?", opts:["Только сигнал неисправности","Контрольный сигнал","Сигнал оповещения","Контроль не разрешён"], re:"Состояния пожарного насоса, такие как насос-работает и статус источника питания, - это контрольные сигналы. (NFPA 72-2022, 17.16; NFPA 20)"},
  {id:396, q:"Срабатывание (агент выпущен) системы пожаротушения чистым агентом или CO2 сообщается системе пожарной сигнализации как:", opts:["Контрольный сигнал","Сигнал тревоги (тревога выпуска/выброса)","Сигнал неисправности","Никакого сигнала"], re:"Выброс/выпуск агента пожаротушения - это состояние тревоги; система выпуска взаимодействует с FACU. (NFPA 72-2022, гл.23; NFPA 2001/12)"},
  {id:397, q:"Потеря целостности контроля (обрыв или замыкание на землю) в контрольной цепи спринклеров приводит к:", opts:["Сигналу тревоги","Контрольному сигналу","Сигналу неисправности","Активации спринклеров"], re:"Неисправность проводки/целостности - это сигнал неисправности, отличный от самого контрольного сигнала (задвижка/давление). (NFPA 72-2022, 10.15; 17.16)"},
  {id:398, q:"Что из следующего правильно сопоставляет событие, связанное со спринклерами, с его типом сигнала по NFPA 72?", opts:["Проток воды = контрольный; задвижка закрыта = тревога","Проток воды = тревога; задвижка закрыта = контрольный","И проток воды, и закрытие задвижки = неисправность","И проток воды, и закрытие задвижки = контрольный"], re:"Проток воды - это тревога (вода течёт = пожар); закрытая/вскрытая задвижка - это контрольный (система, возможно, нарушена). (NFPA 72-2022, 17.12 / 17.16)"},
  {id:399, q:"Спринклерная система предварительного действия обычно приводится в действие:", opts:["Только протоком воды","Выключателем вскрытия (tamper)","Держателем двери","Независимым пожарным обнаружением (дым/тепло), открывающим клапан предварительного действия, после чего спринклерные оросители управляют водой"], re:"Системы предварительного действия используют обнаружение FACU для открытия клапана, заполняя трубопроводы; затем оросители выпускают воду. Обнаружение взаимодействует с FACU. (NFPA 72-2022, гл.23; NFPA 13)"},
  {id:400, q:"Основная причина, по которой контроль положения задвижки (tamper) является контрольным, а проток воды - тревогой, состоит в том, что:", opts:["Вскрытие опаснее пожара","Закрытая задвижка лишь предупреждает о возможном нарушении, тогда как проток воды указывает на реальный пожар/выброс, требующий эвакуации","Оба должны одинаково включать эвакуацию","Проток воды менее срочен, чем вскрытие"], re:"Контрольный сигнал предупреждает персонал о состоянии, влияющем на надёжность (задвижка закрыта); тревога сигнализирует о реальном событии пожара (проток). (NFPA 72-2022, определения; 17.12/17.16)"},
  {id:401, q:"Каково официальное название NFPA 72?", opts:["Национальный кодекс пожарной сигнализации и оповещения","Национальный электротехнический кодекс","Кодекс безопасности жизни","Стандарт для переносных огнетушителей"], re:"NFPA 72 — это Национальный кодекс пожарной сигнализации и оповещения; он регулирует применение, монтаж, размещение, рабочие характеристики, осмотр, испытание и обслуживание систем пожарной сигнализации и оповещения. Источник: титульный лист NFPA 72."},
  {id:402, q:"Согласно NFPA 72, кто имеет полномочия предоставлять эквивалентности и утверждать альтернативные решения, прямо не описанные в Кодексе?", opts:["Орган, обладающий юрисдикцией (AHJ)","Монтажник системы","Изготовитель оборудования","Владелец здания"], re:"Глава 1 NFPA 72 возлагает утверждение оборудования, материалов и альтернативных/эквивалентных решений на орган, обладающий юрисдикцией (AHJ). Источник: NFPA 72, администрирование Главы 1 (положения об Утверждении / Эквивалентности)."},
  {id:403, q:"В NFPA 72 термин 'shall' (должен) указывает на что?", opts:["Обязательное требование","Только рекомендацию","Разрешающую опцию","Пояснительное примечание"], re:"Согласно Руководству по стилю NFPA, принятому в NFPA 72, 'shall' (должен) обозначает обязательное требование, тогда как 'should' (следует) указывает на рекомендацию. Источник: соглашение об обязательном/рекомендательном языке NFPA 72."},
  {id:404, q:"Материал в Приложении NFPA 72 (например, в Приложении A) является каким из следующего?", opts:["Пояснительным/информационным, не частью требований","Обязательным и подлежащим исполнению","Отдельным стандартом","Применимым только к жилым системам"], re:"Приложения в документах NFPA не являются частью подлежащих исполнению требований; они являются информационными/пояснительными, если только специально не приняты. Источник: обозначение материала приложения NFPA 72."},
  {id:405, q:"NFPA 72 определяет какой тип системы как установленную внутри или на сооружении для защиты сооружения и его обитателей?", opts:["Система пожарной сигнализации защищаемого объекта (локальная)","Система публичного оповещения о чрезвычайных ситуациях","Система массового оповещения большой территории","Система обслуживания систем пожаротушения"], re:"Система пожарной сигнализации защищаемого объекта (локальная) устанавливается на защищаемом объекте для обеспечения обнаружения, оповещения и управления для этого объекта. Источник: определения NFPA 72 / Глава о системах защищаемого объекта."},
  {id:406, q:"На какой документ ссылается NFPA 72 в отношении символов, используемых на монтажных чертежах пожарной сигнализации, если иные символы не приемлемы для AHJ?", opts:["NFPA 170","NFPA 13","NFPA 101","статья 760 NEC"], re:"NFPA 72 требует, чтобы на чертежах пожарной сигнализации использовались символы NFPA 170, Стандарта по символам пожарной безопасности и чрезвычайных ситуаций, если иные символы не приемлемы для AHJ. Источник: NFPA 170, на который ссылается NFPA 72."},
  {id:407, q:"Согласно NFPA 72, максимальное время отклика для передачи сигнала тревоги за пределы объекта на станцию надзора обычно составляет сколько секунд?", opts:["10 секунд","30 секунд","90 секунд","180 секунд"], re:"NFPA 72 ограничивает время от инициирования до получения тревоги на станции надзора до 90 секунд. Источник: требования к таймингу связи со станцией надзора NFPA 72."},
  {id:408, q:"Вторичный (резервный) источник питания для системы пожарной сигнализации защищаемого объекта должен быть способен поддерживать работу системы под нормальной нагрузкой не менее какого времени?", opts:["4 часа","12 часов","24 часа","72 часа"], re:"NFPA 72 требует, чтобы вторичный источник питания поддерживал систему в нормальном (дежурном) состоянии в течение 24 часов, а затем питал требуемую нагрузку оповещения (обычно 5 или 15 минут). Источник: требования к источнику питания NFPA 72."},
  {id:409, q:"После 24 часов на вторичном питании система пожарной сигнализации в типичном защищаемом объекте должна быть способна питать нагрузку оповещения о тревоге не менее какого времени?", opts:["5 минут","15 минут","30 минут","60 минут"], re:"NFPA 72 требует, чтобы вторичный источник нёс нагрузку оповещения о тревоге в течение 5 минут после 24-часового дежурного периода (массовое оповещение внутри здания использует 15 минут). Источник: ёмкость вторичного питания NFPA 72."},
  {id:410, q:"Сигнал неисправности (trouble) в системе пожарной сигнализации указывает на какое состояние?", opts:["Подтверждённый пожар","Срабатывание реле потока воды спринклера","Неисправность, такую как обрыв или замыкание на землю в контролируемой проводке","Нормальное надзорное состояние"], re:"Сигнал неисправности указывает на неисправность (обрыв, замыкание на землю, потеря питания и т. д.) в системе, которая может ухудшить её работу; он отличается от сигналов тревоги и надзора. Источник: определения сигналов NFPA 72."},
  {id:411, q:"Надзорный сигнал в системе пожарной сигнализации чаще всего указывает на что?", opts:["Пожарное состояние, требующее эвакуации","Обрыв цепи в проводке инициирующего устройства","Ненормальное состояние системы противопожарной защиты или её компонентов (например, закрытая задвижка)","Разряженный резервный аккумулятор"], re:"Надзорный сигнал указывает на ненормальное состояние обхода охраны, системы пожаротушения или иного защитного элемента, находящегося под контролем (например, датчика вскрытия на контрольной задвижке). Источник: определения сигналов NFPA 72."},
  {id:412, q:"Согласно NFPA 72, уровень слышимости сигнала эвакуации в публичном режиме должен быть не менее скольких дБА выше среднего уровня окружающего шума?", opts:["5 дБА","10 дБА","15 дБА","20 дБА"], re:"Звуковые оповещатели публичного режима должны выдавать не менее 15 дБА выше среднего уровня окружающего шума или 5 дБА выше максимального уровня звука длительностью 60 секунд, в зависимости от того, что больше. Источник: требования к слышимости NFPA 72."},
  {id:413, q:"Стандартный временной паттерн, используемый для сигналов пожарной эвакуации согласно NFPA 72, называется как?", opts:["Временной код 3 (Temporal-Three)","Непрерывный тон","Маршевый темп","Кодированный импульс"], re:"NFPA 72 устанавливает звуковой паттерн Temporal-Three (Временной код 3) для пожарной эвакуации: три импульса с последующей паузой, повторяющиеся. Источник: паттерн сигнала эвакуации NFPA 72."},
  {id:414, q:"Какой тип сигнала должен иметь приоритет и подавлять все остальные сигналы на блоке управления пожарной сигнализацией?", opts:["Надзорный сигнал","Сигнал неисправности","Сигнал тревоги","Сигнал испытания"], re:"NFPA 72 устанавливает, что сигналы тревоги получают наивысший приоритет; блок управления должен отдавать предпочтение сигналу пожарной тревоги перед надзорным и сигналом неисправности. Источник: требования к приоритету сигналов NFPA 72."},
  {id:415, q:"Согласно NFPA 72, квалифицированный персонал систем пожарной сигнализации должен подтверждать свою компетентность каким способом?", opts:["Только устным заявлением об опыте","Членством в профсоюзе","Признанной сертификацией, лицензией, регистрацией или заводским обучением, приемлемым для AHJ","Владением испытательным оборудованием"], re:"NFPA 72 требует, чтобы обслуживающий персонал был квалифицирован, что подтверждается сертификацией (например, NICET), лицензией/регистрацией или обучением изготовителя, приемлемым для AHJ. Источник: требования к квалификации персонала NFPA 72."},
  {id:416, q:"Когда новое оборудование пожарной сигнализации добавляется к существующей системе, NFPA 72 требует какой вид испытания затронутых функций?", opts:["Никакого испытания, если панель не изменена","Полную замену системы","Повторное приёмочное испытание изменённых частей и затронутых интерфейсов","Только визуальный осмотр"], re:"NFPA 72 требует повторного приёмочного испытания всякий раз, когда система изменяется, чтобы проверить изменения и убедиться, что другие части/интерфейсы не были затронуты неблагоприятно. Источник: повторное приёмочное испытание Главы 14 NFPA 72."},
  {id:417, q:"NFPA 72 требует, чтобы уровень звукового сигнала в частном режиме был не менее скольких дБА выше среднего уровня окружающего шума в месте нахождения слушающей стороны?", opts:["6 дБА","10 дБА","15 дБА","20 дБА"], re:"Звуковые оповещатели частного режима должны обеспечивать не менее 6 дБА выше среднего окружающего уровня или 5 дБА выше максимального уровня звука длительностью 60 секунд, в зависимости от того, что больше. Источник: требования к слышимости в частном режиме NFPA 72."},
  {id:418, q:"На гладком потолке номинальное (максимальное) расстояние между точечными дымовыми извещателями согласно NFPA 72 составляет какое значение?", opts:["20 ft","40 ft","30 ft","50 ft"], re:"NFPA 72 устанавливает номинальное расстояние 30 ft (9,1 м) для точечных дымовых извещателей на гладких потолках, причём извещатели располагаются в пределах половины этого расстояния от стен. Источник: расстановка дымовых извещателей Гл. 17 NFPA 72."},
  {id:419, q:"На гладком потолке точечный дымовой извещатель должен располагаться в пределах какого расстояния, измеренного под прямым углом от всех стен или перегородок?", opts:["Четверть номинального шага","Полный номинальный шаг","Половина номинального шага","Двойной номинальный шаг"], re:"NFPA 72 требует, чтобы извещатели располагались в пределах половины номинального шага (то есть в пределах 15 ft для номинала 30 ft) от стен, измеренного под прямым углом. Источник: расстановка на гладком потолке Гл. 17 NFPA 72."},
  {id:420, q:"'Правило точки 0,7' для расстановки извещателей требует, чтобы все точки потолка находились в пределах какого расстояния от извещателя?", opts:["0,5 от указанного в перечне/номинального шага","1,0 от указанного в перечне/номинального шага","0,9 от указанного в перечне/номинального шага","0,7 от указанного в перечне/номинального шага"], re:"Правило 0,7S требует, чтобы каждая точка потолка находилась в пределах 0,7 номинального/указанного в перечне шага от извещателя при использовании нестандартных (например, нерегулярных) расстановок. Источник: Гл. 17 NFPA 72 (метод расстановки 0,7S)."},
  {id:421, q:"Для точечного дымового извещателя, установленного на потолке, NFPA 72 требует минимального зазора от любой стены не менее какого значения?", opts:["1 inch","36 inches","12 inches","4 inches"], re:"NFPA 72 требует, чтобы точечные дымовые извещатели, установленные на потолке, располагались на расстоянии не менее 4 in. (100 мм) от любой стены, чтобы избежать зоны застойного воздуха в стыке потолок-стена. Источник: размещение Гл. 17 NFPA 72."},
  {id:422, q:"Точечный дымовой извещатель, установленный на стене (боковой), должен иметь свою верхнюю часть расположенной в пределах какой зоны, измеренной вниз от потолка?", opts:["В пределах верхних 4 in.","В любом месте на стене","Между 12 in. и 24 in. вниз","Между 4 in. и 12 in. вниз"], re:"NFPA 72 допускает дымовые извещатели, установленные на боковой стене, с верхней частью извещателя между 4 in. и 12 in. (100 мм и 300 мм) вниз от потолка. Источник: размещение Гл. 17 NFPA 72."},
  {id:423, q:"Требует ли высота потолка сама по себе уменьшения шага ДЫМОВЫХ извещателей согласно NFPA 72?", opts:["Да, применяется та же таблица, что и для тепловых извещателей","Да, шаг удваивается выше 20 ft","Да, шаг уменьшается вдвое выше 10 ft","Нет, номинальный шаг дымовых извещателей не уменьшается только из-за высоты потолка (в пределах указанных лимитов)"], re:"В отличие от тепловых извещателей, NFPA 72 не требует уменьшения шага дымовых извещателей, основанного только на увеличении высоты потолка (другие факторы, такие как балки, воздушный поток и стратификация, по-прежнему применяются). Источник: Гл. 17 NFPA 72."},
  {id:424, q:"Для ТЕПЛОВЫХ извещателей по мере увеличения высоты потолка NFPA 72 требует корректировать шаг с использованием какого метода?", opts:["Корректировка никогда не требуется","Использования шага дымовых извещателей вместо этого","Удвоения указанного в перечне шага","Поправочного коэффициента по высоте (множителя) из таблицы шага тепловых извещателей"], re:"NFPA 72 требует, чтобы указанный в перечне шаг тепловых извещателей умножался на коэффициент уменьшения, который снижается по мере увеличения высоты потолка (согласно таблице высоты потолка для тепловых извещателей). Источник: таблица шага тепловых извещателей Гл. 17 NFPA 72."},
  {id:425, q:"Глубина балки становится фактором при расстановке дымовых извещателей на ровном потолке, когда глубина балки превышает какую долю высоты потолка?", opts:["5% (0,05H)","40% (0,40H)","25% (0,25H)","10% (0,10H)"], re:"Когда глубина балки составляет 10% или более от высоты потолка (>0,1H), балки влияют на шаг; балки мельче 10% от высоты потолка допускают шаг как для гладкого потолка. Источник: правила потолков с балками Гл. 17 NFPA 72."},
  {id:426, q:"Для потолка с балками, где глубина балки составляет не менее 10% высоты потолка И шаг балок составляет не менее 40% высоты потолка, NFPA 72 требует, чтобы дымовые извещатели располагались где?", opts:["Только на нижней части балок","С полным номинальным шагом 30 ft","Только в центре помещения","В каждом межбалочном кармане"], re:"Когда балки глубокие (>=0,1H) и широко расставлены (>=0,4H), каждый межбалочный карман рассматривается как отдельная зона, поэтому извещатель требуется в каждом межбалочном кармане. Источник: правила потолков с балками Гл. 17 NFPA 72."},
  {id:427, q:"Для потолка с балками, где глубина балки составляет не менее 10% высоты потолка, но шаг балок МЕНЬШЕ 40% высоты потолка, шаг дымовых извещателей перпендикулярно балкам уменьшается до чего?", opts:["Без уменьшения","Двойного шага для гладкого потолка","Четверти шага для гладкого потолка","Половины шага для гладкого потолка"], re:"Когда балки глубокие, но близко расставлены (<0,4H), шаг, измеренный перпендикулярно (под прямым углом) балкам, уменьшается до половины значения для гладкого потолка. Источник: правила потолков с балками Гл. 17 NFPA 72."},
  {id:428, q:"На наклонном (двускатном) потолке с уклоном более 1 к 8 первый ряд извещателей должен располагаться где?", opts:["В самой низкой точке уклона","Только на карнизах","По центру каждой стены","На коньке (высшей точке) или в пределах 36 in. от него"], re:"NFPA 72 требует ряд извещателей на коньке или в пределах 36 in. (910 мм) от конька наклонного/двускатного потолка, измеренного горизонтально от конька. Источник: размещение на наклонном потолке Гл. 17 NFPA 72."},
  {id:429, q:"NFPA 72 (рекомендации Приложения A) рекомендует, чтобы точечные дымовые извещатели не располагались ближе какого расстояния к диффузору подачи воздуха?", opts:["12 in.","24 in.","36 in.","60 in."], re:"Приложение A NFPA 72 рекомендует держать точечные дымовые извещатели вне прямого воздушного потока и не ближе 36 in. (910 мм) от диффузора подачи воздуха, чтобы избежать разбавления дыма. Источник: NFPA 72 Приложение A.17.7.4."},
  {id:430, q:"Тепловой извещатель скорости нарастания (rate-of-rise) предназначен для срабатывания, когда температура воздуха нарастает быстрее, чем приблизительно с какой скоростью?", opts:["5 deg F в минуту","10 deg F в минуту","15 deg F в минуту","50 deg F в минуту"], re:"Тепловые извещатели скорости нарастания обычно реагируют, когда температура повышается примерно на 15 deg F (8,3 deg C) или более в минуту. Источник: описания тепловых извещателей Гл. 17 NFPA 72 / перечни извещателей."},
  {id:431, q:"Комбинированный тепловой извещатель фиксированной температуры/скорости нарастания обеспечивает преимущество какого поведения?", opts:["Он полностью игнорирует медленное нарастание температуры","Он обнаруживает дым, а не тепло","Он работает только выше 200 deg F","Он реагирует на быстрое нарастание температуры И на фиксированную максимальную температуру"], re:"Комбинированные извещатели срабатывают при быстрой скорости нарастания, а также при достижении установленной фиксированной температуры, охватывая как быстро, так и медленно развивающиеся пожары. Источник: типы тепловых извещателей Гл. 17 NFPA 72."},
  {id:432, q:"Для ровного потолка высотой 12 ft или менее балка, выступающая менее чем на 4 in. (менее 10% высоты потолка), рассматривается как при расстановке дымовых извещателей?", opts:["Требует извещателей в каждом кармане","Запрещает извещатели, установленные на потолке","Требует четверти шага","Как гладкий потолок (без уменьшения шага)"], re:"Мелкая балка (<10% высоты потолка, например, <~4 in. на потолке 12 ft) не влияет на шаг дымовых извещателей; потолок рассматривается как гладкий. Источник: правила потолков с балками Гл. 17 NFPA 72."},
  {id:433, q:"Какова основная цель канального дымового извещателя, установленного в системе HVAC?", opts:["Служить основным площадным обнаружением дыма в здании","Заменять площадные тепловые извещатели","Измерять только температуру воздуха","Обнаруживать дым в воздушном потоке и отключать воздухообрабатывающий агрегат для ограничения распространения дыма"], re:"Канальные дымовые извещатели NFPA 72 / NFPA 90A обнаруживают дым в приточном/вытяжном воздухе и инициируют отключение вентилятора или управление заслонками; они не заменяют требуемое площадное (открытое) обнаружение. Источник: Гл. 17 NFPA 72 и NFPA 90A."},
  {id:434, q:"При использовании поправки по высоте потолка для тепловых извещателей NFPA 72 обычно ограничивает уменьшенный шаг так, чтобы он был не менее какой доли высоты потолка?", opts:["0,2 высоты потолка","1,0 высоты потолка","0,7 высоты потолка","0,4 высоты потолка"], re:"После применения поправки по высоте шаг тепловых извещателей не нужно уменьшать ниже 0,4 высоты потолка согласно рекомендациям NFPA 72. Источник: положения о поправке по высоте для тепловых извещателей Гл. 17 NFPA 72."},
  {id:435, q:"Стояковая схема (riser diagram) пожарной сигнализации в первую очередь показывает какое из следующего?", opts:["Точное физическое местоположение каждого устройства на этаже","Архитектурный план отражённого потолка","Только спецификацию электрической панели","Вертикальную компоновку системы и взаимосвязь цепей/устройств между этажами"], re:"Стояковая схема — это схематическое изображение, показывающее вертикальную компоновку системы: блок управления, цепи, устройства и взаимосвязи между этажами/зонами (не точное физическое размещение). Источник: требования к документации / монтажным чертежам NFPA 72."},
  {id:436, q:"Какой документ заполняется и предоставляется во время приёмки системы для подтверждения того, что установка соответствует утверждённым чертежам и NFPA 72?", opts:["Акт о завершении (Record of Completion)","Разрешение на строительство","Архитектурный поэтажный план","Технический паспорт изготовителя"], re:"Акт о завершении NFPA 72 оформляется при приёмке для документирования того, что система была смонтирована и испытана согласно утверждённому проекту и Кодексу. Источник: документация Гл. 7 NFPA 72."},
  {id:437, q:"Матрица 'последовательности работы' (вход/выход) в документации пожарной сигнализации описывает что?", opts:["Цвета используемых проводов","Спецификацию заполнения кабелепровода","Только расчёт аккумулятора","Причинно-следственную связь между входами (инициирующими событиями) и выходами (откликами системы)"], re:"Последовательность работы (причина-следствие / матрица вход-выход) определяет, что делает каждый вход и какие выходы получаются в результате, и является требуемой документацией для проектирования и испытаний. Источник: документация Гл. 7 NFPA 72."},
  {id:438, q:"Исполнительные чертежи 'as-built' (учётные), предоставляемые после монтажа, должны отражать что?", opts:["Только первоначальный замысел проекта","Типовую каталожную компоновку изготовителя","Только будущее расширение","Систему в том виде, как она фактически смонтирована, включая изменения на месте"], re:"Исполнительные/учётные чертежи документируют систему в том виде, как она фактически смонтирована, включая все изменения на месте, и должны предоставляться владельцу. Источник: требования к документации Гл. 7 NFPA 72."},
  {id:439, q:"Расчёты аккумулятора (резервного питания), подаваемые вместе с чертежами пожарной сигнализации, используются для проверки чего?", opts:["Размера кабелепровода","Расстановки извещателей","Слышимости в дБА","Того, что вторичный источник может нести дежурную нагрузку в течение требуемых часов плюс нагрузку тревоги"], re:"Расчёты аккумулятора показывают, что вторичный источник питания может поддерживать дежурную нагрузку в течение требуемого дежурного периода (например, 24 ч), а затем нагрузку тревоги (например, 5 мин). Источник: источник питания / документация NFPA 72."},
  {id:440, q:"Расчёты падения напряжения для цепи устройств оповещения обеспечивают что?", opts:["Что извещатели расставлены на расстоянии 30 ft друг от друга","Что кабель пригоден для пленума","Что у панели есть аккумулятор","Что последнее устройство в цепи по-прежнему получает не менее своего указанного в перечне минимального рабочего напряжения"], re:"Расчёты падения напряжения подтверждают, что устройство в конце линии получает не менее своего минимального рабочего напряжения, указанного в перечне UL, при наихудших условиях. Источник: практика проектирования / документации NAC NFPA 72."},
  {id:441, q:"На чертежах пожарной сигнализации сплошной треугольник или аналогичный набор стандартизированных символов вычерчивается из какого источника?", opts:["Символы спринклеров NFPA 13","Символы воздуховодов ASHRAE","Символы кабельных каналов NEC","Символы пожарной безопасности NFPA 170"], re:"Символы устройств пожарной сигнализации на чертежах следуют NFPA 170, Стандарту по символам пожарной безопасности и чрезвычайных ситуаций, если иные символы не приняты AHJ. Источник: NFPA 170, на который ссылается NFPA 72."},
  {id:442, q:"Какой элемент обычно НЕ является частью полного комплекта монтажных чертежей пожарной сигнализации?", opts:["Поэтажные планы, показывающие расположение устройств","Стояковая схема","Последовательность работы","Оценка налога на имущество здания"], re:"Комплекты включают поэтажные планы, стояковую схему, последовательность работы, поточечную проводку, расчёты аккумулятора/падения напряжения и технические листы; оценка налога не имеет отношения. Источник: документация Гл. 7 NFPA 72."},
  {id:443, q:"Поточечная схема проводки используется в первую очередь для отображения чего?", opts:["Точных клеммных соединений и полевой проводки между устройствами и блоком управления","Архитектурных фасадов","Прокладки воздуховодов HVAC","Кривой пожарного насоса"], re:"Поточечные схемы проводки показывают поклеммные соединения проводников между блоком управления, модулями и полевыми устройствами, поддерживая монтаж и поиск неисправностей. Источник: документация Гл. 7 NFPA 72."},
  {id:444, q:"Согласно NFPA 72, владелец должен хранить постоянную копию учётной документации в каком месте?", opts:["Только в офисе подрядчика","Только у изготовителя","Только у AHJ","На защищаемом объекте (например, в шкафу документации) или ином утверждённом месте"], re:"NFPA 72 требует, чтобы учётная (исполнительная) документация хранилась на протяжении срока службы системы на защищаемом объекте или в утверждённом месте, часто в шкафу документации у FACU. Источник: Гл. 7 NFPA 72."},
  {id:445, q:"Перед приёмочным испытанием NFPA 72 требует, чтобы монтажный подрядчик предоставил какую гарантию относительно установки?", opts:["Только устное подтверждение","Только гарантийный талон","Копию городского постановления","Заполненную/оформленную документацию, включая предварительное удостоверение перед испытанием того, что 100% системы было смонтировано и предварительно испытано"], re:"Монтажник предоставляет заполненную документацию и заявление о том, что система была смонтирована и испытана на 100% монтажником до приёмочного испытания (испытания AHJ). Источник: приёмочная документация Гл. 14 / Гл. 7 NFPA 72."},
  {id:446, q:"'Матрица операций' должна проверяться на соответствие чему во время приёмочного испытания?", opts:["Фактическому запрограммированному отклику системы для каждого входа","Цветовой схеме архитектора","Цвету окраски кабелепровода","Местоположению огнетушителей"], re:"Приёмочное испытание подтверждает, что смонтированная/запрограммированная причинно-следственная связь соответствует утверждённой последовательности работы (матрице). Источник: приёмочное испытание Гл. 14 NFPA 72."},
  {id:447, q:"Какой цвет требуется NFPA/NEC для идентификации разъединителя выделенной ответвлённой цепи, питающей блок управления пожарной сигнализацией?", opts:["Синий","Зелёный","Красный","Жёлтый"], re:"Идентификация в стиле NEC 760.121/695 требует, чтобы устройство защиты от сверхтока/разъединитель ответвлённой цепи пожарной сигнализации был помечен красным и маркирован 'ЦЕПЬ ПОЖАРНОЙ СИГНАЛИЗАЦИИ'. Источник: маркировка источника питания статьи 760 NEC."},
  {id:448, q:"Что представляет собой 'зона' на плане обычной системы пожарной сигнализации?", opts:["Один адрес устройства","Только прокладку кабелепровода","Аккумуляторный отсек","Определённую зону, обслуживаемую цепью, используемую для индикации общего местоположения события"], re:"Зона — это определённая зона здания (часто цепь), используемая для указания общего источника состояния тревоги/надзора/неисправности на индикаторной панели. Источник: требования к зонированию/индикации NFPA 72."},
  {id:449, q:"Для адресной системы идентичность каждого устройства на плане соответствует чему?", opts:["Уникальному адресу/точке, сообщаемому индивидуально блоку управления","Общей зоне без индивидуальной идентичности","Только проводному звонку","Клемме аккумулятора"], re:"Каждое адресное устройство сообщает уникальный адрес/точку, так что блок управления и планы идентифицируют местоположение конкретного устройства, а не только зону. Источник: работа адресной системы NFPA 72."},
  {id:450, q:"'Акт о завершении' пожарной сигнализации должен быть подписан какими сторонами?", opts:["Только владельцем здания","Только архитектором","Только поставщиком оборудования","Представителями монтажного подрядчика и владельца системы/AHJ в соответствующих случаях"], re:"Акт о завершении подписывается представителем монтажного подрядчика и представителем владельца (и AHJ, когда требуется) для удостоверения правильного монтажа. Источник: Акт о завершении Гл. 7 NFPA 72."},
  {id:451, q:"Руководства по эксплуатации и обслуживанию (O&M), передаваемые владельцу, должны включать что?", opts:["Только счёт-фактуру на продажу","Данные изготовителя, записи о программировании/конфигурации и инструкции по ITM для смонтированного оборудования","Резюме архитектора","Отчёт о балансировке HVAC"], re:"Передача O&M включает литературу изготовителя, записи о конфигурации/ПО в запрограммированном виде и инструкции по осмотру-испытанию-обслуживанию, чтобы владелец мог обслуживать систему. Источник: документация владельца Гл. 7 NFPA 72."},
  {id:452, q:"Приёмочное испытание новой системы пожарной сигнализации проверяет что?", opts:["Только то, что панель включается","Что вся смонтированная система работает согласно утверждённому проекту и NFPA 72 до ввода в эксплуатацию","Только напряжение аккумулятора","Нагрузку заполняемости здания"], re:"Приёмочное (первоначальное) испытание подтверждает, что 100% смонтированной системы функционирует в соответствии с утверждёнными чертежами, последовательностью работы и NFPA 72 до ввода в эксплуатацию. Источник: приёмочное испытание Гл. 14 NFPA 72."},
  {id:453, q:"Во время приёмочного испытания инициирующих устройств какой процент устройств должен быть испытан?", opts:["10%","25%","50%","100%"], re:"При первоначальной приёмке должно быть испытано 100% инициирующих устройств, устройств оповещения и функций. Источник: объём приёмочного испытания Гл. 14 NFPA 72."},
  {id:454, q:"Приёмочное испытание точечного дымового извещателя должно подтвердить поступление дыма с использованием чего?", opts:["Только магнита","Дыма или аэрозоля, указанного в перечне/одобренного для извещателя, поступающего в чувствительную камеру","Показания мультиметра","Только визуального осмотра"], re:"Дымовые извещатели должны испытываться дымом или указанным в перечне аэрозолем, который действительно поступает в чувствительную камеру для проверки отклика, а не просто магнитом (который проверяет только цепь тревоги/реле). Источник: методы испытания извещателей Гл. 14 NFPA 72."},
  {id:455, q:"Использование испытательного магнита на адресном дымовом извещателе во время приёмочного испытания в первую очередь проверяет что?", opts:["Что дым действительно поступает в камеру","Электронику/сигнализацию тревоги и адресацию извещателя, но НЕ поступление дыма","Дрейф чувствительности извещателя","Высоту потолка"], re:"Испытание магнитом проверяет сигнализацию тревоги/адресацию (функциональный отклик), но не подтверждает, что дым может поступать в камеру; поступление дыма/аэрозоля также должно быть проверено. Источник: методы испытания Гл. 14 NFPA 72."},
  {id:456, q:"Во время приёмки покрытие звуковых устройств оповещения проверяется путём измерения чего?", opts:["Только частоты в герцах","Уровня звукового давления (дБА) для подтверждения требуемой слышимости выше окружающего шума","Ампер-часов аккумулятора","Сопротивления проводника"], re:"Слышимость проверяется путём измерения уровня звукового давления (дБА) для подтверждения требуемого запаса выше окружающего шума (например, 15 дБА в публичном режиме). Источник: Гл. 14 NFPA 72 / требования к слышимости."},
  {id:457, q:"Приёмочное испытание стробоскопов (визуального оповещения) проверяет соответствие какому параметру перечня?", opts:["Номиналу в канделах (cd) и синхронизации, где требуется","Номиналу в децибелах","Химическому составу аккумулятора","Затемнению от дыма"], re:"Визуальные оповещатели проверяются на надлежащую выходную мощность/размещение в канделах и, где требуется, на синхронизацию для предотвращения частот вспышек, вызывающих судороги. Источник: Гл. 14 NFPA 72 и требования к визуальному оповещению."},
  {id:458, q:"В рамках приёмочного испытания целостность контролируемой цепи проверяется путём выполнения чего?", opts:["Окраски кабелепровода","Внесения неисправностей (обрыв, замыкание на землю) и подтверждения того, что панель сообщает правильное состояние неисправности","Постоянного отключения аккумулятора","Удаления всех извещателей"], re:"Надзор за цепью проверяется путём внесения неисправностей обрыва/замыкания на землю и подтверждения надлежащей индикации неисправности, демонстрируя контроль целостности. Источник: приёмочное испытание проводки Гл. 14 NFPA 72."},
  {id:459, q:"Во время приёмочного испытания вторичный источник питания испытывается путём выполнения чего?", opts:["Измерения окружающего освещения","Отключения первичного (переменного тока) питания и проверки того, что система работает на резервном питании в течение требуемой продолжительности","Замены панели","Подсчёта извещателей"], re:"Вторичное питание проверяется путём снятия первичного питания и подтверждения того, что система работает на аккумуляторе в течение дежурного периода, а затем несёт нагрузку тревоги. Источник: испытание источника питания Гл. 14 NFPA 72."},
  {id:460, q:"Приёмочное испытание должно проверить передачу сигнала за пределы объекта путём подтверждения чего?", opts:["Что станция надзора корректно получает сигналы тревоги, надзора и неисправности","Что звонок красный","Что аккумулятор заряжен до 12 V","Что извещатель находится на расстоянии 30 ft от стены"], re:"Там, где система передаёт сигналы за пределы объекта, приёмочное испытание подтверждает, что станция надзора корректно получает и идентифицирует сигналы тревоги, надзора и неисправности. Источник: Гл. 14 NFPA 72 / испытание станции надзора."},
  {id:461, q:"Во время приёмочного испытания системы экстренной речевой/тревожной связи (EVACS) разборчивость оценивается, чтобы обеспечить что?", opts:["Что громкость сообщения превышает 120 дБА повсюду","Что речевые сообщения понятны в акустически различимых пространствах","Что стробоскопы вспыхивают быстрее","Что аккумулятора хватает на 72 часа"], re:"Приёмка EVACS включает проверку разборчивости речи в требуемых акустически различимых пространствах, а не только громкости. Источник: требования к разборчивости Гл. 14 и Гл. 18 NFPA 72."},
  {id:462, q:"Кто обычно присутствует при окончательном приёмочном испытании системы пожарной сигнализации?", opts:["Орган, обладающий юрисдикцией (AHJ), и представитель владельца","Только подрядчик HVAC","Садовник","Никто не требуется"], re:"AHJ (и представитель владельца) обычно присутствует при приёмочном испытании для подтверждения соответствия кодексу до того, как система будет одобрена к эксплуатации. Источник: процесс приёмки Гл. 14 NFPA 72."},
  {id:463, q:"Когда инициирование пожарной тревоги вызывает отключение вентилятора HVAC, приёмочное испытание должно проверить что?", opts:["Что вентиляторы действительно отключаются (или выполняют запрограммированное действие) при правильном входе","Цвет воздуховода","Уставку термостата","Размер фильтра"], re:"Интерфейсные функции, такие как отключение вентилятора, закрытие заслонки, разблокировка дверей и возврат лифтов, должны проверяться на работу согласно последовательности работы во время приёмки. Источник: испытание интерфейсов Гл. 14 NFPA 72."},
  {id:464, q:"Для инициирования пожарной тревогой возврата лифтов (Фаза I) приёмочное испытание должно подтвердить что?", opts:["Лифты возвращаются на назначенный/альтернативный уровень при срабатывании правильного извещателя","Кабина лифта перекрашивается","Дымовой извещатель шахты удаляется","Вместимость кабины увеличивается"], re:"Приёмочное испытание проверяет возврат лифтов Фазы I на назначенный или альтернативный уровень при срабатывании надлежащего извещателя холла/машинного помещения/шахты согласно NFPA 72 и ASME A17.1. Источник: Гл. 21 / испытание интерфейсов Гл. 14 NFPA 72."},
  {id:465, q:"Приёмочное испытание инициирования тревоги по потоку воды от спринклерной системы проверяет что?", opts:["Реле потока воды инициирует тревогу в пределах разрешённого времени задержки","Цвет спринклерной трубы","Давление воды превышает 300 psi","Шаг извещателей составляет 30 ft"], re:"Реле потока воды должны инициировать тревогу не более чем через 90 секунд после начала потока (в пределах лимитов задержки); приёмка проверяет правильное инициирование и индикацию. Источник: Гл. 14 NFPA 72 / интерфейс с NFPA 13."},
  {id:466, q:"Если приёмочное испытание выявляет недостаток, каково надлежащее действие согласно NFPA 72?", opts:["Всё равно ввести систему в эксплуатацию","Задокументировать недостаток, устранить его и повторно испытать затронутую функцию до окончательного одобрения","Игнорировать незначительные недостатки","Навсегда удалить затронутые устройства"], re:"Недостатки, выявленные во время испытаний, должны быть задокументированы, устранены, а затронутые функции повторно испытаны до того, как система может быть принята/введена в эксплуатацию. Источник: обработка приёмки/недостатков Гл. 14 NFPA 72."},
  {id:467, q:"Повторное приёмочное испытание требуется после какого события?", opts:["Планового годового осмотра без изменений","Добавления, перемещения или изменения инициирующих устройств, устройств оповещения или программирования","Чистки внешней части панели","Изменения окраски стены рядом с устройством"], re:"Повторное приёмочное испытание требуется при добавлении, удалении, перемещении устройств/оповещателей или при изменении ПО/программирования, влияющего на работу, для подтверждения правильной работы и отсутствия неблагоприятного воздействия. Источник: повторная приёмка Гл. 14 NFPA 72."},
  {id:468, q:"Во время приёмки ручные пожарные извещатели (ручные пункты) испытываются путём выполнения чего?", opts:["Измерения только их высоты","Срабатывания каждого пункта и подтверждения правильного сигнала тревоги и идентификации","Окраски их в красный цвет","Снятия только крышки"], re:"Каждый ручной пожарный пункт срабатывает для проверки того, что он инициирует правильную тревогу и должным образом идентифицирован/индицирован. Источник: приёмочное испытание ручных пунктов Гл. 14 NFPA 72."},
  {id:469, q:"Согласно Главе 14 NFPA 72, точечные дымовые извещатели должны проходить функциональное испытание с какой минимальной периодичностью?", opts:["Ежемесячно","Ежеквартально","Ежегодно","Каждые 5 лет"], re:"Гл. 14 NFPA 72 требует функционального испытания дымовых извещателей не реже одного раза в год (в дополнение к полугодовому визуальному осмотру). Источник: NFPA 72 Таблица 14.4.3.2."},
  {id:470, q:"ЧУВСТВИТЕЛЬНОСТЬ дымовых извещателей должна быть впервые испытана в течение какого времени после монтажа, а затем с интервалом через год?", opts:["В течение 6 месяцев","В течение 1 года","В течение 2 лет","В течение 5 лет"], re:"NFPA 72 требует, чтобы чувствительность дымовых извещателей была испытана в течение 1 года после монтажа, затем через год; интервалы могут быть продлены до 5 лет, если результаты остаются в диапазоне. Источник: испытание чувствительности Гл. 14 NFPA 72."},
  {id:471, q:"После двух успешных испытаний чувствительности дымовых извещателей, показывающих значения в пределах указанного в перечне диапазона, интервал может быть продлён максимум до какого срока?", opts:["1 год","2 года","5 лет","10 лет"], re:"Если два последовательных испытания чувствительности находятся в пределах указанного в перечне/маркированного диапазона, NFPA 72 позволяет продлить интервал испытаний максимум до 5 лет. Источник: испытание чувствительности Гл. 14 NFPA 72."},
  {id:472, q:"Дымовой ИЗВЕЩАТЕЛЬ-СИГНАЛИЗАТОР одиночной или множественной станции должен быть заменён не позднее чем через сколько лет с даты изготовления (если изготовитель не указывает иное)?", opts:["5 лет","10 лет","15 лет","20 лет"], re:"NFPA 72 требует, чтобы дымовые извещатели-сигнализаторы заменялись в течение 10 лет с даты изготовления, если инструкции изготовителя не указывают иное. Источник: замена дымовых извещателей-сигнализаторов Гл. 14 NFPA 72."},
  {id:473, q:"Герметичные свинцово-кислотные (SLA) резервные аккумуляторы, используемые в системах пожарной сигнализации, должны заменяться с интервалами, не превышающими приблизительно какой срок?", opts:["1 год","4 года","10 лет","15 лет"], re:"NFPA 72 указывает, что герметичные свинцово-кислотные аккумуляторы заменяются, когда они достигают примерно 80% маркированной ёмкости, как правило, в течение ~4 лет; изготовители часто рекомендуют ~5 лет. Источник: обслуживание аккумуляторов Гл. 14 NFPA 72."},
  {id:474, q:"NFPA 72 требует нагрузочного (разрядного) испытания вторичного аккумулятора с какой минимальной периодичностью?", opts:["Еженедельно","Ежемесячно","Ежегодно","Каждые 5 лет"], re:"Гл. 14 NFPA 72 требует, чтобы аккумулятор подвергался нагрузочному/разрядному испытанию не реже одного раза в год для подтверждения того, что он может поддерживать работу системы. Источник: NFPA 72 Таблица 14.4.3.2 (аккумуляторные батареи)."},
  {id:475, q:"Инициирующие устройства и устройства оповещения обычно требуют ВИЗУАЛЬНОГО осмотра с какой минимальной периодичностью согласно NFPA 72?", opts:["Еженедельно","Ежемесячно","Каждые полгода","Каждые 5 лет"], re:"Таблица 14.3.1 NFPA 72 предусматривает полугодовой визуальный осмотр для большинства инициирующих устройств и устройств оповещения (физическое состояние/монтаж). Источник: NFPA 72 Таблица 14.3.1."},
  {id:476, q:"Устройства потока воды (например, реле потока воды) должны проходить функциональное испытание с какой минимальной периодичностью согласно NFPA 72?", opts:["Ежегодно","Каждые полгода","Ежеквартально","Каждые 5 лет"], re:"NFPA 72 требует функционального испытания устройств потока воды каждые полгода (а также надзорных устройств/датчиков вскрытия задвижек каждые полгода). Источник: Гл. 14 NFPA 72 (испытание устройств потока воды и надзорных устройств)."},
  {id:477, q:"Тепловой извещатель, который является восстанавливаемым (неразрушающего типа), проходит функциональное испытание с какой минимальной периодичностью?", opts:["Ежемесячно","Ежеквартально","Ежегодно","Каждые 10 лет"], re:"Восстанавливаемые тепловые извещатели проходят функциональное испытание теплом не реже одного раза в год; невосстанавливаемые типы не испытываются теплом, но проверяются/заменяются согласно программе. Источник: NFPA 72 Таблица 14.4.3.2 (тепловые извещатели)."},
  {id:478, q:"Какой тип теплового извещателя НЕ должен испытываться путём приложения тепла (чтобы избежать его разрушения)?", opts:["Пневматический скорости нарастания","Восстанавливаемый электронный фиксированной температуры","Невосстанавливаемый тип фиксированной температуры (плавкий/эвтектический)","Комбинированный электронный извещатель"], re:"Невосстанавливаемые извещатели фиксированной температуры (например, с плавкой вставкой/эвтектические) разрушаются при срабатывании, поэтому они не испытываются теплом; используются альтернативные методы или плановая замена. Источник: испытание тепловых извещателей Гл. 14 NFPA 72."},
  {id:479, q:"Сигналы неисправности блока управления должны испытываться с какой минимальной периодичностью согласно NFPA 72?", opts:["Ежегодно","Каждые 5 лет","Только при приёмке","Каждые 10 лет"], re:"NFPA 72 требует, чтобы функции блока управления, включая сигналы неисправности, испытывались не реже одного раза в год. Источник: NFPA 72 Таблица 14.4.3.2 (управляющее оборудование)."},
  {id:480, q:"Канальные дымовые извещатели должны испытываться для проверки чего в дополнение к отклику тревоги?", opts:["Что отбор проб воздуха/воздушный поток достаточен, чтобы дым мог достичь чувствительной камеры","Что воздуховод окрашен","Что вентилятор правильной марки","Что фильтр новый"], re:"Испытание канальных извещателей проверяет, что пробоотборная трубка/воздушный поток позволяет дыму поступать в чувствительную камеру и что устройство срабатывает и выполняет свою управляющую функцию (например, отключение вентилятора). Источник: испытание канальных извещателей Гл. 14 NFPA 72."},
  {id:481, q:"Записи об осмотре, испытании и обслуживании должны храниться не менее какого срока согласно NFPA 72?", opts:["6 месяцев","1 год (до следующего испытания) или как требует AHJ","Бессрочно без минимума","Только до следующего дня"], re:"NFPA 72 требует, чтобы записи ITM хранились не менее чем до следующего испытания/осмотра и в течение периода, приемлемого для AHJ (обычно один цикл испытаний или дольше). Источник: хранение записей Гл. 14 NFPA 72."},
  {id:482, q:"Перед отключением части системы пожарной сигнализации для обслуживания ('нарушение работоспособности') передовая практика NFPA 72 требует чего?", opts:["Уведомить AHJ/владельца и обеспечить пожарный надзор или иные утверждённые меры по мере необходимости","Ничего; просто отключить её","Снять все аккумуляторы","Отключить питание здания"], re:"Процедуры вывода из эксплуатации/нарушения работоспособности требуют уведомления владельца/AHJ и контроля/пожарного надзора или иных утверждённых мер, пока защита нарушена. Источник: положения о нарушении работоспособности Гл. 10/14 NFPA 72."},
  {id:483, q:"Ручные пожарные извещатели (ручные пункты) должны проходить функциональное испытание с какой минимальной периодичностью?", opts:["Еженедельно","Ежемесячно","Ежегодно","Каждые 10 лет"], re:"Таблица 14.4.3.2 NFPA 72 требует, чтобы ручные пожарные пункты проходили функциональное испытание не реже одного раза в год. Источник: испытание ручных пунктов Гл. 14 NFPA 72."},
  {id:484, q:"Звуковые и визуальные устройства оповещения должны проходить функциональное испытание с какой минимальной периодичностью?", opts:["Ежегодно","Каждые 5 лет","Только при приёмке","Каждые 10 лет"], re:"NFPA 72 требует, чтобы устройства оповещения (звуковые сигнализаторы, стробоскопы, громкоговорители) проходили функциональное испытание не реже одного раза в год. Источник: NFPA 72 Таблица 14.4.3.2 (устройства оповещения)."},
  {id:485, q:"Основная цель планового обслуживания (например, чистки) дымовых извещателей состоит в том, чтобы сделать что?", opts:["Изменить цвет устройства","Поддерживать извещатель в пределах его указанного в перечне диапазона чувствительности и снизить нежелательные тревоги","Увеличить выходную мощность в канделах","Удлинить кабелепровод"], re:"Чистка/обслуживание поддерживает работу извещателей в пределах их указанного в перечне диапазона чувствительности, сохраняя отклик и минимизируя ложные тревоги от загрязнения пылью. Источник: положения об обслуживании Гл. 14 NFPA 72."},
  {id:486, q:"Какая статья NEC конкретно охватывает монтаж проводки системы пожарной сигнализации?", opts:["Статья 250","Статья 700","Статья 760","Статья 800"], re:"Статья 760 NEC охватывает монтаж проводки и оборудования систем пожарной сигнализации, включая цепи с ограниченной мощностью (PLFA) и с неограниченной мощностью (NPLFA). Источник: область применения статьи 760 NEC (760.1)."},
  {id:487, q:"В статье 760 NEC обозначение кабеля 'FPL' относится к чему?", opts:["Кабель пожарной сигнализации с ограниченной мощностью, общего назначения","Кабель с ограниченной мощностью для стояка","Кабель с ограниченной мощностью для пленума","Кабель пожарной сигнализации с неограниченной мощностью"], re:"FPL — это кабель пожарной сигнализации с ограниченной мощностью общего назначения; семейство составляют FPLP (пленум), FPLR (стояк) и FPL (общий). Источник: типы кабелей NEC 760.179 / Таблица 760.154."},
  {id:488, q:"Какой кабель пожарной сигнализации с ограниченной мощностью требуется для монтажа в воздуховодах, пленумах и иных пространствах, используемых для воздуха окружающей среды?", opts:["FPL","FPLR","FPLP","CL2"], re:"Тип FPLP (пленум) требуется в воздуховодах, пленумах и пространствах обработки воздуха окружающей среды, поскольку он соответствует строгому испытанию на распространение пламени/малое дымообразование (пленум). Источник: кабель для пленума NEC 760.154 / 760.179."},
  {id:489, q:"Какой кабель пожарной сигнализации с ограниченной мощностью требуется для вертикальных прокладок в шахте или с этажа на этаж (стояк)?", opts:["FPL","FPLR","CL2X","NPLF"], re:"Тип FPLR (стояк) требуется для прокладок, проходящих более одного этажа, или в вертикальных шахтах; FPLP может быть заменён. Источник: кабель для стояка NEC 760.154 / 760.179."},
  {id:490, q:"В иерархии замены кабелей с ограниченной мощностью NEC 760 какая замена РАЗРЕШЕНА?", opts:["FPL вместо FPLP","FPLR вместо FPLP в пленуме","FPLP вместо FPLR или FPL","FPL вместо FPLR в стояке"], re:"Кабель более высокой категории может заменять кабель более низкой: FPLP может заменять FPLR и FPL; FPLR может заменять FPL; обратное не разрешено. Источник: замены кабелей NEC Таблица 760.154."},
  {id:491, q:"Что обозначает 'NPLFA' в статье 760 NEC?", opts:["Цепь пожарной сигнализации с неограниченной мощностью","Цепь пожарной сигнализации с ограниченной мощностью","Кабель связи для пленума","Проводник заземляющего электрода"], re:"NPLFA — это цепь пожарной сигнализации с неограниченной мощностью; её выходная мощность не ограничена по своей сути, и она может работать при более высоком напряжении (до 600 V). Источник: NEC статья 760 Часть III (NPLFA)."},
  {id:492, q:"Цепь пожарной сигнализации с ограниченной мощностью (PLFA) получает свою характеристику ограниченной мощности от чего?", opts:["Цвета проводника","Указанного в перечне источника питания, который ограничивает напряжение и ток согласно Кодексу","Материала кабелепровода","Количества извещателей"], re:"Цепи PLFA питаются от указанного в перечне источника питания, который ограничивает напряжение и ток (например, согласно таблицам источника питания), что позволяет применять упрощённые методы проводки. Источник: источник питания PLFA NEC 760.121 / Часть III."},
  {id:493, q:"Там, где они не находятся в кабельном канале или иным образом не разделены, проводники пожарной сигнализации с ограниченной мощностью должны быть отделены от проводников электрического освещения, силовых и Класса 1 не менее чем на какое расстояние?", opts:["1/2 in.","1 in.","2 in.","6 in."], re:"NEC 760.136 обычно требует не менее 2 in. (50 мм) разделения между проводниками PLFA и проводниками цепей освещения, силовых, Класса 1 или NPLFA, если они не разделены барьером или не находятся в кабельном канале. Источник: NEC 760.136."},
  {id:494, q:"NEC 760.124 требует, чтобы цепи и оборудование пожарной сигнализации идентифицировались как, чтобы предотвратить случайное вмешательство во время обслуживания?", opts:["Без какой-либо маркировки","Долговечно маркированными/идентифицированными в местах клемм и соединительных коробок как цепи пожарной сигнализации","Только по памяти монтажника","Символом огнетушителя"], re:"NEC 760.124 требует, чтобы цепи пожарной сигнализации идентифицировались в местах клемм и соединительных коробок этикеткой/маркировкой для предотвращения непреднамеренного вмешательства во время испытаний/обслуживания. Источник: NEC 760.124."},
  {id:495, q:"Выделенная ответвлённая цепь, питающая блок управления пожарной сигнализацией, должна иметь своё устройство защиты от сверхтока идентифицированным как?", opts:["Окрашенным в синий цвет и без маркировки","Помеченным красным и маркированным 'ЦЕПЬ ПОЖАРНОЙ СИГНАЛИЗАЦИИ', доступным только квалифицированному персоналу","Оставленным без маркировки","Маркированным 'РЕЗЕРВ'"], re:"NEC 760.121(B) требует, чтобы устройство защиты от сверхтока ответвлённой цепи пожарной сигнализации было помечено красным, маркировано 'ЦЕПЬ ПОЖАРНОЙ СИГНАЛИЗАЦИИ' и доступно только квалифицированному персоналу. Источник: NEC 760.121(B)."},
  {id:496, q:"Проводникам цепи пожарной сигнализации с ограниченной мощностью разрешено быть меньше типичного минимума только при каком условии NEC?", opts:["Никогда ни при каком условии","26 AWG разрешён там, где он оконцован/сращён на указанном в перечне оборудовании, пригодном для этого размера","Только если они окрашены в красный цвет","Только выше 600 V"], re:"NEC 760.142/760.179 разрешают проводники PLFA 26 AWG только там, где они сращены/оконцованы соединителями или оборудованием, указанным в перечне как пригодным для 26 AWG (в противном случае минимум 24 AWG). Источник: выбор сечения проводников NEC 760.179."},
  {id:497, q:"В пределах одного корпуса проводникам PLFA разрешено находиться в одном кабельном канале/корпусе с силовыми проводниками только при выполнении какого условия?", opts:["Они одного цвета","Барьер разделяет их, или силовые проводники подключаются исключительно к тому же оборудованию пожарной сигнализации","Они используют более крупный провод","Напряжение выше 600 V"], re:"NEC 760.136 разрешает PLFA с силовыми проводниками в одном корпусе только при разделении барьером или там, где проводники освещения/силовые вводятся исключительно для подключения к тому же оборудованию пожарной сигнализации. Источник: NEC 760.136(C)/(D)."},
  {id:498, q:"Заброшенный кабель пожарной сигнализации (не оконцованный на оборудовании и не идентифицированный для будущего использования) должен обрабатываться как согласно NEC?", opts:["Оставлен на месте постоянно","Удалён (доступная часть)","Закрашен","Постоянно под напряжением"], re:"NEC требует, чтобы доступная часть заброшенного кабеля пожарной сигнализации была удалена для снижения горючей нагрузки пожара/дыма, если только она не помечена для будущего использования. Источник: удаление заброшенного кабеля NEC 760.25."},
  {id:499, q:"Проводники цепи пожарной сигнализации с неограниченной мощностью (NPLFA) обычно имеют какое требование к минимальному сечению согласно NEC?", opts:["26 AWG","18 AWG (с 16 AWG и крупнее, также разрешёнными)","10 AWG","4 AWG"], re:"NEC 760.49 предусматривает, что проводники NPLFA сечением 18 AWG и 16 AWG разрешены для ограниченных токов, с более крупными сечениями согласно токовой нагрузке; PLFA отличается. Источник: выбор сечения проводников NPLFA NEC 760.49."},
  {id:500, q:"Какое утверждение о перечнях кабелей NEC 760 является правильным?", opts:["Кабель общего назначения FPL всегда можно использовать в пленуме","Замены идут только от более высокой категории к более низкой категории применения (пленум > стояк > общий)","Кабель для стояка (FPLR) можно использовать в пленуме","Тип кабеля не имеет значения внутри помещений"], re:"Таблица 760.154 NEC разрешает заменять только кабель более высокой категории для применения более низкой категории (пленумный FPLP для стояка/общего; стояковый FPLR для общего); кабель более низкой категории нельзя использовать в более требовательном месте. Источник: NEC Таблица 760.154."}
];
